def resolve_data_root_setting() -> tuple[str | None, str, str | None]:
    env_value = os.environ.get("MEIAO_DATA_DIR")
    if env_value and env_value.strip():
        return env_value, "env:MEIAO_DATA_DIR", None
    if CONFIG_FILE.exists():
        try:
            config = json.loads(CONFIG_FILE.read_text(encoding="utf-8-sig"))
            storage = config.get("storage") if isinstance(config.get("storage"), dict) else {}
            candidates = [
                ("config:dataDir", config.get("dataDir")),
                ("config:data_dir", config.get("data_dir")),
                ("config:storage.dataDir", storage.get("dataDir")),
                ("config:storage.data_dir", storage.get("data_dir")),
                ("config:storage.root", storage.get("root")),
            ]
            for source, value in candidates:
                if value and str(value).strip():
                    return str(value), source, None
        except Exception as exc:
            return None, "default:storage", f"读取 config.local.json 失败：{exc}"
    return None, "default:storage", None


def resolve_data_root() -> Path:
    raw_value, _, _ = resolve_data_root_setting()
    path = Path(str(raw_value).strip()) if raw_value else BASE_DIR / "storage"
    path = path.expanduser()
    if not path.is_absolute():
        path = BASE_DIR / path
    return path.resolve()


