def count_video_files_quick(folder_path: Path, max_count: int = 9999) -> int:
    count = 0
    stack = [folder_path]
    while stack:
        current = stack.pop()
        try:
            with os.scandir(current) as entries:
                for entry in entries:
                    try:
                        if entry.is_dir(follow_symlinks=False):
                            stack.append(Path(entry.path))
                        elif entry.is_file(follow_symlinks=False) and Path(entry.name).suffix.lower() in VIDEO_FILE_SUFFIXES:
                            count += 1
                            if count >= max_count:
                                return count
                    except OSError:
                        continue
        except OSError:
            continue
    return count
