def append_debug_log(event: str, data: dict | None = None) -> None:
    LOG_ROOT.mkdir(parents=True, exist_ok=True)
    payload = {
        "ts": datetime.now().isoformat(timespec="seconds"),
        "event": event,
        **(data or {}),
    }
    line = json.dumps(payload, ensure_ascii=False, default=str) + "\n"
    try:
        with INGEST_LOG_FILE.open("a", encoding="utf-8") as file:
            file.write(line)
    except PermissionError:
        try:
            fallback_file = LOG_ROOT / f"ingest-debug-{os.getpid()}.jsonl"
            with fallback_file.open("a", encoding="utf-8") as file:
                file.write(line)
        except Exception:
            pass


