class Win32GUID(ctypes.Structure):
    _fields_ = [
        ("Data1", ctypes.c_ulong),
        ("Data2", ctypes.c_ushort),
        ("Data3", ctypes.c_ushort),
        ("Data4", ctypes.c_ubyte * 8),
    ]


def win32_guid(value: str) -> Win32GUID:
    parsed = uuid.UUID(value)
    data4 = (ctypes.c_ubyte * 8).from_buffer_copy(parsed.bytes[8:])
    return Win32GUID(parsed.time_low, parsed.time_mid, parsed.time_hi_version, data4)


def hresult_hex(value: int) -> str:
    return f"0x{ctypes.c_uint32(value).value:08X}"


def select_folder_with_win32_dialog(title: str) -> str:
    if os.name != "nt":
        return ""
    clsid_file_open_dialog = win32_guid("DC1C5A9C-E88A-4DDE-A5A1-60F82A20AEF7")
    iid_file_dialog = win32_guid("42F85136-DB7E-439C-85F1-E4075D135FC8")
    dialog = ctypes.c_void_p()
    shell_item = ctypes.c_void_p()
    path_ptr = ctypes.c_void_p()
    co_initialized = False
    try:
        ole32 = ctypes.OleDLL("ole32")
        user32 = ctypes.WinDLL("user32")
        hr = ole32.CoInitializeEx(None, 0x2)
        co_initialized = hr in (0, 1)
        if hr not in (0, 1, -2147417850):  # RPC_E_CHANGED_MODE means COM is already initialized differently.
            append_debug_log("system.select_folder.com_init_error", {"hresult": hresult_hex(hr)})
            return ""

        hr = ole32.CoCreateInstance(
            ctypes.byref(clsid_file_open_dialog),
            None,
            0x1,
            ctypes.byref(iid_file_dialog),
            ctypes.byref(dialog),
        )
        if hr != 0 or not dialog.value:
            append_debug_log("system.select_folder.create_dialog_error", {"hresult": hresult_hex(hr)})
            return ""

        vtable = ctypes.cast(dialog, ctypes.POINTER(ctypes.POINTER(ctypes.c_void_p))).contents
        release = ctypes.WINFUNCTYPE(ctypes.c_ulong, ctypes.c_void_p)(vtable[2])
        show = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.c_void_p)(vtable[3])
        set_options = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.c_uint)(vtable[9])
        get_options = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.POINTER(ctypes.c_uint))(vtable[10])
        set_title = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.c_wchar_p)(vtable[17])
        set_ok_button_label = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.c_wchar_p)(vtable[18])
        get_result = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.POINTER(ctypes.c_void_p))(vtable[20])

        options = ctypes.c_uint()
        hr = get_options(dialog, ctypes.byref(options))
        if hr == 0:
            set_options(dialog, options.value | 0x20 | 0x40 | 0x800)
        set_title(dialog, title)
        set_ok_button_label(dialog, "选择文件夹")

        owner = ctypes.c_void_p(user32.GetForegroundWindow())
        hr = show(dialog, owner)
        if hr != 0:
            if ctypes.c_uint32(hr).value != 0x800704C7:
                append_debug_log("system.select_folder.show_error", {"hresult": hresult_hex(hr)})
            return ""

        hr = get_result(dialog, ctypes.byref(shell_item))
        if hr != 0 or not shell_item.value:
            append_debug_log("system.select_folder.result_error", {"hresult": hresult_hex(hr)})
            return ""

        item_vtable = ctypes.cast(shell_item, ctypes.POINTER(ctypes.POINTER(ctypes.c_void_p))).contents
        item_release = ctypes.WINFUNCTYPE(ctypes.c_ulong, ctypes.c_void_p)(item_vtable[2])
        get_display_name = ctypes.WINFUNCTYPE(ctypes.c_long, ctypes.c_void_p, ctypes.c_uint, ctypes.POINTER(ctypes.c_void_p))(item_vtable[5])
        hr = get_display_name(shell_item, 0x80058000, ctypes.byref(path_ptr))
        if hr != 0:
            append_debug_log("system.select_folder.path_error", {"hresult": hresult_hex(hr)})
            return ""
        return ctypes.wstring_at(path_ptr.value).strip() if path_ptr.value else ""
    except Exception as exc:
        append_debug_log("system.select_folder.win32_error", {"error": str(exc), "traceback": traceback.format_exc()})
        return ""
    finally:
        try:
            if path_ptr:
                ctypes.OleDLL("ole32").CoTaskMemFree(path_ptr)
        except Exception:
            pass
        try:
            if shell_item.value:
                item_release(shell_item)
        except Exception:
            pass
        try:
            if dialog.value:
                release(dialog)
        except Exception:
            pass
        try:
            if co_initialized:
                ctypes.OleDLL("ole32").CoUninitialize()
        except Exception:
            pass


def select_folder_with_tkinter(title: str) -> str:
    try:
        import tkinter as tk
        from tkinter import filedialog

        root = tk.Tk()
        root.withdraw()
        root.attributes("-topmost", True)
        folder = filedialog.askdirectory(title=title)
        root.destroy()
        return str(folder or "").strip()
    except Exception as exc:
        append_debug_log("system.select_folder.tkinter_unavailable", {"error": str(exc)})
        return ""


def select_folder_with_native_dialog(title: str) -> str:
    return select_folder_with_win32_dialog(title) or select_folder_with_tkinter(title)


def sanitize_export_filename_part(value: str) -> str:
    cleaned = re.sub(r'[<>:"/\\|?*\x00-\x1f]+', "_", str(value or "").strip())
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" ._")
    return cleaned[:80] or "导出视频"


def resolve_capcut_export_source(video_url: str) -> Path:
    raw_value = str(video_url or "").strip()
    if not raw_value:
        raise ValueError("缺少导出视频地址")
    parsed = urlparse(raw_value)
    if parsed.scheme in ("http", "https"):
        if parsed.hostname not in ("127.0.0.1", "localhost") or parsed.path.lower().find("/output/draft/") == -1:
            raise ValueError("当前只支持归档剪映小助手本机导出的视频")
        file_name = Path(unquote(parsed.path)).name
        source = (CAPCUT_MATE_OUTPUT_DRAFT_DIR / file_name).resolve()
    elif parsed.scheme == "file":
        source = Path(unquote(parsed.path)).resolve()
    else:
        source = Path(raw_value).expanduser().resolve()
    if not source.exists() or not source.is_file():
        raise FileNotFoundError(f"导出视频文件不存在：{source}")
    if source.suffix.lower() != ".mp4":
        raise ValueError("导出视频不是 MP4 文件")
    if not path_is_under(source, CAPCUT_MATE_OUTPUT_DRAFT_DIR):
        raise PermissionError(f"导出视频必须位于剪映小助手输出目录：{CAPCUT_MATE_OUTPUT_DRAFT_DIR}")
    return source


def next_export_target_path(output_dir: Path, project_name: str) -> tuple[Path, int]:
    date_text = datetime.now().strftime("%Y%m%d")
    safe_project = sanitize_export_filename_part(project_name)
    prefix = f"{safe_project}_{date_text}_"
    max_index = 0
    pattern = re.compile(rf"^.+_{date_text}_(\d{{3}})\.mp4$", re.IGNORECASE)
    for item in output_dir.iterdir():
        if not item.is_file():
            continue
        match = pattern.match(item.name)
        if match:
            max_index = max(max_index, int(match.group(1)))
    index = max_index + 1
    while True:
        target = output_dir / f"{prefix}{index:03d}.mp4"
        if not target.exists():
            return target, index
        index += 1


def normalize_local_open_path(value: str) -> Path:
    raw_value = str(value or "").strip().strip('"')
    if not raw_value:
        raise ValueError("缺少要打开的路径")
    parsed = urlparse(raw_value)
    if parsed.scheme in {"http", "https"}:
        if parsed.hostname not in {"127.0.0.1", "localhost", "::1"}:
            raise PermissionError("只能打开本机运行时生成的文件")
        if not parsed.path.startswith("/media/"):
            raise PermissionError("只能打开本机媒体库文件")
        media_path = media_url_to_file_path(raw_value)
        if not media_path:
            raise FileNotFoundError("本机媒体文件不存在")
        return media_path.resolve()
    if parsed.scheme == "file":
        path_text = unquote(parsed.path)
        if os.name == "nt" and re.match(r"^/[A-Za-z]:/", path_text):
            path_text = path_text[1:]
        return Path(path_text).expanduser().resolve()
    return Path(raw_value).expanduser().resolve()


def allowed_local_open_roots() -> list[Path]:
    roots = [
        DATA_ROOT,
        MEDIA_ROOT,
        CAPCUT_MATE_OUTPUT_DRAFT_DIR,
        BASE_DIR / "storage",
        BASE_DIR / "media",
        BASE_DIR / "drafts",
    ]
    try:
        from integrations.capcut_mate.adapter import jianying_draft_root

        roots.append(jianying_draft_root())
    except Exception:
        pass
    state = read_client_state()
    export_folders = state.get("meiao-export-folders") if isinstance(state.get("meiao-export-folders"), dict) else {}
    for folder in export_folders.values():
        folder_text = str(folder or "").strip()
        if folder_text:
            roots.append(Path(folder_text).expanduser())
    normalized: list[Path] = []
    for root in roots:
        try:
            normalized.append(root.resolve())
        except Exception:
            continue
    return normalized


def assert_local_open_allowed(path: Path) -> None:
    if not path.exists():
        raise FileNotFoundError(f"路径不存在：{path}")
    if not any(path_is_under(path, root) for root in allowed_local_open_roots()):
        raise PermissionError("为了避免误打开系统文件，只能定位数据目录、剪映草稿目录、剪映输出目录或已配置导出目录内的文件")


def reveal_local_path(path: Path) -> None:
    if os.name != "nt":
        raise RuntimeError("当前只支持在 Windows 资源管理器中定位本地文件")
    target = path.resolve()
    if target.is_file():
        subprocess.Popen(["explorer.exe", f"/select,{target}"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    else:
        subprocess.Popen(["explorer.exe", str(target)], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)


def path_is_network_location(path: Path) -> bool:
    path_text = str(path)
    if path_text.startswith("\\\\"):
        return True
    drive = path.drive
    if not drive or os.name != "nt":
        return False
    try:
        import ctypes
        drive_root = f"{drive}\\"
        return ctypes.windll.kernel32.GetDriveTypeW(drive_root) == 4
    except Exception:
        return False


def path_is_under(path: Path, root: Path) -> bool:
    try:
        path.resolve().relative_to(root.resolve())
        return True
    except Exception:
        return False


def describe_file_operation_error(action: str, path: Path, exc: Exception) -> str:
    location = "NAS/网络路径" if path_is_network_location(path) else "本地路径"
    if isinstance(exc, FileNotFoundError):
        reason = "路径不存在，可能是 NAS 未连接、盘符变化或文件已被移动"
    elif isinstance(exc, PermissionError):
        reason = "权限不足，或文件正在被剪映/其他程序占用"
    else:
        reason = "文件系统操作失败"
    return f"{action}失败：{path}。{location}，{reason}。{exc}"


MIN_STATE_FREE_BYTES = 512 * 1024 * 1024
MIN_VIDEO_FREE_BYTES = 5 * 1024 * 1024 * 1024


def format_disk_size(value: int | float | None) -> str:
    if value is None:
        return "未知"
    units = ["B", "KB", "MB", "GB", "TB"]
    size = float(max(0, value))
    unit_index = 0
    while size >= 1024 and unit_index < len(units) - 1:
        size /= 1024
        unit_index += 1
    if unit_index == 0:
        return f"{int(size)} {units[unit_index]}"
    return f"{size:.1f} {units[unit_index]}"


def nearest_existing_path(path: Path) -> Path | None:
    current = path
    while True:
        if current.exists():
            return current
        parent = current.parent
        if parent == current:
            return None
        current = parent


def get_disk_free_bytes(path: Path) -> int | None:
    try:
        existing_path = nearest_existing_path(path)
        if not existing_path:
            return None
        return int(shutil.disk_usage(existing_path).free)
    except Exception:
        return None


def attach_free_space_check(result: dict, path: Path, min_free_bytes: int | None = None) -> dict:
    free_bytes = get_disk_free_bytes(path)
    if free_bytes is None:
        return result
    result["freeBytes"] = free_bytes
    if min_free_bytes is not None and free_bytes < min_free_bytes and result.get("status") != "error":
        result["status"] = "warning"
        result["message"] = (
            f"{result.get('message') or '目录可访问'}；磁盘剩余空间 {format_disk_size(free_bytes)}，"
            f"建议至少保留 {format_disk_size(min_free_bytes)}"
        )
    return result


def assert_writable_directory(path: Path, label: str) -> None:
    if not path.exists() or not path.is_dir():
        raise FileNotFoundError(f"{label}不存在或不是文件夹")
    probe = path / f".meiao-write-test-{uuid.uuid4().hex}.tmp"
    try:
        probe.write_text("ok", encoding="utf-8")
    finally:
        try:
            probe.unlink(missing_ok=True)
        except Exception:
            pass


