def recover_media_library_items_from_disk() -> list[dict]:
    if not MEDIA_ROOT.exists():
        return []
    skip_names = {
        "bgm-library",
        "capcut-fonts",
        "capcut-test-audio",
        "_capcut_assets",
        "__capcut_assets__",
        "__dedupe_aux__",
    }
    skip_prefixes = ("ab-dedup-", "flow-fission-")
    recovered: list[dict] = []
    for media_dir in sorted(MEDIA_ROOT.iterdir(), key=lambda item: item.stat().st_mtime if item.exists() else 0, reverse=True):
        if not media_dir.is_dir():
            continue
        if media_dir.name in skip_names or media_dir.name.startswith(skip_prefixes) or media_dir.name.startswith("_"):
            continue
        video_path = find_original_media_video(media_dir) or find_primary_media_video(media_dir)
        if not video_path:
            continue
        poster_path = next(
            (
                path for path in media_dir.iterdir()
                if path.is_file() and path.suffix.lower() in {".jpg", ".jpeg", ".png", ".webp"}
            ),
            None,
        )
        if not poster_path:
            poster_path = generate_poster(video_path, media_dir)
        created_at = int(media_dir.stat().st_mtime * 1000)
        recovered.append(
            {
                "id": f"REC-{media_dir.name}",
                "title": video_path.stem or media_dir.name,
                "source": "本地恢复",
                "duration": format_duration(probe_video_duration(video_path)),
                "status": "已入库",
                "progress": 100,
                "time": "已恢复",
                "failed": False,
                "createdAt": created_at,
                "ingestMode": "url",
                "sourceUrl": get_public_media_url(media_dir.name, video_path.name),
                "sourceVideoUrl": get_public_media_url(media_dir.name, video_path.name),
                "remoteVideoUrl": get_public_media_url(media_dir.name, video_path.name),
                "remotePosterUrl": get_public_media_url(media_dir.name, poster_path.name) if poster_path else None,
                "backendMediaId": media_dir.name,
                "notes": "从本地媒体目录恢复",
            }
        )
    return recovered


def media_item_richness(item: dict) -> int:
    score = 0
    for key in (
        "title",
        "source",
        "duration",
        "status",
        "sourceUrl",
        "sourceVideoUrl",
        "remoteVideoUrl",
        "remotePosterUrl",
        "backendMediaId",
        "notes",
        "basicInfo",
        "author",
        "metrics",
        "contentTags",
        "commerce",
        "platformRaw",
    ):
        if str(item.get(key) or "").strip():
            score += 1
    return score


def is_stale_local_placeholder(item: dict) -> bool:
    return (
        str(item.get("ingestMode") or "").strip() == "local"
        and not bool(item.get("failed"))
        and not str(item.get("localUploadId") or "").strip()
        and not str(item.get("backendMediaId") or "").strip()
        and not str(item.get("remoteVideoUrl") or "").strip()
        and not str(item.get("sourceVideoUrl") or "").strip()
        and not str(item.get("fileId") or "").strip()
    )


def sanitize_media_library_item(item: dict) -> dict:
    next_item = dict(item)
    if (
        str(next_item.get("backendMediaId") or "").strip()
        or str(next_item.get("remotePosterUrl") or "").strip()
        or str(next_item.get("remoteVideoUrl") or "").strip()
    ):
        next_item.pop("posterDataUrl", None)
    return next_item


def merge_media_library_items(primary: list[dict], fallback: list[dict]) -> list[dict]:
    by_key: dict[str, dict] = {}
    loose: list[dict] = []
    for item in [*primary, *fallback]:
        if not isinstance(item, dict):
            continue
        if is_stale_local_placeholder(item):
            continue
        item = sanitize_media_library_item(item)
        key = str(item.get("backendMediaId") or item.get("id") or item.get("remoteVideoUrl") or "").strip()
        if not key:
            loose.append(item)
            continue
        previous = by_key.get(key)
        if previous is None:
            by_key[key] = item
            continue
        item_time = client_item_time(item)
        previous_time = client_item_time(previous)
        if item_time > previous_time or (item_time == previous_time and media_item_richness(item) >= media_item_richness(previous)):
            by_key[key] = {**previous, **item}
        else:
            by_key[key] = {**item, **previous}
    merged = [*by_key.values(), *loose]
    return sorted(merged, key=client_item_time, reverse=True)


