def sanitize_draft_template(item: dict) -> dict:
    def num(value: object, fallback: float, min_value: float, max_value: float) -> float:
        try:
            next_value = float(value)
        except Exception:
            next_value = fallback
        if not math.isfinite(next_value):
            next_value = fallback
        return max(min_value, min(max_value, next_value))

    def percent(value: object, fallback: float, min_value: float = 100, max_value: float = 300) -> int:
        raw = num(value, fallback, 0, max_value)
        normalized = raw * 100 if 0 < raw <= 3 else raw
        return round(max(min_value, min(max_value, normalized)))

    def scale_ratio(value: object, fallback: float = 1) -> float:
        raw = num(value, fallback, 0.2, 300)
        normalized = raw / 100 if raw > 10 else raw
        return round(max(0.2, min(3, normalized)), 3)

    template = dict(item)
    filter_layers = template.get("filterLayers") if isinstance(template.get("filterLayers"), list) else []
    normalized_filter_layers: list[dict] = []
    for index, layer in enumerate(filter_layers):
        if not isinstance(layer, dict):
            continue
        choice = str(layer.get("filterChoice") or "").strip()
        if not choice:
            continue
        normalized_filter_layers.append(
            {
                "id": str(layer.get("id") or f"filter-{index}"),
                "filterChoice": choice,
                "intensity": round(num(layer.get("intensity"), 100, 0, 100)),
                "opacity": round(num(layer.get("opacity"), 100, 0, 100)),
                "startSec": 0,
                "endSec": 0,
            }
        )
        if len(normalized_filter_layers) >= 8:
            break
    filter_layers = normalized_filter_layers
    template["filterLayers"] = filter_layers
    if not filter_layers:
        template["filterTrackCount"] = 1
        if str(template.get("filterChoice") or "").strip() == "recommended":
            template["filterChoice"] = ""
    else:
        template["filterTrackCount"] = max(1, min(8, len(filter_layers)))
        template["filterLayers"] = filter_layers
        first_filter = next((layer.get("filterChoice") for layer in filter_layers if isinstance(layer, dict) and layer.get("filterChoice")), "")
        if first_filter:
            template["filterChoice"] = first_filter
    sticker_layers = template.get("stickerLayers") if isinstance(template.get("stickerLayers"), list) else []
    normalized_sticker_layers: list[dict] = []
    for index, layer in enumerate(sticker_layers):
        if not isinstance(layer, dict):
            continue
        sticker_id = str(layer.get("stickerId") or "").strip()
        keyword = str(layer.get("keyword") or "").strip()
        if not sticker_id and not keyword:
            continue
        normalized_sticker_layers.append(
            {
                "id": str(layer.get("id") or f"sticker-{index}"),
                "stickerId": sticker_id,
                "keyword": keyword,
                "scale": num(layer.get("scale"), 0.35, 0.05, 3),
                "alpha": round(num(layer.get("alpha"), 100, 0, 100)),
                "transformX": num(layer.get("transformX"), 0.28, -1, 1),
                "transformY": num(layer.get("transformY"), -0.3, -1, 1),
                "startSec": 0,
                "endSec": 0,
            }
        )
        if len(normalized_sticker_layers) >= 8:
            break
    template["stickerLayers"] = normalized_sticker_layers
    template["stickersEnabled"] = bool(template.get("stickersEnabled") or normalized_sticker_layers)
    caption_font_raw = num(template.get("captionFontSize"), 10, -100000, 100000)
    template["captionFontSize"] = num(10 if caption_font_raw == 46 else caption_font_raw, 10, 6, 40)
    caption_keyword_raw = num(template.get("captionKeywordFontSize"), 12, -100000, 100000)
    template["captionKeywordFontSize"] = num(12 if caption_keyword_raw == 58 else caption_keyword_raw, 12, 6, 46)
    template["captionAlpha"] = round(num(template.get("captionAlpha"), 100, 0, 100))
    zoom_min = percent(template.get("randomZoomMin"), 110)
    zoom_max = percent(template.get("randomZoomMax"), 130)
    template["randomZoomEnabled"] = bool(template.get("randomZoomEnabled", True))
    template["randomZoomMin"] = min(zoom_min, zoom_max)
    template["randomZoomMax"] = max(zoom_min, zoom_max)
    template["clipScale"] = scale_ratio(template.get("clipScale"), 1)
    template["randomFlipEnabled"] = bool(template.get("randomFlipEnabled", False))
    template["fitMode"] = "contain" if template.get("fitMode") == "contain" else "cover"
    template["dedupeEnabled"] = bool(template.get("dedupeEnabled", True))
    template["dedupeAuxVideoFolderPath"] = str(template.get("dedupeAuxVideoFolderPath") or "").strip()
    template["dedupeAuxVideoFolderName"] = str(template.get("dedupeAuxVideoFolderName") or "").strip()
    template["dedupeAuxVideoFolderVideoCount"] = round(num(template.get("dedupeAuxVideoFolderVideoCount"), 0, 0, 9999))
    template["dedupeAuxVideoCount"] = round(num(template.get("dedupeAuxVideoCount"), 2, 0, 4))
    template["dedupeAuxAlpha"] = round(num(template.get("dedupeAuxAlpha"), 2, 0, 20))
    template["filterStartSec"] = 0
    template["filterEndSec"] = 0
    template["effectChoice"] = ""
    template["effectStartSec"] = 0
    template["effectEndSec"] = 0
    template["effectLayers"] = []
    return template


def client_item_time(item: object) -> int:
    if not isinstance(item, dict):
        return 0
    for key in ("updatedAt", "updated_at", "createdAt", "created_at", "time"):
        try:
            value = item.get(key)
            if isinstance(value, (int, float)):
                return int(value)
            if isinstance(value, str) and value.strip().isdigit():
                return int(value.strip())
        except Exception:
            continue
    return 0


def merge_draft_templates(primary: list[dict], fallback: list[dict]) -> list[dict]:
    by_id: dict[str, dict] = {}
    loose: list[dict] = []
    for item in [*primary, *fallback]:
        if not isinstance(item, dict):
            continue
        template_id = str(item.get("id") or "").strip()
        if not template_id:
            loose.append(sanitize_draft_template(item))
            continue
        normalized = sanitize_draft_template(item)
        previous = by_id.get(template_id)
        if previous is None or client_item_time(normalized) >= client_item_time(previous):
            by_id[template_id] = normalized
    merged = [*by_id.values(), *loose]
    return sorted(merged, key=lambda item: int(item.get("updatedAt") or item.get("createdAt") or 0), reverse=True)


def read_client_state() -> dict:
    if not CLIENT_STATE_FILE.exists():
        return read_latest_client_state_backup()
    try:
        data = json.loads(CLIENT_STATE_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) and data else read_latest_client_state_backup()
    except Exception:
        return read_latest_client_state_backup()


def client_state_source_signature() -> dict:
    sources = [
        ("clientState", CLIENT_STATE_FILE),
        ("mediaLibrary", MEDIA_LIBRARY_FILE),
        ("draftTemplates", DRAFT_TEMPLATES_FILE),
        ("batchDraftProjects", BATCH_DRAFT_PROJECTS_FILE),
        ("mediaRoot", MEDIA_ROOT),
    ]
    entries: list[dict] = []
    for name, path in sources:
        try:
            stat = path.stat()
            entries.append({
                "name": name,
                "exists": True,
                "size": int(stat.st_size),
                "mtimeMs": int(stat.st_mtime * 1000),
            })
        except Exception:
            entries.append({"name": name, "exists": False, "size": 0, "mtimeMs": 0})
    digest_source = json.dumps(entries, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return {
        "signature": hashlib.sha256(digest_source).hexdigest(),
        "sources": entries,
    }


def flow_fission_task_is_canceled(job_id: str | None) -> bool:
    job_id = str(job_id or "").strip()
    if not job_id:
        return False
    task_id = f"flow-fission:{job_id}"
    state = read_client_state()
    tombstones = state.get("meiao-unified-task-tombstones")
    if isinstance(tombstones, dict) and task_id in tombstones:
        return True
    tasks = state.get("meiao-unified-tasks")
    if isinstance(tasks, list):
        for task in tasks:
            if isinstance(task, dict) and str(task.get("taskId") or "") == task_id and str(task.get("status") or "") == "canceled":
                return True
    return False


def raise_if_flow_fission_canceled(job_id: str | None, context: str = "") -> None:
    if flow_fission_task_is_canceled(job_id):
        suffix = f"（{context}）" if context else ""
        raise IngestError(f"Flow 裂变任务已取消{suffix}。", "FLOW_FISSION_CANCELED", "CHECK_FLOW")


UNIFIED_TASK_VOLATILE_FIELDS = {"stage", "progress", "message", "error", "updatedAt", "retryCount", "startedAt"}
UNIFIED_TASK_ACTIVE_STATUSES = {"queued", "running"}


def unified_task_id_map(value: object) -> dict[str, dict] | None:
    if not isinstance(value, list):
        return None
    result: dict[str, dict] = {}
    for item in value:
        if not isinstance(item, dict):
            return None
        task_id = str(item.get("taskId") or "").strip()
        if not task_id:
            return None
        result[task_id] = item
    return result


def unified_task_is_active(item: dict) -> bool:
    return str(item.get("status") or "") in UNIFIED_TASK_ACTIVE_STATUSES


def unified_task_change_is_volatile(previous: dict, current: dict) -> bool:
    if not unified_task_is_active(previous) or not unified_task_is_active(current):
        return False
    changed_keys = {key for key in set(previous.keys()) | set(current.keys()) if previous.get(key) != current.get(key)}
    return bool(changed_keys) and changed_keys.issubset(UNIFIED_TASK_VOLATILE_FIELDS)


def unified_tasks_change_is_volatile(previous: object, current: object) -> bool:
    previous_tasks = unified_task_id_map(previous)
    current_tasks = unified_task_id_map(current)
    if previous_tasks is None or current_tasks is None:
        return False
    if set(previous_tasks.keys()) != set(current_tasks.keys()):
        return False
    changed = False
    for task_id, current_task in current_tasks.items():
        previous_task = previous_tasks[task_id]
        if previous_task == current_task:
            continue
        changed = True
        if not unified_task_change_is_volatile(previous_task, current_task):
            return False
    return changed


def should_snapshot_client_state_change(previous: dict, current: dict) -> bool:
    if not previous or previous == current:
        return False
    changed_keys = {key for key in set(previous.keys()) | set(current.keys()) if previous.get(key) != current.get(key)}
    if changed_keys == {"meiao-unified-tasks"} and unified_tasks_change_is_volatile(previous.get("meiao-unified-tasks"), current.get("meiao-unified-tasks")):
        return False
    return True


def write_client_state(state: dict) -> None:
    current = read_client_state()
    if should_snapshot_client_state_change(current, state):
        snapshot_client_state(current, "before-write")
    atomic_write_json(CLIENT_STATE_FILE, state)


def read_latest_client_state_backup() -> dict:
    try:
        backups = sorted(CLIENT_STATE_BACKUP_DIR.glob("*.json"), key=lambda item: item.stat().st_mtime, reverse=True)
    except Exception:
        return {}
    for backup in backups:
        try:
            payload = json.loads(backup.read_text(encoding="utf-8"))
            state = payload.get("state") if isinstance(payload, dict) else None
            if isinstance(state, dict) and state:
                return state
        except Exception:
            continue
    return {}


def snapshot_client_state(state: dict, reason: str) -> None:
    if not isinstance(state, dict) or not state:
        return
    try:
        CLIENT_STATE_BACKUP_DIR.mkdir(parents=True, exist_ok=True)
        timestamp = datetime.now().strftime("%Y%m%d-%H%M%S-%f")
        backup_path = CLIENT_STATE_BACKUP_DIR / f"{timestamp}-{reason}.json"
        atomic_write_json(backup_path, {
            "createdAt": int(time.time() * 1000),
            "reason": reason,
            "state": state,
        })
        backups = sorted(CLIENT_STATE_BACKUP_DIR.glob("*.json"), key=lambda item: item.stat().st_mtime, reverse=True)
        for stale in backups[30:]:
            try:
                stale.unlink()
            except Exception:
                pass
    except Exception as exc:
        append_debug_log("client_state.backup.error", {"errorType": type(exc).__name__, "error": str(exc)})


