def merge_list_by_stable_id(incoming: list, current: list) -> list:
    by_id: dict[str, dict] = {}
    loose: list = []
    for item in [*incoming, *current]:
        if not isinstance(item, dict):
            continue
        key = str(item.get("id") or item.get("backendMediaId") or item.get("taskId") or item.get("recordId") or "").strip()
        if not key:
            loose.append(item)
            continue
        previous = by_id.get(key)
        if previous is None or client_item_time(item) >= client_item_time(previous):
            by_id[key] = item
    return [*by_id.values(), *loose]


def merge_flow_fission_attempts(primary: object, fallback: object) -> list:
    primary_list = primary if isinstance(primary, list) else []
    fallback_list = fallback if isinstance(fallback, list) else []
    return sorted(merge_list_by_stable_id(primary_list, fallback_list), key=client_item_time, reverse=True)


def flow_fission_slot_key(slot: object) -> str:
    if not isinstance(slot, dict):
        return ""
    return str(slot.get("id") or slot.get("slotId") or slot.get("index") or "").strip()


def flow_fission_slot_index(slot: object) -> int:
    if not isinstance(slot, dict):
        return 9999
    try:
        return int(slot.get("index") or 9999)
    except Exception:
        return 9999


def merge_flow_fission_slots(primary: object, fallback: object, attempts: list) -> list:
    primary_list = primary if isinstance(primary, list) else []
    fallback_list = fallback if isinstance(fallback, list) else []
    by_slot: dict[str, dict] = {}
    loose: list = []
    for slot in [*fallback_list, *primary_list]:
        if not isinstance(slot, dict):
            continue
        key = flow_fission_slot_key(slot)
        if not key:
            loose.append(slot)
            continue
        previous = by_slot.get(key)
        if previous is None:
            by_slot[key] = dict(slot)
            continue
        merged = {**previous, **slot}
        if previous.get("videoAssetId") and not merged.get("videoAssetId"):
            merged["videoAssetId"] = previous.get("videoAssetId")
        if previous.get("aiReason") and not merged.get("aiReason"):
            merged["aiReason"] = previous.get("aiReason")
        by_slot[key] = merged

    active_slot_ids = {
        str(attempt.get("slotId") or "").strip()
        for attempt in attempts
        if isinstance(attempt, dict)
        and str(attempt.get("status") or "") in {"pending", "submitting", "running"}
        and str(attempt.get("slotId") or "").strip()
    }
    success_asset_by_slot: dict[str, str] = {}
    for attempt in attempts:
        if not isinstance(attempt, dict) or str(attempt.get("status") or "") != "success":
            continue
        slot_id = str(attempt.get("slotId") or "").strip()
        asset_id = str(attempt.get("assetId") or "").strip()
        if slot_id and asset_id and slot_id not in success_asset_by_slot:
            success_asset_by_slot[slot_id] = asset_id

    merged_slots: list = []
    for slot in by_slot.values():
        next_slot = dict(slot)
        slot_id = str(next_slot.get("id") or "").strip()
        if slot_id in active_slot_ids and not next_slot.get("videoAssetId"):
            next_slot["status"] = "视频生成中"
        if slot_id in success_asset_by_slot and not next_slot.get("videoAssetId"):
            next_slot["videoAssetId"] = success_asset_by_slot[slot_id]
            next_slot["status"] = "已生成视频"
        merged_slots.append(next_slot)
    return sorted([*merged_slots, *loose], key=flow_fission_slot_index)


def merge_flow_fission_job(primary: dict, fallback: dict) -> dict:
    primary_time = client_item_time(primary)
    fallback_time = client_item_time(fallback)
    newer, older = (primary, fallback) if primary_time >= fallback_time else (fallback, primary)
    merged = {**older, **newer}
    attempts = merge_flow_fission_attempts(newer.get("videoAttempts"), older.get("videoAttempts"))
    merged["videoAttempts"] = attempts
    merged["promptSlots"] = merge_flow_fission_slots(newer.get("promptSlots"), older.get("promptSlots"), attempts)
    return merged


def merge_flow_fission_jobs(incoming: list, current: list, *, replace: bool = False) -> list:
    if replace and len(incoming) < len(current):
        return incoming
    by_id: dict[str, dict] = {}
    loose: list = []
    for item in [*incoming, *current]:
        if not isinstance(item, dict):
            continue
        key = str(item.get("id") or "").strip()
        if not key:
            loose.append(item)
            continue
        previous = by_id.get(key)
        by_id[key] = item if previous is None else merge_flow_fission_job(item, previous)
    return sorted([*by_id.values(), *loose], key=client_item_time, reverse=True)


FLOW_ACCOUNT_CLIENT_STATE_SECRET_FIELDS = {"password"}


def sanitize_flow_accounts_for_client_state(value: object) -> list:
    if not isinstance(value, list):
        return []
    sanitized: list[dict] = []
    for item in value:
        if not isinstance(item, dict):
            continue
        sanitized.append({
            key: field_value
            for key, field_value in item.items()
            if str(key).strip().lower() not in FLOW_ACCOUNT_CLIENT_STATE_SECRET_FIELDS
        })
    return sanitized


def merge_product_projects(incoming: list, current: list, deleted_projects: dict | None = None) -> list:
    deleted_projects = deleted_projects if isinstance(deleted_projects, dict) else {}
    by_id: dict[str, dict] = {}
    loose: list = []
    for item in [*incoming, *current]:
        if not isinstance(item, dict):
            continue
        key = str(item.get("id") or "").strip()
        if not key:
            loose.append(item)
            continue
        item_time = client_item_time(item)
        try:
            deleted_at = int(deleted_projects.get(key) or 0)
        except Exception:
            deleted_at = 0
        if deleted_at and item_time <= deleted_at:
            continue
        previous = by_id.get(key)
        if previous is None or item_time >= client_item_time(previous):
            by_id[key] = item
    return sorted([*by_id.values(), *loose], key=client_item_time, reverse=True)


def recover_batch_draft_project_estimate(project: dict) -> dict:
    if not isinstance(project, dict):
        return project
    try:
        estimated = int(project.get("estimatedVideoCount") or 0)
    except Exception:
        estimated = 0
    if estimated > 0:
        return project
    requirements = project.get("shotRequirements")
    matches = project.get("materialMatches")
    if not isinstance(requirements, list) or not isinstance(matches, list) or not requirements or len(matches) < len(requirements):
        return project
    match_by_id = {str(match.get("shotId") or ""): match for match in matches if isinstance(match, dict)}
    complete = True
    for requirement in requirements:
        if not isinstance(requirement, dict):
            complete = False
            break
        match = match_by_id.get(str(requirement.get("id") or ""))
        if not isinstance(match, dict) or not isinstance(match.get("selectedShotIds"), list) or not match.get("selectedShotIds"):
            complete = False
            break
    if not complete:
        return project
    try:
        fallback_count = max(1, int(project.get("outputCount") or 1))
    except Exception:
        fallback_count = 1
    project = dict(project)
    project["estimatedVideoCount"] = fallback_count
    return project


def batch_project_stage_rank(project: dict) -> int:
    stages = {
        "script_source": 0,
        "script_structured": 1,
        "material_matched": 2,
        "voice_ready": 3,
        "plan_ready": 4,
        "draft_generated": 5,
    }
    return stages.get(str(project.get("stage") or ""), 0)


def batch_project_semantic_inputs_changed(incoming: dict, current: dict) -> bool:
    for key in ("sourceScriptText", "rawScript"):
        incoming_text = str(incoming.get(key) or "").strip()
        current_text = str(current.get(key) or "").strip()
        if incoming_text and current_text and incoming_text != current_text:
            return True
    keys = ("matchingMode", "durationMode", "materialMatchMinScore", "materialMatchQueryVersion", "materialMatchThresholdVersion")
    for key in keys:
        if incoming.get(key) != current.get(key):
            return True
    return False


def batch_project_stale_downgrade(incoming: dict, current: dict) -> bool:
    if not isinstance(incoming, dict) or not isinstance(current, dict):
        return False
    incoming_requirements = incoming.get("shotRequirements")
    current_requirements = current.get("shotRequirements")
    incoming_matches = incoming.get("materialMatches")
    current_matches = current.get("materialMatches")
    incoming_req_count = len(incoming_requirements) if isinstance(incoming_requirements, list) else 0
    current_req_count = len(current_requirements) if isinstance(current_requirements, list) else 0
    incoming_match_count = len(incoming_matches) if isinstance(incoming_matches, list) else 0
    current_match_count = len(current_matches) if isinstance(current_matches, list) else 0
    if current_req_count <= 0 and current_match_count <= 0:
        return False
    if batch_project_semantic_inputs_changed(incoming, current):
        return False
    if current_req_count > 0 and incoming_req_count == 0:
        return True
    if current_match_count > 0 and incoming_match_count == 0 and incoming_req_count <= current_req_count:
        return True
    return batch_project_stage_rank(incoming) < batch_project_stage_rank(current) and current_match_count > incoming_match_count


def protect_batch_draft_projects_from_stale_overwrite(incoming: list, current: list) -> list:
    if not isinstance(incoming, list):
        return []
    current_by_id = {
        str(item.get("id") or "").strip(): item
        for item in current
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    } if isinstance(current, list) else {}
    protected: list = []
    protected_by_id = dict(current_by_id)
    protected_index_by_id: dict[str, int] = {}
    for item in incoming:
        if not isinstance(item, dict):
            continue
        key = str(item.get("id") or "").strip()
        current_item = protected_by_id.get(key)
        if current_item and batch_project_stale_downgrade(item, current_item):
            next_item = current_item
        elif current_item and batch_project_stale_downgrade(current_item, item):
            next_item = item
        else:
            next_item = item
        if key:
            if key in protected_index_by_id:
                protected[protected_index_by_id[key]] = next_item
            else:
                protected_index_by_id[key] = len(protected)
                protected.append(next_item)
            protected_by_id[key] = next_item
        else:
            protected.append(next_item)
    return protected


def batch_projects_include_stale_downgrade(incoming: list, current: list) -> bool:
    if not isinstance(incoming, list) or not isinstance(current, list):
        return False
    current_by_id = {
        str(item.get("id") or "").strip(): item
        for item in current
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    for item in incoming:
        if not isinstance(item, dict):
            continue
        current_item = current_by_id.get(str(item.get("id") or "").strip())
        if current_item and batch_project_stale_downgrade(item, current_item):
            return True
    return False


def merge_batch_draft_projects_for_persistence(incoming: list, current: list, *, replace: bool = False) -> list:
    protected_incoming = protect_batch_draft_projects_from_stale_overwrite(incoming, current)
    if not replace:
        return normalize_batch_draft_projects([*protected_incoming, *current])
    if batch_projects_include_stale_downgrade(incoming, current):
        incoming_ids = {
            str(item.get("id") or "").strip()
            for item in incoming
            if isinstance(item, dict) and str(item.get("id") or "").strip()
        }
        missing_current = [
            item for item in current
            if isinstance(item, dict) and str(item.get("id") or "").strip() and str(item.get("id") or "").strip() not in incoming_ids
        ]
        return normalize_batch_draft_projects([*protected_incoming, *missing_current])
    return normalize_batch_draft_projects(protected_incoming)


def normalize_batch_draft_projects(raw: object) -> list:
    if not isinstance(raw, list):
        return []
    protected = protect_batch_draft_projects_from_stale_overwrite(raw, [])
    return sorted([recover_batch_draft_project_estimate(item) for item in merge_list_by_stable_id(protected, [])], key=client_item_time, reverse=True)


def read_batch_draft_projects() -> list[dict]:
    if not BATCH_DRAFT_PROJECTS_FILE.exists():
        return []
    try:
        data = json.loads(BATCH_DRAFT_PROJECTS_FILE.read_text(encoding="utf-8"))
        return normalize_batch_draft_projects(data)
    except Exception:
        return []


def write_batch_draft_projects(items: list[dict]) -> None:
    with JSON_STORE_WRITE_LOCK:
        BATCH_DRAFT_PROJECTS_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp_file = BATCH_DRAFT_PROJECTS_FILE.with_suffix(".tmp")
        tmp_file.write_text(json.dumps(normalize_batch_draft_projects(items), ensure_ascii=False, indent=2), encoding="utf-8")
        tmp_file.replace(BATCH_DRAFT_PROJECTS_FILE)


def merge_client_state_value(key: str, incoming: object, current: object, replace: bool = False) -> object:
    if key == "meiao-flow-fission-jobs" and isinstance(incoming, list) and isinstance(current, list):
        return merge_flow_fission_jobs(incoming, current, replace=replace)
    if key == "meiao-flow-accounts" and isinstance(incoming, list):
        current_list = [] if replace else current if isinstance(current, list) else []
        merged = merge_list_by_stable_id(incoming, current_list) if current_list else incoming
        return sanitize_flow_accounts_for_client_state(merged)
    if key == "meiao-batch-draft-projects" and isinstance(incoming, list) and isinstance(current, list):
        return merge_batch_draft_projects_for_persistence(incoming, current, replace=replace)
    if replace:
        return incoming
    if key == "meiao-ingest-items" and isinstance(incoming, list) and isinstance(current, list):
        return merge_media_library_items(incoming, current)
    if key == "meiao-product-projects" and isinstance(incoming, list) and isinstance(current, list):
        state = read_client_state()
        deleted = state.get("meiao-deleted-product-projects") if isinstance(state.get("meiao-deleted-product-projects"), dict) else {}
        return merge_product_projects(incoming, current, deleted)
    if key == "meiao-draft-templates" and isinstance(incoming, list) and isinstance(current, list):
        return merge_draft_templates(incoming, current)
    if key == "meiao-unified-tasks" and isinstance(incoming, list):
        current_list = current if isinstance(current, list) else []
        return normalize_unified_client_tasks([*incoming, *current_list])
    if key in CLIENT_STATE_MERGE_LIST_KEYS and isinstance(incoming, list) and isinstance(current, list):
        return merge_list_by_stable_id(incoming, current)
    if key in CLIENT_STATE_UNION_LIST_KEYS and isinstance(incoming, list) and isinstance(current, list):
        return sorted({str(item) for item in [*incoming, *current] if str(item or "").strip()})
    if key in CLIENT_STATE_MERGE_DICT_KEYS and isinstance(incoming, dict) and isinstance(current, dict):
        return {**current, **incoming}
    return incoming


def client_state_replace_requested(payload: dict, key: str) -> bool:
    replace = payload.get("replace") is True
    if not replace:
        return False
    if payload.get("destructive") is True:
        return True
    # Browser-local state is only a cache. Exact replacement of list-backed
    # workspace data is allowed only for explicit destructive actions so an old
    # browser tab cannot wipe newer local data.
    if key in CLIENT_STATE_MERGE_LIST_KEYS or key in CLIENT_STATE_UNION_LIST_KEYS:
        return False
    return True


def should_skip_empty_client_state_update(key: str, value: object, current_value: object, *, allow_empty: bool = False) -> bool:
    return (
        not allow_empty
        and key in CLIENT_STATE_PROTECTED_EMPTY_KEYS
        and is_empty_client_value(value)
        and not is_empty_client_value(current_value)
    )


def sync_client_state_value(key: str, value: object, *, replace: bool = False) -> None:
    if not key.startswith("meiao-"):
        return
    current = read_client_state()
    if should_skip_empty_client_state_update(key, value, current.get(key), allow_empty=replace):
        return
    current[key] = merge_client_state_value(key, value, current.get(key), replace)
    write_client_state(current)
    try:
        if key == "meiao-ingest-items" and isinstance(current.get(key), list):
            write_media_library_items(merge_media_library_items(current[key], []))
        if key == "meiao-draft-templates" and isinstance(current.get(key), list):
            write_draft_templates(merge_draft_templates(current[key], []))
        if key == "meiao-batch-draft-projects" and isinstance(current.get(key), list):
            write_batch_draft_projects(current[key])
    except Exception as exc:
        append_debug_log("client_state.sidecar_sync.error", {"key": key, "errorType": type(exc).__name__, "error": str(exc)})


def client_state_value_count(value: object) -> int:
    if isinstance(value, (list, dict)):
        return len(value)
    if value is None:
        return 0
    return 1


def client_state_approx_bytes(value: object) -> int:
    try:
        return len(json.dumps(value, ensure_ascii=False, separators=(",", ":")).encode("utf-8"))
    except Exception:
        return 0


CLIENT_STATE_SENSITIVE_KEY_NAMES = {
    "password",
    "apikey",
    "authorization",
    "secret",
    "accesstoken",
    "refreshtoken",
    "admintoken",
    "licensekey",
    "bearertoken",
}


def client_state_sensitive_key_name(key: str) -> bool:
    normalized = key.strip().lower().replace("_", "").replace("-", "").replace(".", "")
    return normalized in CLIENT_STATE_SENSITIVE_KEY_NAMES


def client_state_sensitive_field_count(value: object) -> int:
    if isinstance(value, dict):
        total = 0
        for key, item in value.items():
            if client_state_sensitive_key_name(str(key)) and isinstance(item, str) and item.strip():
                total += 1
            total += client_state_sensitive_field_count(item)
        return total
    if isinstance(value, list):
        return sum(client_state_sensitive_field_count(item) for item in value)
    return 0


def client_state_list_key(item: object) -> str:
    if not isinstance(item, dict):
        return ""
    return str(item.get("id") or item.get("backendMediaId") or item.get("taskId") or item.get("recordId") or "").strip()


def client_state_duplicate_count(value: object) -> int:
    if not isinstance(value, list):
        return 0
    seen: set[str] = set()
    duplicates = 0
    for item in value:
        key = client_state_list_key(item)
        if not key:
            continue
        if key in seen:
            duplicates += 1
        else:
            seen.add(key)
    return duplicates


UNIFIED_TASK_ACTIVE_STATUSES = {"queued", "running"}
UNIFIED_TASK_VALID_STATUSES = {"idle", "queued", "running", "success", "failed", "canceled"}
UNIFIED_TASK_VALID_STAGES = {
    "validating",
    "uploading",
    "submitted",
    "polling",
    "downloading",
    "importing",
    "completed",
    "failed",
    "canceled",
}
UNIFIED_TASK_ACTIVE_STAGE_RANK = {
    "validating": 1,
    "uploading": 2,
    "submitted": 3,
    "polling": 4,
    "downloading": 5,
    "importing": 6,
}
UNIFIED_TASK_STALE_ACTIVE_MS = 10 * 60 * 1000
MAX_UNIFIED_CLIENT_TASKS = 120


def client_state_number(value: object) -> int:
    try:
        return int(float(value))
    except Exception:
        return 0


def summarize_unified_client_tasks(value: object) -> dict:
    result = {
        "total": 0,
        "active": 0,
        "staleActive": 0,
        "failed": 0,
        "canceled": 0,
        "success": 0,
        "malformed": 0,
        "duplicates": 0,
        "duplicateActiveDedupeKeys": 0,
    }
    if not isinstance(value, list):
        if value is not None:
            result["malformed"] = 1
        return result

    timestamp = int(time.time() * 1000)
    seen: set[str] = set()
    active_dedupe_keys: set[str] = set()
    for item in value:
        if not isinstance(item, dict):
            result["malformed"] += 1
            continue
        task_id = str(item.get("taskId") or "").strip()
        title = str(item.get("title") or "").strip()
        status = str(item.get("status") or "").strip()
        stage = str(item.get("stage") or "").strip()
        updated_at = client_state_number(item.get("updatedAt"))
        if not task_id or not title:
            result["malformed"] += 1
            continue
        if task_id in seen:
            result["duplicates"] += 1
        seen.add(task_id)
        result["total"] += 1
        if status not in UNIFIED_TASK_VALID_STATUSES or stage not in UNIFIED_TASK_VALID_STAGES or updated_at <= 0:
            result["malformed"] += 1
        if status in UNIFIED_TASK_ACTIVE_STATUSES:
            result["active"] += 1
            dedupe_key = str(item.get("dedupeKey") or "").strip()
            if dedupe_key:
                if dedupe_key in active_dedupe_keys:
                    result["duplicateActiveDedupeKeys"] += 1
                active_dedupe_keys.add(dedupe_key)
            if updated_at <= 0 or timestamp - updated_at > UNIFIED_TASK_STALE_ACTIVE_MS:
                result["staleActive"] += 1
        elif status == "failed":
            result["failed"] += 1
        elif status == "canceled":
            result["canceled"] += 1
        elif status == "success":
            result["success"] += 1
    return result


def task_status_from_dict_map(value: object, matcher) -> str:
    if not isinstance(value, dict):
        return "missing"
    for item in value.values():
        if isinstance(item, dict) and matcher(item):
            return str(item.get("status") or "")
    return "missing"


def task_status_from_list(value: object, matcher) -> str:
    if not isinstance(value, list):
        return "missing"
    for item in value:
        if isinstance(item, dict) and matcher(item):
            return str(item.get("status") or "")
    return "missing"


def count_inconsistent_active_unified_tasks(state: dict) -> int:
    tasks = state.get("meiao-unified-tasks")
    if not isinstance(tasks, list):
        return 0
    count = 0
    for task in tasks:
        if not isinstance(task, dict) or str(task.get("status") or "") not in UNIFIED_TASK_ACTIVE_STATUSES:
            continue
        task_id = str(task.get("taskId") or "").strip()
        if task_id.startswith("voice:"):
            provider_task_id = task_id.removeprefix("voice:")
            business_status = task_status_from_list(
                state.get("meiao-generated-voice-assets"),
                lambda item: str(item.get("providerTaskId") or "") == provider_task_id,
            )
            if business_status in {"missing", "success", "failed"}:
                count += 1
        elif task_id.startswith("capcut-export:"):
            output_id = task_id.removeprefix("capcut-export:")
            business_status = task_status_from_list(
                state.get("meiao-output-records"),
                lambda item: str(item.get("id") or "") == output_id,
            )
            if business_status == "missing" or business_status != "导出中":
                count += 1
        elif task_id.startswith("capcut-draft:"):
            plan_id = task_id.removeprefix("capcut-draft:")
            business_status = task_status_from_list(
                state.get("meiao-draft-plans"),
                lambda item: str(item.get("id") or "") == plan_id,
            )
            if business_status == "missing" or business_status not in {"generating"}:
                count += 1
        elif task_id.startswith("copy-clean:"):
            backend_task_id = task_id.removeprefix("copy-clean:")
            business_status = task_status_from_dict_map(
                state.get("meiao-copy-clean-tasks"),
                lambda item: str(item.get("taskId") or "") == backend_task_id,
            )
            if business_status == "missing" or business_status not in {"submitted", "waiting", "doing"}:
                count += 1
        elif task_id.startswith("flow-fission:"):
            job_id = task_id.removeprefix("flow-fission:")
            business_status = task_status_from_list(
                state.get("meiao-flow-fission-jobs"),
                lambda item: str(item.get("id") or "") == job_id,
            )
            task_status = str(task.get("status") or "")
            consistent = (
                (task_status == "queued" and business_status == "待执行")
                or (task_status == "running" and business_status in {"执行中", "待人工"})
            )
            if business_status == "missing" or not consistent:
                count += 1
    return count


def unified_active_task_quality_score(task: dict) -> int:
    artifacts = task.get("artifacts")
    return (
        (1000 if str(task.get("backendTaskId") or "").strip() else 0)
        + (100 if isinstance(artifacts, list) and len(artifacts) > 0 else 0)
        + (UNIFIED_TASK_ACTIVE_STAGE_RANK.get(str(task.get("stage") or ""), 0) * 10)
        + min(99, max(0, client_state_number(task.get("progress"))))
    )


def prefer_unified_active_task(candidate: dict, current: dict | None) -> bool:
    if current is None:
        return True
    candidate_score = unified_active_task_quality_score(candidate)
    current_score = unified_active_task_quality_score(current)
    if candidate_score != current_score:
        return candidate_score > current_score
    return client_item_time(candidate) >= client_item_time(current)


def normalize_unified_client_tasks(raw: object) -> list:
    if not isinstance(raw, list):
        return []
    by_id: dict[str, dict] = {}
    for item in raw:
        if not isinstance(item, dict):
            continue
        task_id = str(item.get("taskId") or "").strip()
        title = str(item.get("title") or "").strip()
        status = str(item.get("status") or "").strip()
        stage = str(item.get("stage") or "").strip()
        if (
            not task_id
            or not title
            or status not in UNIFIED_TASK_VALID_STATUSES
            or stage not in UNIFIED_TASK_VALID_STAGES
        ):
            continue
        previous = by_id.get(task_id)
        if previous is None or client_item_time(item) >= client_item_time(previous):
            by_id[task_id] = item
    candidates = sorted(by_id.values(), key=client_item_time, reverse=True)
    active_by_dedupe: dict[str, dict] = {}
    active_without_dedupe: list[dict] = []
    for item in candidates:
        if str(item.get("status") or "") not in UNIFIED_TASK_ACTIVE_STATUSES:
            continue
        dedupe_key = str(item.get("dedupeKey") or "").strip()
        if not dedupe_key:
            active_without_dedupe.append(item)
            continue
        previous = active_by_dedupe.get(dedupe_key)
        if prefer_unified_active_task(item, previous):
            active_by_dedupe[dedupe_key] = item
    active = sorted([*active_by_dedupe.values(), *active_without_dedupe], key=client_item_time, reverse=True)
    attention = [item for item in candidates if str(item.get("status") or "") in {"failed", "canceled"}]
    completed = [item for item in candidates if str(item.get("status") or "") not in UNIFIED_TASK_ACTIVE_STATUSES and str(item.get("status") or "") not in {"failed", "canceled"}]
    return [*active, *attention, *completed][:MAX_UNIFIED_CLIENT_TASKS]


def flow_fission_unified_status_from_job(job: dict) -> str:
    status = str(job.get("status") or "")
    if status == "已完成":
        return "success"
    if status == "失败":
        return "failed"
    if status == "待执行":
        return "queued"
    return "running"


def flow_fission_unified_stage_from_job(job: dict) -> str:
    status = str(job.get("status") or "")
    stage = str(job.get("stage") or "")
    if status == "已完成":
        return "completed"
    if status == "失败":
        return "failed"
    if stage == "首帧":
        return "validating"
    if stage == "生图":
        return "uploading"
    if stage in {"审图", "视频", "人工审核"}:
        return "polling"
    if stage == "入库":
        return "importing"
    return "submitted"


def flow_fission_unified_progress_from_job(job: dict) -> int:
    status = str(job.get("status") or "")
    if status in {"已完成", "失败"}:
        return 100
    stage = str(job.get("stage") or "")
    return {
        "首帧": 12,
        "生图": 36,
        "审图": 58,
        "视频": 76,
        "人工审核": 84,
        "入库": 94,
    }.get(stage, 10)


def normalize_flow_fission_unified_tasks(tasks: object, jobs: object) -> list:
    normalized_tasks = normalize_unified_client_tasks(tasks)
    if not isinstance(jobs, list):
        return normalized_tasks
    jobs_by_id = {
        str(job.get("id") or "").strip(): job
        for job in jobs
        if isinstance(job, dict) and str(job.get("id") or "").strip()
    }
    result: list = []
    for task in normalized_tasks:
        if not isinstance(task, dict):
            continue
        task_id = str(task.get("taskId") or "").strip()
        if not task_id.startswith("flow-fission:"):
            result.append(task)
            continue
        job = jobs_by_id.get(task_id.removeprefix("flow-fission:"))
        if not isinstance(job, dict):
            result.append(task)
            continue
        next_task = dict(task)
        next_task["status"] = flow_fission_unified_status_from_job(job)
        next_task["stage"] = flow_fission_unified_stage_from_job(job)
        next_task["progress"] = flow_fission_unified_progress_from_job(job)
        if next_task["status"] == "queued":
            next_task.pop("startedAt", None)
            next_task.pop("finishedAt", None)
        elif next_task["status"] in {"success", "failed"}:
            next_task["finishedAt"] = job.get("updatedAt") or next_task.get("updatedAt") or int(time.time() * 1000)
        if next_task["status"] == "failed":
            next_task["error"] = next_task.get("error") or next_task.get("message") or "Flow 裂变任务失败"
        elif next_task.get("error") and next_task["status"] in {"queued", "running", "success"}:
            next_task.pop("error", None)
        result.append(next_task)
    return normalize_unified_client_tasks(result)


def sanitize_flow_video_reference_wording(value: object) -> object:
    if isinstance(value, str):
        return (
            value
            .replace("通过审核的首帧图", "视频参考图")
            .replace("裂变首帧图", "视频参考图")
            .replace("裂变首帧在前", "视频参考图在前")
        )
    if isinstance(value, list):
        return [sanitize_flow_video_reference_wording(item) for item in value]
    if isinstance(value, dict):
        return {key: sanitize_flow_video_reference_wording(item) for key, item in value.items()}
    return value


def summarize_client_state(state: dict) -> list[dict]:
    rows: list[dict] = []
    for key in sorted(k for k in state.keys() if isinstance(k, str) and k.startswith("meiao-")):
        value = state.get(key)
        expected = "list" if key in CLIENT_STATE_MERGE_LIST_KEYS or key in CLIENT_STATE_UNION_LIST_KEYS else "dict" if key in CLIENT_STATE_MERGE_DICT_KEYS else type(value).__name__
        malformed = (
            (expected == "list" and not isinstance(value, list))
            or (expected == "dict" and not isinstance(value, dict))
        )
        rows.append({
            "key": key,
            "type": type(value).__name__,
            "expected": expected,
            "count": client_state_value_count(value),
            "approxBytes": client_state_approx_bytes(value),
            "sensitiveFields": client_state_sensitive_field_count(value),
            "empty": is_empty_client_value(value),
            "protected": key in CLIENT_STATE_PROTECTED_EMPTY_KEYS,
            "duplicates": client_state_duplicate_count(value),
            "malformed": malformed,
        })
    return rows


def build_client_state_health() -> dict:
    raw_state = read_client_state()
    raw_media_items = read_media_library_items()
    raw_disk_media_items = recover_media_library_items_from_disk()
    raw_draft_templates = read_draft_templates()
    raw_state_ingest_count = client_state_value_count(raw_state.get("meiao-ingest-items"))
    raw_state_template_count = client_state_value_count(raw_state.get("meiao-draft-templates"))
    raw_media_count = client_state_value_count(raw_media_items)
    raw_disk_media_count = client_state_value_count(raw_disk_media_items)
    raw_template_count = client_state_value_count(raw_draft_templates)
    raw_unified_task_summary = summarize_unified_client_tasks(raw_state.get("meiao-unified-tasks"))
    state = build_recovered_client_state()
    rows = summarize_client_state(state)
    ingest_ids = {
        str(item.get("id") or "").strip()
        for item in state.get("meiao-ingest-items", [])
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    queue = [str(item or "").strip() for item in state.get("meiao-scene-split-queue", []) if str(item or "").strip()]
    orphan_queue = [item for item in queue if item not in ingest_ids]
    duplicate_total = sum(int(row.get("duplicates") or 0) for row in rows)
    malformed_total = sum(1 for row in rows if row.get("malformed"))
    approx_total = sum(int(row.get("approxBytes") or 0) for row in rows)
    sensitive_total = sum(int(row.get("sensitiveFields") or 0) for row in rows)
    oversized_rows = [row for row in rows if int(row.get("approxBytes") or 0) >= 1_000_000]
    empty_protected = [row.get("key") for row in rows if row.get("protected") and row.get("empty")]
    unified_task_summary = summarize_unified_client_tasks(state.get("meiao-unified-tasks"))
    trimmed_unified_task_count = max(0, raw_unified_task_summary["total"] - unified_task_summary["total"])
    inconsistent_active_unified_tasks = count_inconsistent_active_unified_tasks(state)
    duplicate_active_dedupe_keys = max(
        raw_unified_task_summary["duplicateActiveDedupeKeys"],
        unified_task_summary["duplicateActiveDedupeKeys"],
    )
    issues = []
    if duplicate_total:
        issues.append({"level": "warning", "message": f"发现 {duplicate_total} 条重复本地记录，可安全合并。"})
    if orphan_queue:
        issues.append({"level": "warning", "message": f"分镜队列里有 {len(orphan_queue)} 条素材已不在素材库。"})
    if malformed_total:
        issues.append({"level": "error", "message": f"发现 {malformed_total} 个状态字段结构异常。"})
    if oversized_rows:
        labels = "、".join(str(row.get("key")) for row in oversized_rows[:3])
        issues.append({"level": "warning", "message": f"{labels} 本地状态体积较大，可能拖慢首次恢复和 NAS 同步。"})
    if sensitive_total:
        issues.append({"level": "warning", "message": f"本地状态里发现 {sensitive_total} 个敏感字段；打包交付前应迁入独立配置或账号安全存储。"})
    if empty_protected:
        issues.append({"level": "info", "message": f"{len(empty_protected)} 个本地状态当前为空；页面会以运行时数据为准同步浏览器缓存。"})
    if unified_task_summary["staleActive"]:
        issues.append({"level": "warning", "message": f"有 {unified_task_summary['staleActive']} 个统一任务长时间未更新，建议在任务中心刷新或重试。"})
    if unified_task_summary["malformed"]:
        issues.append({"level": "warning", "message": f"有 {unified_task_summary['malformed']} 条统一任务状态不完整，可先备份后清理。"})
    if duplicate_active_dedupe_keys:
        issues.append({"level": "warning", "message": f"有 {duplicate_active_dedupe_keys} 个统一任务疑似重复运行，已优先保留最新执行记录。"})
    if inconsistent_active_unified_tasks:
        issues.append({"level": "warning", "message": f"有 {inconsistent_active_unified_tasks} 个统一任务仍显示执行中，但来源业务记录已完成、失败或丢失，建议在任务中心刷新后重试或移除。"})
    if raw_unified_task_summary["total"] > MAX_UNIFIED_CLIENT_TASKS:
        issues.append({"level": "info", "message": f"统一任务历史超过保留上限，已优先保留执行中、失败/停止和最近完成的 {MAX_UNIFIED_CLIENT_TASKS} 条。"})
    if raw_state_ingest_count and raw_media_count and raw_media_count < raw_state_ingest_count:
        issues.append({"level": "warning", "message": f"独立素材库少于统一工作台状态，已自动校准：{raw_media_count} -> {client_state_value_count(state.get('meiao-ingest-items'))}。"})
    if raw_disk_media_count and raw_media_count < raw_disk_media_count:
        issues.append({"level": "warning", "message": f"磁盘素材多于独立素材库，已自动从本地文件恢复：{raw_media_count} -> {client_state_value_count(state.get('meiao-ingest-items'))}。"})
    if raw_state_template_count and raw_template_count < raw_state_template_count:
        issues.append({"level": "warning", "message": f"草稿模板备份少于统一工作台状态，已自动校准：{raw_template_count} -> {client_state_value_count(state.get('meiao-draft-templates'))}。"})
    batch_project_file_items = read_batch_draft_projects()
    raw_batch_project_count = client_state_value_count(raw_state.get("meiao-batch-draft-projects"))
    batch_project_file_count = client_state_value_count(batch_project_file_items)
    if raw_batch_project_count and batch_project_file_count < raw_batch_project_count:
        issues.append({"level": "warning", "message": f"批量任务备份少于统一工作台状态，已自动校准：{batch_project_file_count} -> {client_state_value_count(state.get('meiao-batch-draft-projects'))}。"})
    return {
        "generatedAt": int(time.time() * 1000),
        "stateFile": str(CLIENT_STATE_FILE),
        "backupCount": len(list(CLIENT_STATE_BACKUP_DIR.glob("*.json"))) if CLIENT_STATE_BACKUP_DIR.exists() else 0,
        "summary": rows,
        "issues": issues,
        "totals": {
            "keys": len(rows),
            "duplicates": duplicate_total,
            "malformed": malformed_total,
            "approxBytes": approx_total,
            "sensitiveFields": sensitive_total,
            "orphanSceneQueue": len(orphan_queue),
            "ingestItems": len(ingest_ids),
            "draftTemplates": client_state_value_count(state.get("meiao-draft-templates")),
            "batchProjects": client_state_value_count(state.get("meiao-batch-draft-projects")),
            "unifiedTasks": unified_task_summary["total"],
            "maxUnifiedTasks": MAX_UNIFIED_CLIENT_TASKS,
            "rawUnifiedTasks": raw_unified_task_summary["total"],
            "trimmedUnifiedTasks": trimmed_unified_task_count,
            "activeUnifiedTasks": unified_task_summary["active"],
            "staleUnifiedTasks": unified_task_summary["staleActive"],
            "inconsistentActiveUnifiedTasks": inconsistent_active_unified_tasks,
            "failedUnifiedTasks": unified_task_summary["failed"],
            "canceledUnifiedTasks": unified_task_summary["canceled"],
            "malformedUnifiedTasks": unified_task_summary["malformed"],
            "duplicateUnifiedTasks": unified_task_summary["duplicates"],
            "duplicateActiveDedupeKeys": duplicate_active_dedupe_keys,
            "mediaLibraryFileItems": client_state_value_count(read_media_library_items()),
            "diskMediaItems": raw_disk_media_count,
            "draftTemplateFileItems": client_state_value_count(read_draft_templates()),
            "batchProjectFileItems": client_state_value_count(read_batch_draft_projects()),
        },
    }


def clean_client_state(*, apply: bool = False) -> dict:
    state = build_recovered_client_state()
    cleaned = dict(state)
    changes: list[dict] = []
    for key in CLIENT_STATE_MERGE_LIST_KEYS:
        value = cleaned.get(key)
        if not isinstance(value, list):
            continue
        next_value = (
            merge_draft_templates(value, [])
            if key == "meiao-draft-templates"
            else merge_media_library_items(value, [])
            if key == "meiao-ingest-items"
            else normalize_batch_draft_projects(value)
            if key == "meiao-batch-draft-projects"
            else normalize_unified_client_tasks(value)
            if key == "meiao-unified-tasks"
            else merge_list_by_stable_id(value, [])
        )
        if next_value != value:
            changes.append({
                "key": key,
                "before": len(value),
                "after": len(next_value),
                "action": "dedupe-normalize" if len(next_value) == len(value) else "dedupe",
            })
            cleaned[key] = next_value
    queue = cleaned.get("meiao-scene-split-queue")
    if isinstance(queue, list):
        ingest_ids = {
            str(item.get("id") or "").strip()
            for item in cleaned.get("meiao-ingest-items", [])
            if isinstance(item, dict) and str(item.get("id") or "").strip()
        }
        next_queue = []
        seen_queue: set[str] = set()
        for item in queue:
            value = str(item or "").strip()
            if not value or value in seen_queue or (ingest_ids and value not in ingest_ids):
                continue
            seen_queue.add(value)
            next_queue.append(value)
        if next_queue != queue:
            changes.append({"key": "meiao-scene-split-queue", "before": len(queue), "after": len(next_queue), "action": "prune-orphans"})
            cleaned["meiao-scene-split-queue"] = next_queue
    if apply and changes:
        snapshot_client_state(read_client_state(), "before-clean")
        write_client_state(cleaned)
        if isinstance(cleaned.get("meiao-ingest-items"), list):
            write_media_library_items(cleaned["meiao-ingest-items"])
        if isinstance(cleaned.get("meiao-draft-templates"), list):
            write_draft_templates(cleaned["meiao-draft-templates"])
        if isinstance(cleaned.get("meiao-batch-draft-projects"), list):
            write_batch_draft_projects(cleaned["meiao-batch-draft-projects"])
    return {"applied": apply, "changes": changes, "health": build_client_state_health() if apply else {"summary": summarize_client_state(cleaned)}}


PROJECT_GLOBAL_MEDIA_IDS = {"bgm-library", "capcut-fonts", "capcut-audio", "_capcut_assets", "__capcut_assets__"}


def project_scoped_item(item: object, project_id: str) -> bool:
    if not isinstance(item, dict):
        return False
    item_project_id = str(item.get("projectId") or "").strip()
    if item_project_id:
        return item_project_id == project_id
    # Legacy data created before product projects were isolated belongs to the
    # built-in x5pro test project.
    return project_id == "x5pro"


def collect_media_ids_from_value(value: object) -> set[str]:
    ids: set[str] = set()
    if isinstance(value, dict):
        for key, item in value.items():
            if str(key).lower().endswith("mediaid") and str(item or "").strip():
                ids.add(str(item).strip())
            elif isinstance(item, str) and ("/media/" in item or item.startswith("http://127.0.0.1")):
                media_id = media_id_from_media_url(item)
                if media_id:
                    ids.add(media_id)
            elif isinstance(item, (dict, list)):
                ids.update(collect_media_ids_from_value(item))
    elif isinstance(value, list):
        for item in value:
            ids.update(collect_media_ids_from_value(item))
    return {item for item in ids if item and item not in PROJECT_GLOBAL_MEDIA_IDS}


def delete_project_media_dirs(media_ids: set[str]) -> dict:
    deleted: list[str] = []
    skipped: list[str] = []
    errors: list[dict] = []
    media_root = MEDIA_ROOT.resolve()
    for media_id in sorted(media_ids):
        if not media_id or media_id in PROJECT_GLOBAL_MEDIA_IDS or "/" in media_id or "\\" in media_id:
            skipped.append(media_id)
            continue
        target = (MEDIA_ROOT / media_id).resolve()
        try:
            if media_root not in target.parents:
                skipped.append(media_id)
                continue
            if target.exists() and target.is_dir():
                shutil.rmtree(target, ignore_errors=False)
                deleted.append(media_id)
        except Exception as exc:
            errors.append({"mediaId": media_id, "error": str(exc)})
    return {"deleted": deleted, "skipped": skipped, "errors": errors}


def safe_media_child_path(media_id: str, relative_path: str) -> Path | None:
    media_id = sanitize_filename(str(media_id or "").strip())
    relative_path = str(relative_path or "").replace("\\", "/").lstrip("/")
    if not media_id or not relative_path:
        return None
    target = (MEDIA_ROOT / media_id / relative_path).resolve()
    media_dir = (MEDIA_ROOT / media_id).resolve()
    try:
        target.relative_to(media_dir)
    except ValueError:
        return None
    return target


def delete_scene_segment_files(media_id: str, segments: list[dict]) -> dict:
    deleted: list[str] = []
    skipped: list[str] = []
    errors: list[dict] = []
    for segment in segments:
        if not isinstance(segment, dict):
            continue
        paths: list[str] = []
        filename = str(segment.get("filename") or "").strip()
        if filename:
            paths.append(filename if filename.startswith("scenes/") else f"scenes/{filename}")
            stem = Path(filename).stem
            if stem:
                paths.append(f"scenes/{stem}.jpg")
        for field in ("url", "posterUrl"):
            media_path = media_url_to_file_path(segment.get(field))
            if media_path and media_path.exists():
                try:
                    media_path.unlink()
                    deleted.append(str(media_path.relative_to(MEDIA_ROOT / sanitize_filename(media_id))))
                except Exception as exc:
                    errors.append({"path": str(media_path), "error": str(exc)})
        for relative_path in paths:
            target = safe_media_child_path(media_id, relative_path)
            if not target:
                skipped.append(relative_path)
                continue
            if not target.exists():
                skipped.append(relative_path)
                continue
            try:
                target.unlink()
                deleted.append(relative_path)
            except Exception as exc:
                errors.append({"path": relative_path, "error": str(exc)})
    return {"deleted": sorted(set(deleted)), "skipped": sorted(set(skipped)), "errors": errors}


def delete_product_project_cascade(project_id: str) -> dict:
    state = build_recovered_client_state()
    snapshot_client_state(read_client_state(), f"before-delete-project-{project_id}")
    next_state = dict(state)
    deleted: dict[str, int] = {}

    def list_items(key: str) -> list:
        value = next_state.get(key)
        return value if isinstance(value, list) else []

    def dict_items(key: str) -> dict:
        value = next_state.get(key)
        return value if isinstance(value, dict) else {}

    projects = list_items("meiao-product-projects")
    next_projects = [item for item in projects if not (isinstance(item, dict) and str(item.get("id") or "").strip() == project_id)]
    next_state["meiao-product-projects"] = next_projects
    deleted["projects"] = len(projects) - len(next_projects)

    ingest_items = list_items("meiao-ingest-items")
    removed_ingest_items = [item for item in ingest_items if project_scoped_item(item, project_id)]
    removed_ingest_ids = {str(item.get("id") or "").strip() for item in removed_ingest_items if isinstance(item, dict) and str(item.get("id") or "").strip()}
    removed_media_ids = set()
    for item in removed_ingest_items:
        if not isinstance(item, dict):
            continue
        removed_media_ids.update(collect_media_ids_from_value(item))
        backend_media_id = str(item.get("backendMediaId") or "").strip()
        if backend_media_id:
            removed_media_ids.add(backend_media_id)
    next_state["meiao-ingest-items"] = [item for item in ingest_items if item not in removed_ingest_items]
    deleted["ingestItems"] = len(removed_ingest_items)

    for key in ("meiao-copy-clean-review", "meiao-copy-clean-tasks", "meiao-copy-clean-regions"):
        records = dict_items(key)
        next_records = {item_id: value for item_id, value in records.items() if str(item_id) not in removed_ingest_ids}
        next_state[key] = next_records
        deleted[key] = len(records) - len(next_records)

    split_records = dict_items("meiao-scene-split-records")
    removed_script_ids: set[str] = set()
    next_split_records = {}
    for key, record in split_records.items():
        record_media_ids = collect_media_ids_from_value(record)
        record_ingest_id = str(record.get("ingestId") or "").strip() if isinstance(record, dict) else ""
        record_script_id = str(record.get("scriptId") or key or "").strip() if isinstance(record, dict) else str(key)
        remove = (
            record_ingest_id in removed_ingest_ids
            or bool(record_media_ids & removed_media_ids)
            or project_scoped_item(record, project_id)
        )
        if remove:
            if record_script_id:
                removed_script_ids.add(record_script_id)
            removed_media_ids.update(record_media_ids)
        else:
            next_split_records[key] = record
    next_state["meiao-scene-split-records"] = next_split_records
    deleted["sceneSplitRecords"] = len(split_records) - len(next_split_records)

    queue = list_items("meiao-scene-split-queue")
    next_queue = [item for item in queue if str(item or "").strip() not in removed_ingest_ids and str(item or "").strip() not in removed_script_ids]
    next_state["meiao-scene-split-queue"] = next_queue
    deleted["sceneSplitQueue"] = len(queue) - len(next_queue)

    hidden = list_items("meiao-scene-split-hidden-records")
    next_hidden = [item for item in hidden if str(item or "").strip() not in removed_ingest_ids and str(item or "").strip() not in removed_script_ids]
    next_state["meiao-scene-split-hidden-records"] = next_hidden
    deleted["sceneHiddenRecords"] = len(hidden) - len(next_hidden)

    for key in ("meiao-scene-vector-status", "meiao-script-quality", "meiao-script-renames"):
        records = dict_items(key)
        next_records = {item_id: value for item_id, value in records.items() if str(item_id) not in removed_script_ids}
        next_state[key] = next_records
        deleted[key] = len(records) - len(next_records)

    batch_projects = list_items("meiao-batch-draft-projects")
    removed_batch_projects = [
        item for item in batch_projects
        if project_scoped_item(item, project_id)
        or (isinstance(item, dict) and str(item.get("sourceVideoBackendMediaId") or "").strip() in removed_media_ids)
    ]
    removed_task_ids = {str(item.get("id") or "").strip() for item in removed_batch_projects if isinstance(item, dict) and str(item.get("id") or "").strip()}
    next_state["meiao-batch-draft-projects"] = [item for item in batch_projects if item not in removed_batch_projects]
    deleted["batchProjects"] = len(removed_batch_projects)

    draft_plans = list_items("meiao-draft-plans")
    next_draft_plans = [item for item in draft_plans if not (isinstance(item, dict) and str(item.get("taskId") or "").strip() in removed_task_ids)]
    removed_plan_ids = {str(item.get("id") or "").strip() for item in draft_plans if isinstance(item, dict) and item not in next_draft_plans and str(item.get("id") or "").strip()}
    next_state["meiao-draft-plans"] = next_draft_plans
    deleted["draftPlans"] = len(draft_plans) - len(next_draft_plans)

    voice_assets = list_items("meiao-generated-voice-assets")
    next_voice_assets = [item for item in voice_assets if not (isinstance(item, dict) and str(item.get("taskId") or "").strip() in removed_task_ids)]
    removed_media_ids.update(collect_media_ids_from_value([item for item in voice_assets if item not in next_voice_assets]))
    next_state["meiao-generated-voice-assets"] = next_voice_assets
    deleted["voiceAssets"] = len(voice_assets) - len(next_voice_assets)

    draft_templates = list_items("meiao-draft-templates")
    next_draft_templates = [item for item in draft_templates if not project_scoped_item(item, project_id)]
    next_state["meiao-draft-templates"] = next_draft_templates
    deleted["draftTemplates"] = len(draft_templates) - len(next_draft_templates)

    for key in ("meiao-output-tasks", "meiao-output-records", "meiao-unified-tasks", "meiao-ab-dedup-results"):
        items = list_items(key)
        next_items = [
            item for item in items
            if not (
                project_scoped_item(item, project_id)
                or (isinstance(item, dict) and str(item.get("taskId") or "").strip() in removed_task_ids)
                or (isinstance(item, dict) and str(item.get("planId") or "").strip() in removed_plan_ids)
            )
        ]
        removed_media_ids.update(collect_media_ids_from_value([item for item in items if item not in next_items]))
        next_state[key] = next_items
        deleted[key] = len(items) - len(next_items)

    fission_jobs = list_items("meiao-flow-fission-jobs")
    removed_fission_jobs = [
        item for item in fission_jobs
        if project_scoped_item(item, project_id)
        or (isinstance(item, dict) and str(item.get("sourceScriptId") or "").strip() in removed_script_ids)
        or (project_id == "x5pro" and isinstance(item, dict) and not str(item.get("projectId") or "").strip())
    ]
    removed_fission_job_ids = {str(item.get("id") or "").strip() for item in removed_fission_jobs if isinstance(item, dict) and str(item.get("id") or "").strip()}
    removed_media_ids.update(collect_media_ids_from_value(removed_fission_jobs))
    next_state["meiao-flow-fission-jobs"] = [item for item in fission_jobs if item not in removed_fission_jobs]
    deleted["flowFissionJobs"] = len(removed_fission_jobs)

    fission_assets = list_items("meiao-flow-fission-assets")
    next_fission_assets = [
        item for item in fission_assets
        if not (
            project_scoped_item(item, project_id)
            or (isinstance(item, dict) and str(item.get("jobId") or "").strip() in removed_fission_job_ids)
        )
    ]
    removed_media_ids.update(collect_media_ids_from_value([item for item in fission_assets if item not in next_fission_assets]))
    next_state["meiao-flow-fission-assets"] = next_fission_assets
    deleted["flowFissionAssets"] = len(fission_assets) - len(next_fission_assets)

    fission_done = dict_items("meiao-fission-done")
    next_fission_done = {
        key: value for key, value in fission_done.items()
        if str(key) not in removed_fission_job_ids and str(key) not in removed_ingest_ids and str(key) not in removed_script_ids
    }
    next_state["meiao-fission-done"] = next_fission_done
    deleted["fissionDone"] = len(fission_done) - len(next_fission_done)

    for key in ("meiao-shot-usage", "meiao-shot-reservations"):
        records = dict_items(key)
        next_records = {
            item_id: value for item_id, value in records.items()
            if str(item_id) not in removed_plan_ids and str(item_id) not in removed_task_ids
        }
        next_state[key] = next_records
        deleted[key] = len(records) - len(next_records)

    ai_output_workspaces = dict_items("meiao-ai-output-workspaces")
    next_ai_output_workspaces = {
        key: value for key, value in ai_output_workspaces.items()
        if str(key) != project_id
    }
    next_state["meiao-ai-output-workspaces"] = next_ai_output_workspaces
    deleted["aiOutputWorkspaces"] = len(ai_output_workspaces) - len(next_ai_output_workspaces)

    vector_removed = int(prune_vector_items(project_id=project_id).get("removed") or 0)
    for media_id in sorted(removed_media_ids):
        vector_removed += int(prune_vector_items(media_id=media_id).get("removed") or 0)
    deleted["vectors"] = int(deleted.get("vectors") or 0) + vector_removed

    media_delete_result = delete_project_media_dirs(removed_media_ids)
    write_client_state(next_state)
    write_media_library_items(merge_media_library_items(next_state.get("meiao-ingest-items", []), []))
    write_draft_templates(merge_draft_templates(next_state.get("meiao-draft-templates", []), []))
    write_batch_draft_projects(normalize_batch_draft_projects(next_state.get("meiao-batch-draft-projects", [])))
    append_debug_log(
        "api.product_projects.delete",
        {
            "projectId": project_id,
            "deleted": deleted,
            "mediaIds": sorted(removed_media_ids),
            "mediaDeleteResult": media_delete_result,
        },
    )
    return {
        "ok": True,
        "projectId": project_id,
        "deleted": deleted,
        "mediaIds": sorted(removed_media_ids),
        "mediaDeleteResult": media_delete_result,
        "state": next_state,
        "health": build_client_state_health(),
    }


def stable_script_id_from_ingest_id(ingest_id: str) -> str:
    normalized = re.sub(r"[^A-Za-z0-9]", "", str(ingest_id or "").removeprefix("IN-"))
    return f"S-{normalized or ingest_id}"


def natural_sort_key(value: str) -> list[object]:
    return [int(part) if part.isdigit() else part.lower() for part in re.split(r"(\d+)", value)]


def recover_scene_split_records_from_vectors(valid_media_ids: set[str] | None = None) -> tuple[dict, dict]:
    if not VECTOR_STORE_FILE.exists():
        return {}, {}
    try:
        store = json.loads(VECTOR_STORE_FILE.read_text(encoding="utf-8"))
        items = store.get("items") if isinstance(store, dict) else {}
    except Exception:
        return {}, {}
    if not isinstance(items, dict):
        return {}, {}
    grouped: dict[str, list[dict]] = {}
    for raw in items.values():
        if not isinstance(raw, dict):
            continue
        script_id = str(raw.get("scriptId") or "").strip()
        media_id = str(raw.get("mediaId") or "").strip()
        segment_index = raw.get("segmentIndex")
        if not script_id or not media_id or not isinstance(segment_index, int):
            continue
        if valid_media_ids is not None and media_id not in valid_media_ids:
            continue
        grouped.setdefault(f"{script_id}|{media_id}", []).append(raw)

    records: dict = {}
    vector_status: dict = {}
    for group_key, group_items in grouped.items():
        script_id, media_id = group_key.split("|", 1)
        group_items.sort(key=lambda item: int(item.get("segmentIndex") or 0))
        cursor = 0.0
        segments = []
        split_run_id = ""
        updated_at = 0
        for item in group_items:
            duration = float(item.get("duration") or 0) or 0.1
            start = cursor
            end = start + duration
            cursor = end
            split_run_id = split_run_id or str(item.get("splitRunId") or "")
            updated_at = max(updated_at, int((parse_iso_time(item.get("updatedAt")) or datetime.utcnow()).timestamp() * 1000))
            segments.append({
                "index": int(item.get("segmentIndex") or len(segments) + 1),
                "segmentId": item.get("segmentId"),
                "splitRunId": item.get("splitRunId"),
                "start": round(start, 3),
                "end": round(end, 3),
                "duration": round(duration, 3),
                "filename": str(item.get("filename") or ""),
                "url": item.get("url"),
                "posterUrl": item.get("posterUrl"),
                "mediaId": media_id,
            })
        if not segments:
            continue
        records[script_id] = {
            "status": "done",
            "segments": len(segments),
            "mediaId": media_id,
            "scriptId": script_id,
            "splitRunId": split_run_id,
            "sceneSegments": segments,
            "updatedAt": updated_at or int(time.time() * 1000),
        }
        vector_status[script_id] = "done"
    return records, vector_status


def recover_scene_split_records_from_media_files(ingest_items: list[dict], existing_records: dict) -> dict:
    recovered: dict = {}
    media_with_records = {
        str(record.get("mediaId") or "").strip()
        for record in existing_records.values()
        if isinstance(record, dict) and str(record.get("mediaId") or "").strip()
    }
    for item in ingest_items:
        if not isinstance(item, dict):
            continue
        ingest_id = str(item.get("id") or "").strip()
        media_id = str(item.get("backendMediaId") or "").strip()
        if not ingest_id or not media_id or media_id in media_with_records:
            continue
        scenes_dir = MEDIA_ROOT / media_id / "scenes"
        if not scenes_dir.exists():
            continue
        segment_paths = sorted(
            [path for path in scenes_dir.glob("scene-*.mp4") if path.is_file()],
            key=lambda path: natural_sort_key(path.name),
        )
        if not segment_paths:
            continue
        cursor = 0.0
        split_run_id = re.sub(r"-\d{3}$", "", segment_paths[0].stem.removeprefix("scene-"))
        segments: list[dict] = []
        updated_at = 0
        for index, segment_path in enumerate(segment_paths, start=1):
            duration = probe_video_duration(segment_path) or 0.1
            start = cursor
            end = start + duration
            cursor = end
            poster_path = segment_path.with_suffix(".jpg")
            updated_at = max(updated_at, int(segment_path.stat().st_mtime * 1000))
            segments.append({
                "index": index,
                "segmentId": f"{split_run_id}-{index:03d}",
                "splitRunId": split_run_id,
                "start": round(start, 3),
                "end": round(end, 3),
                "duration": round(duration, 3),
                "filename": segment_path.name,
                "url": get_public_media_url(media_id, f"scenes/{segment_path.name}"),
                "posterUrl": get_public_media_url(media_id, f"scenes/{poster_path.name}") if poster_path.exists() else None,
                "mediaId": media_id,
            })
        script_id = stable_script_id_from_ingest_id(ingest_id)
        recovered[script_id] = {
            "status": "done",
            "segments": len(segments),
            "mediaId": media_id,
            "scriptId": script_id,
            "ingestId": ingest_id,
            "source": str(item.get("title") or item.get("source") or media_id),
            "splitRunId": split_run_id,
            "sceneSegments": segments,
            "updatedAt": updated_at or int(time.time() * 1000),
        }
        media_with_records.add(media_id)
    if recovered:
        append_debug_log("client_state.recover.scene_split_files", {"recovered": len(recovered)})
    return recovered


def active_product_project_ids_from_state(state: dict) -> set[str]:
    projects = state.get("meiao-product-projects") if isinstance(state.get("meiao-product-projects"), list) else []
    return {
        str(project.get("id") or "").strip()
        for project in projects
        if isinstance(project, dict) and str(project.get("id") or "").strip()
    }


def filter_project_scoped_list(value: object, active_project_ids: set[str]) -> list:
    items = value if isinstance(value, list) else []
    if not active_project_ids:
        return list(items)
    return [
        item for item in items
        if isinstance(item, dict) and str(item.get("projectId") or "").strip() in active_project_ids
    ]


def ingest_item_belongs_to_active_project(item: dict, active_project_ids: set[str]) -> bool:
    if not active_project_ids:
        return True
    project_id = str(item.get("projectId") or "").strip()
    if project_id:
        return project_id in active_project_ids
    return "x5pro" in active_project_ids


def filter_ingest_items_for_active_projects(items: list[dict], active_project_ids: set[str]) -> list[dict]:
    return [
        item for item in items
        if isinstance(item, dict) and ingest_item_belongs_to_active_project(item, active_project_ids)
    ]


def scene_split_record_media_ids(record: dict) -> set[str]:
    media_ids: set[str] = set()
    media_id = str(record.get("mediaId") or "").strip()
    if media_id:
        media_ids.add(media_id)
    segments = record.get("sceneSegments") if isinstance(record.get("sceneSegments"), list) else []
    for segment in segments:
        if not isinstance(segment, dict):
            continue
        segment_media_id = str(segment.get("mediaId") or "").strip()
        if segment_media_id:
            media_ids.add(segment_media_id)
            continue
        for field in ("url", "posterUrl"):
            inferred = media_id_from_media_url(segment.get(field))
            if inferred:
                media_ids.add(inferred)
    return media_ids


def filter_scene_split_records_for_active_media(records: dict, valid_media_ids: set[str], valid_script_ids: set[str]) -> dict:
    if not isinstance(records, dict):
        return {}
    filtered: dict = {}
    for key, record in records.items():
        if not isinstance(record, dict):
            continue
        script_id = str(record.get("scriptId") or key or "").strip()
        if script_id in valid_script_ids:
            filtered[key] = record
            continue
        media_ids = scene_split_record_media_ids(record)
        if media_ids and any(media_id in valid_media_ids for media_id in media_ids):
            filtered[key] = record
    return filtered


def recover_flow_fission_assets_from_disk(existing_assets: object | None = None, valid_job_ids: set[str] | None = None) -> list[dict]:
    existing_assets = existing_assets if isinstance(existing_assets, list) else []
    existing_ids = {
        str(item.get("id") or "").strip()
        for item in existing_assets
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    existing_file_keys = {
        (
            str(item.get("jobId") or "").strip(),
            str(item.get("type") or "").strip(),
            str(item.get("fileName") or "").strip(),
        )
        for item in existing_assets
        if isinstance(item, dict)
        and str(item.get("jobId") or "").strip()
        and str(item.get("type") or "").strip()
        and str(item.get("fileName") or "").strip()
    }
    recovered_file_keys: set[tuple[str, str, str]] = set()
    recovered: list[dict] = []
    if not MEDIA_ROOT.exists():
        return recovered
    for media_dir in sorted(MEDIA_ROOT.glob("flow-fission-FJ-*")):
        if not media_dir.is_dir():
            continue
        media_id = media_dir.name
        job_id = media_id.removeprefix("flow-fission-")
        if valid_job_ids is not None and job_id not in valid_job_ids:
            continue
        for path in sorted(media_dir.iterdir(), key=lambda item: item.stat().st_mtime if item.exists() else 0):
            if not path.is_file():
                continue
            if path.stem.endswith("-poster"):
                continue
            suffix = path.suffix.lower()
            asset_type = "video" if suffix in VIDEO_FILE_SUFFIXES else "image" if suffix in {".jpg", ".jpeg", ".png", ".webp", ".gif"} else ""
            if not asset_type:
                continue
            if asset_type == "image" and any((media_dir / f"{path.stem}{video_suffix}").exists() for video_suffix in VIDEO_FILE_SUFFIXES):
                continue
            match = re.match(r"flow-(image|video)-([A-Za-z0-9]+)", path.stem)
            digest = match.group(2) if match else hashlib.sha1(path.name.encode("utf-8")).hexdigest()[:12]
            asset_id = sanitize_filename(f"FLOW-{asset_type.upper()}-{job_id}-{digest}")
            if asset_id in existing_ids:
                continue
            created_at = int(path.stat().st_mtime * 1000)
            file_key = (job_id, asset_type, path.name)
            if file_key in existing_file_keys or file_key in recovered_file_keys:
                continue
            recovered_file_keys.add(file_key)
            poster_url = ""
            if asset_type == "video":
                poster_path = media_dir / f"{path.stem}-poster.jpg"
                if poster_path.exists():
                    poster_url = get_public_media_url(media_id, poster_path.name)
            recovered.append({
                "schemaVersion": 3,
                "id": asset_id,
                "jobId": job_id,
                "type": asset_type,
                "name": f"Flow裂变{'视频' if asset_type == 'video' else '图'}-{digest}",
                "url": get_public_media_url(media_id, path.name),
                "posterUrl": poster_url,
                "sourceUrl": "flow-disk-recovery",
                "flowResultOrdinal": len(recovered) + 1,
                "flowResultHref": "",
                "flowResultContext": "本地磁盘恢复的 Flow 生成结果",
                "flowSourceKind": "disk-recovery",
                "localMediaId": media_id,
                "fileName": path.name,
                "fileSize": path.stat().st_size,
                "mimeType": mimetypes.guess_type(path.name)[0] or ("video/mp4" if asset_type == "video" else "image/png"),
                "prompt": "",
                "status": "待质检",
                "selected": asset_type == "video",
                "createdAt": created_at,
            })
    return recovered


def bind_flow_fission_assets_to_slots(assets: object, jobs: object) -> list:
    if not isinstance(assets, list) or not isinstance(jobs, list):
        return assets if isinstance(assets, list) else []
    slot_by_asset_id: dict[str, dict] = {}
    for job in jobs:
        if not isinstance(job, dict):
            continue
        for slot in job.get("promptSlots") if isinstance(job.get("promptSlots"), list) else []:
            if not isinstance(slot, dict):
                continue
            for asset_field, asset_type in (("imageAssetId", "image"), ("videoAssetId", "video")):
                asset_id = str(slot.get(asset_field) or "").strip()
                if not asset_id:
                    continue
                slot_by_asset_id[asset_id] = {
                    "slotId": str(slot.get("id") or "").strip(),
                    "slotIndex": slot.get("index"),
                    "status": slot.get("status"),
                    "aiScore": slot.get("aiScore"),
                    "aiReason": slot.get("aiReason"),
                    "reviewDimensions": slot.get("reviewDimensions"),
                    "type": asset_type,
                }
    bound: list = []
    for asset in assets:
        if not isinstance(asset, dict):
            continue
        next_asset = dict(asset)
        slot = slot_by_asset_id.get(str(next_asset.get("id") or "").strip())
        if slot and str(next_asset.get("type") or "") == slot.get("type"):
            next_asset["slotId"] = next_asset.get("slotId") or slot.get("slotId")
            next_asset["slotIndex"] = next_asset.get("slotIndex") or slot.get("slotIndex")
            if next_asset.get("type") == "image" and str(slot.get("status") or "") in {"AI通过", "AI拒绝", "人工通过", "人工拒绝"}:
                next_asset["status"] = slot.get("status")
                next_asset["selected"] = str(slot.get("status")) in {"AI通过", "人工通过"}
                if slot.get("aiScore") is not None:
                    next_asset["aiScore"] = slot.get("aiScore")
                if slot.get("aiReason"):
                    next_asset["aiReason"] = slot.get("aiReason")
                if isinstance(slot.get("reviewDimensions"), dict):
                    next_asset["reviewDimensions"] = slot.get("reviewDimensions")
        bound.append(next_asset)
    return bound


def normalize_flow_fission_jobs_for_recovery(jobs: object, assets: object) -> list:
    if not isinstance(jobs, list):
        return []
    active_video_asset_ids = {
        str(asset.get("id") or "").strip()
        for asset in assets
        if isinstance(asset, dict)
        and str(asset.get("type") or "") == "video"
        and str(asset.get("id") or "").strip()
        and not asset.get("deletedAt")
    } if isinstance(assets, list) else set()
    now_ms = int(time.time() * 1000)
    normalized: list = []
    for job in jobs:
        if not isinstance(job, dict):
            continue
        next_job = dict(job)
        try:
            updated_at = int(next_job.get("updatedAt") or next_job.get("createdAt") or now_ms)
        except Exception:
            updated_at = now_ms
        stale = now_ms - updated_at > 15 * 60 * 1000
        raw_attempts = next_job.get("videoAttempts") if isinstance(next_job.get("videoAttempts"), list) else []
        running_slot_ids = {
            str(attempt.get("slotId") or "").strip()
            for attempt in raw_attempts
            if isinstance(attempt, dict)
            and str(attempt.get("status") or "") in {"pending", "submitting", "running"}
            and str(attempt.get("slotId") or "").strip()
        }
        stale_running_job = stale and str(next_job.get("status") or "") == "执行中" and not running_slot_ids
        changed = False
        next_slots: list = []
        raw_slots = next_job.get("promptSlots") if isinstance(next_job.get("promptSlots"), list) else []
        for slot in raw_slots:
            if not isinstance(slot, dict):
                continue
            next_slot = dict(slot)
            slot_id = str(next_slot.get("id") or "").strip()
            video_asset_id = str(next_slot.get("videoAssetId") or "").strip()
            if (
                stale
                and str(next_slot.get("status") or "") == "视频生成中"
                and slot_id not in running_slot_ids
                and (not video_asset_id or video_asset_id not in active_video_asset_ids)
            ):
                next_slot["status"] = "视频失败"
                next_slot["aiReason"] = str(next_slot.get("aiReason") or "上次视频生成中断或超时，已恢复为可续跑状态。")
                changed = True
            next_slots.append(next_slot)
        if changed:
            next_job["promptSlots"] = next_slots
            append_debug_log("client_state.recover.flow_fission_jobs.normalized", {"jobId": next_job.get("id"), "reason": "stale-video-running"})
        if stale_running_job:
            next_job["status"] = "待执行"
            logs = next_job.get("logs") if isinstance(next_job.get("logs"), list) else []
            recovery_log = "上次任务执行中断或超时，已恢复为可继续状态。"
            if not any(isinstance(line, str) and recovery_log in line for line in logs):
                next_job["logs"] = [f"{datetime.now().strftime('%Y/%m/%d %H:%M:%S')} {recovery_log}", *logs]
            append_debug_log("client_state.recover.flow_fission_jobs.normalized", {"jobId": next_job.get("id"), "reason": "stale-running-job"})
        normalized.append(next_job)
    return normalized


def build_recovered_client_state() -> dict:
    state = read_client_state()
    active_project_ids = active_product_project_ids_from_state(state)
    state_ingest_items = state.get("meiao-ingest-items") if isinstance(state.get("meiao-ingest-items"), list) else []
    saved_ingest_items = read_media_library_items()
    disk_ingest_items = recover_media_library_items_from_disk()
    ingest_items = merge_media_library_items(
        merge_media_library_items(state_ingest_items, saved_ingest_items),
        disk_ingest_items,
    )
    ingest_items = filter_ingest_items_for_active_projects(ingest_items, active_project_ids)
    if ingest_items != saved_ingest_items:
        write_media_library_items(ingest_items)
    valid_ingest_ids = {
        str(item.get("id") or "").strip()
        for item in ingest_items
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    valid_media_ids = {
        str(item.get("backendMediaId") or "").strip()
        for item in ingest_items
        if isinstance(item, dict) and str(item.get("backendMediaId") or "").strip()
    }
    valid_script_ids = {
        stable_script_id_from_ingest_id(str(item.get("id") or "").strip())
        for item in ingest_items
        if isinstance(item, dict) and str(item.get("id") or "").strip()
    }
    review_map = {
        str(item_id): value
        for item_id, value in dict(state.get("meiao-copy-clean-review") or {}).items()
        if str(item_id).strip() in valid_ingest_ids
    }
    queue = {
        str(item_id).strip()
        for item_id in (state.get("meiao-scene-split-queue") or [])
        if str(item_id).strip() in valid_ingest_ids
    }
    for item in ingest_items:
        if not isinstance(item, dict):
            continue
        item_id = str(item.get("id") or "").strip()
        if item_id and not review_map.get(item_id):
            review_map[item_id] = "keep_original"

    recovered_records, recovered_vectors = recover_scene_split_records_from_vectors(valid_media_ids)
    split_records = state.get("meiao-scene-split-records") if isinstance(state.get("meiao-scene-split-records"), dict) else {}
    split_records = filter_scene_split_records_for_active_media(split_records, valid_media_ids, valid_script_ids)
    hidden_split_records = [
        str(item).strip()
        for item in (state.get("meiao-scene-split-hidden-records") if isinstance(state.get("meiao-scene-split-hidden-records"), list) else [])
        if str(item or "").strip()
    ]
    vector_status = state.get("meiao-scene-vector-status") if isinstance(state.get("meiao-scene-vector-status"), dict) else {}
    split_records = {**recovered_records, **split_records}
    split_records = {**recover_scene_split_records_from_media_files(ingest_items, split_records), **split_records}
    vector_status = {
        key: value
        for key, value in {**recovered_vectors, **vector_status}.items()
        if key in split_records
    }

    media_to_ingest = {
        str(item.get("backendMediaId") or ""): str(item.get("id") or "")
        for item in ingest_items
        if isinstance(item, dict) and item.get("backendMediaId") and item.get("id")
    }
    copy_tasks = state.get("meiao-copy-clean-tasks") if isinstance(state.get("meiao-copy-clean-tasks"), dict) else {}
    if not copy_tasks:
        copy_store = read_copy_clean_store()
        for raw_task in copy_store.get("tasks", {}).values():
            if not isinstance(raw_task, dict):
                continue
            task = dict(raw_task)
            mapped_item_id = media_to_ingest.get(str(task.get("backendMediaId") or ""))
            item_id = mapped_item_id or str(task.get("itemId") or "").strip()
            if not item_id:
                continue
            task["itemId"] = item_id
            copy_tasks[item_id] = task
    copy_tasks = {
        str(item_id): task
        for item_id, task in copy_tasks.items()
        if str(item_id).strip() in valid_ingest_ids
    }
    copy_regions_raw = state.get("meiao-copy-clean-regions") if isinstance(state.get("meiao-copy-clean-regions"), dict) else {}
    copy_regions = {
        str(item_id): region
        for item_id, region in copy_regions_raw.items()
        if str(item_id).strip() in valid_ingest_ids
    }
    for task in copy_tasks.values():
        if not isinstance(task, dict):
            continue
        item_id = str(task.get("itemId") or "").strip()
        if item_id and task.get("status") == "success" and (task.get("resultLocalUrl") or task.get("resultUrl")):
            review_map[item_id] = "cleaned"
    for record in split_records.values():
        if not isinstance(record, dict):
            continue
        ingest_id = media_to_ingest.get(str(record.get("mediaId") or ""))
        if ingest_id:
            record["ingestId"] = ingest_id
            queue.add(ingest_id)

    batch_projects = normalize_batch_draft_projects([
        *read_batch_draft_projects(),
        *(state.get("meiao-batch-draft-projects") if isinstance(state.get("meiao-batch-draft-projects"), list) else []),
    ])
    if active_project_ids:
        batch_projects = [
            item for item in batch_projects
            if str(item.get("projectId") or "").strip() in active_project_ids
        ]
    if batch_projects:
        write_batch_draft_projects(batch_projects)

    draft_templates = merge_draft_templates(
        read_draft_templates(),
        state.get("meiao-draft-templates") if isinstance(state.get("meiao-draft-templates"), list) else [],
    )
    if draft_templates:
        write_draft_templates(draft_templates)

    fission_jobs = state.get("meiao-flow-fission-jobs") if isinstance(state.get("meiao-flow-fission-jobs"), list) else []
    fission_assets = state.get("meiao-flow-fission-assets") if isinstance(state.get("meiao-flow-fission-assets"), list) else []
    valid_fission_job_ids = {
        str(job.get("id") or "").strip()
        for job in fission_jobs
        if isinstance(job, dict) and str(job.get("id") or "").strip()
    }
    if valid_fission_job_ids:
        fission_assets = [
            asset for asset in fission_assets
            if not isinstance(asset, dict) or str(asset.get("jobId") or "").strip() in valid_fission_job_ids
        ]
    recovered_fission_assets = recover_flow_fission_assets_from_disk(fission_assets, valid_fission_job_ids)
    if recovered_fission_assets:
        fission_assets = merge_list_by_stable_id(recovered_fission_assets, fission_assets)
        append_debug_log("client_state.recover.flow_fission_assets", {"recovered": len(recovered_fission_assets), "total": len(fission_assets)})
    fission_assets = bind_flow_fission_assets_to_slots(fission_assets, fission_jobs)
    fission_jobs = normalize_flow_fission_jobs_for_recovery(fission_jobs, fission_assets)

    recovered = {
        "meiao-ingest-items": ingest_items,
        "meiao-product-projects": state.get("meiao-product-projects") if isinstance(state.get("meiao-product-projects"), list) else [],
        "meiao-copy-clean-review": review_map,
        "meiao-copy-clean-tasks": copy_tasks,
        "meiao-copy-clean-regions": copy_regions,
        "meiao-scene-split-records": split_records,
        "meiao-scene-split-hidden-records": hidden_split_records,
        "meiao-scene-vector-status": vector_status,
        "meiao-scene-split-queue": sorted(queue),
        "meiao-script-quality": {key: "已通过" for key in split_records.keys()},
        "meiao-output-tasks": filter_project_scoped_list(state.get("meiao-output-tasks"), active_project_ids),
        "meiao-output-records": filter_project_scoped_list(state.get("meiao-output-records"), active_project_ids),
        "meiao-unified-tasks": normalize_flow_fission_unified_tasks(state.get("meiao-unified-tasks"), fission_jobs),
        "meiao-unified-task-tombstones": state.get("meiao-unified-task-tombstones") if isinstance(state.get("meiao-unified-task-tombstones"), dict) else {},
        "meiao-ab-dedup-results": state.get("meiao-ab-dedup-results") if isinstance(state.get("meiao-ab-dedup-results"), list) else [],
        "meiao-storage-preferences": state.get("meiao-storage-preferences") if isinstance(state.get("meiao-storage-preferences"), dict) else {},
        "meiao-shot-usage": state.get("meiao-shot-usage") if isinstance(state.get("meiao-shot-usage"), dict) else {},
        "meiao-shot-reservations": state.get("meiao-shot-reservations") if isinstance(state.get("meiao-shot-reservations"), dict) else {},
        "meiao-draft-plans": filter_project_scoped_list(state.get("meiao-draft-plans"), active_project_ids),
        "meiao-draft-templates": draft_templates,
        "meiao-batch-draft-projects": batch_projects,
        "meiao-generated-voice-assets": state.get("meiao-generated-voice-assets") if isinstance(state.get("meiao-generated-voice-assets"), list) else [],
        "meiao-flow-accounts": sanitize_flow_accounts_for_client_state(state.get("meiao-flow-accounts")),
        "meiao-flow-nodes": state.get("meiao-flow-nodes") if isinstance(state.get("meiao-flow-nodes"), list) else [],
        "meiao-flow-fission-jobs": fission_jobs,
        "meiao-flow-fission-assets": fission_assets,
        "meiao-fission-done": state.get("meiao-fission-done") if isinstance(state.get("meiao-fission-done"), dict) else {},
        "meiao-script-renames": state.get("meiao-script-renames") if isinstance(state.get("meiao-script-renames"), dict) else {},
        "meiao-ai-output-workspaces": state.get("meiao-ai-output-workspaces") if isinstance(state.get("meiao-ai-output-workspaces"), dict) else {},
    }
    recovered = sanitize_flow_video_reference_wording(recovered)
    write_client_state({**state, **recovered})
    return recovered


def normalize_bgm_item(item: dict) -> dict | None:
    track_id = str(item.get("id") or "").strip()
    file_name = str(item.get("fileName") or "").strip()
    if not track_id or not file_name:
        return None
    target = BGM_ROOT / file_name
    return {
        "id": track_id,
        "name": str(item.get("name") or file_name).strip(),
        "category": str(item.get("category") or "").strip(),
        "fileName": file_name,
        "originalName": str(item.get("originalName") or file_name).strip(),
        "mimeType": str(item.get("mimeType") or mimetypes.guess_type(file_name)[0] or "audio/mpeg"),
        "size": target.stat().st_size if target.exists() else int(item.get("size") or 0),
        "url": f"/media/bgm-library/{quote(file_name)}",
        "createdAt": int(item.get("createdAt") or int(time.time() * 1000)),
        "updatedAt": int(item.get("updatedAt") or int(time.time() * 1000)),
    }


def utc_now_iso() -> str:
    return datetime.utcnow().replace(microsecond=0).isoformat() + "Z"


def parse_iso_time(value: object | None) -> datetime | None:
    if not value:
        return None
    text = str(value).strip()
    if not text:
        return None
    try:
        if text.endswith("Z"):
            text = text[:-1] + "+00:00"
        return datetime.fromisoformat(text).replace(tzinfo=None)
    except Exception:
        return None


def get_license_device() -> dict:
    LICENSE_AUTH_ROOT.mkdir(parents=True, exist_ok=True)
    data: dict = {}
    if LICENSE_DEVICE_FILE.exists():
        try:
            loaded = json.loads(LICENSE_DEVICE_FILE.read_text(encoding="utf-8"))
            if isinstance(loaded, dict):
                data = loaded
        except Exception:
            data = {}
    if data.get("salt") and data.get("deviceId") and data.get("deviceName"):
        return data
    if not data.get("salt"):
        data["salt"] = uuid.uuid4().hex
    machine_text = "|".join(
        [
            socket.gethostname(),
            os.environ.get("USERNAME") or os.environ.get("USER") or "",
            platform.platform(),
            platform.node(),
        ]
    )
    device_id = hashlib.sha256(f"{machine_text}|{data['salt']}".encode("utf-8", errors="ignore")).hexdigest()
    data.update(
        {
            "deviceId": device_id,
            "deviceName": f"{socket.gethostname()} · {platform.system()}",
            "updatedAt": utc_now_iso(),
        }
    )
    try:
        LICENSE_DEVICE_FILE.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass
    return data


def read_license_state() -> dict:
    if not LICENSE_FILE.exists():
        return {}
    try:
        data = json.loads(LICENSE_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def write_license_state(state: dict) -> None:
    with JSON_STORE_WRITE_LOCK:
        LICENSE_AUTH_ROOT.mkdir(parents=True, exist_ok=True)
        tmp_file = LICENSE_FILE.with_suffix(".tmp")
        tmp_file.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
        tmp_file.replace(LICENSE_FILE)


def clear_license_state() -> None:
    try:
        if LICENSE_FILE.exists():
            LICENSE_FILE.unlink()
    except Exception:
        pass


def read_rebind_usage_state() -> dict:
    if not LICENSE_REBIND_USAGE_FILE.exists():
        return {"accounts": {}}
    try:
        data = json.loads(LICENSE_REBIND_USAGE_FILE.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return {"accounts": {}}
        if not isinstance(data.get("accounts"), dict):
            data["accounts"] = {}
        return data
    except Exception:
        return {"accounts": {}}


def write_rebind_usage_state(state: dict) -> None:
    with JSON_STORE_WRITE_LOCK:
        LICENSE_AUTH_ROOT.mkdir(parents=True, exist_ok=True)
        tmp_file = LICENSE_REBIND_USAGE_FILE.with_suffix(".tmp")
        tmp_file.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
        tmp_file.replace(LICENSE_REBIND_USAGE_FILE)


def normalize_rebind_account(account: str) -> str:
    return re.sub(r"\s+", " ", account.strip().lower())


def get_current_month_key() -> str:
    return datetime.utcnow().strftime("%Y-%m")


def get_rebind_usage(account: str) -> dict:
    normalized = normalize_rebind_account(account)
    if not normalized:
        return {"used": 0, "limit": LICENSE_REBIND_LIMIT_PER_MONTH, "remaining": LICENSE_REBIND_LIMIT_PER_MONTH}
    state = read_rebind_usage_state()
    accounts = state.get("accounts") if isinstance(state.get("accounts"), dict) else {}
    account_usage = accounts.get(normalized) if isinstance(accounts, dict) else {}
    if not isinstance(account_usage, dict):
        account_usage = {}
    used = 0
    try:
        used = int(account_usage.get(get_current_month_key()) or 0)
    except Exception:
        used = 0
    used = max(0, used)
    return {
        "used": used,
        "limit": LICENSE_REBIND_LIMIT_PER_MONTH,
        "remaining": max(0, LICENSE_REBIND_LIMIT_PER_MONTH - used),
    }


def record_rebind_usage(account: str) -> dict:
    normalized = normalize_rebind_account(account)
    if not normalized:
        return get_rebind_usage(account)
    with JSON_STORE_WRITE_LOCK:
        state = read_rebind_usage_state()
        accounts = state.setdefault("accounts", {})
        if not isinstance(accounts, dict):
            accounts = {}
            state["accounts"] = accounts
        account_usage = accounts.setdefault(normalized, {})
        if not isinstance(account_usage, dict):
            account_usage = {}
            accounts[normalized] = account_usage
        month_key = get_current_month_key()
        try:
            used = max(0, int(account_usage.get(month_key) or 0))
        except Exception:
            used = 0
        if used >= LICENSE_REBIND_LIMIT_PER_MONTH:
            raise IngestError(f"本月换绑次数已达上限（{LICENSE_REBIND_LIMIT_PER_MONTH} 次）。", "REBIND_LIMIT_REACHED")
        account_usage[month_key] = used + 1
        state["updatedAt"] = utc_now_iso()
        tmp_file = LICENSE_REBIND_USAGE_FILE.with_suffix(".tmp")
        tmp_file.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
        tmp_file.replace(LICENSE_REBIND_USAGE_FILE)
        return {
            "used": account_usage[month_key],
            "limit": LICENSE_REBIND_LIMIT_PER_MONTH,
            "remaining": max(0, LICENSE_REBIND_LIMIT_PER_MONTH - account_usage[month_key]),
        }


def read_admin_session_state() -> dict:
    if not LICENSE_ADMIN_SESSION_FILE.exists():
        return {}
    try:
        data = json.loads(LICENSE_ADMIN_SESSION_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def write_admin_session_state(state: dict) -> None:
    with JSON_STORE_WRITE_LOCK:
        LICENSE_AUTH_ROOT.mkdir(parents=True, exist_ok=True)
        tmp_file = LICENSE_ADMIN_SESSION_FILE.with_suffix(".tmp")
        tmp_file.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
        tmp_file.replace(LICENSE_ADMIN_SESSION_FILE)


def clear_admin_session_state() -> None:
    try:
        if LICENSE_ADMIN_SESSION_FILE.exists():
            LICENSE_ADMIN_SESSION_FILE.unlink()
    except Exception:
        pass


def call_supabase_rpc(name: str, payload: dict, timeout: float = 30.0) -> dict:
    url = f"{SUPABASE_LICENSE_URL}/rest/v1/rpc/{name}"
    last_error: Exception | None = None
    for attempt in range(1, LICENSE_RPC_NETWORK_ATTEMPTS + 1):
        try:
            response = requests.post(
                url,
                headers={
                    "apikey": SUPABASE_LICENSE_ANON_KEY,
                    "Authorization": f"Bearer {SUPABASE_LICENSE_ANON_KEY}",
                    "Content-Type": "application/json",
                    "Accept": "application/json",
                },
                json=payload,
                timeout=timeout,
                **get_local_proxy_requests_kwargs(),
            )
            break
        except (requests.exceptions.SSLError, requests.exceptions.ConnectionError, requests.exceptions.Timeout) as exc:
            last_error = exc
            if attempt >= LICENSE_RPC_NETWORK_ATTEMPTS:
                raise IngestError(f"授权服务连接失败：{exc}", "LICENSE_NETWORK_ERROR") from exc
            time.sleep(LICENSE_RPC_RETRY_SLEEP_SECONDS * attempt)
        except Exception as exc:
            raise IngestError(f"授权服务连接失败：{exc}", "LICENSE_NETWORK_ERROR") from exc
    else:
        raise IngestError(f"授权服务连接失败：{last_error}", "LICENSE_NETWORK_ERROR")
    text = (response.text or "").strip()
    try:
        data = response.json() if text else {}
    except Exception:
        data = {"message": text}
    if not response.ok:
        message = data.get("message") if isinstance(data, dict) else ""
        raise IngestError(f"授权服务返回失败：{message or text or response.status_code}", "LICENSE_RPC_ERROR")
    return data if isinstance(data, dict) else {"data": data}


def build_admin_login_payload(account: str, admin_key: str, device: dict) -> dict:
    return {
        "p_account": account,
        "p_admin_key": admin_key,
        "p_device_id": device.get("deviceId", ""),
        "p_device_name": device.get("deviceName", ""),
    }


def admin_result_token(result: dict) -> str:
    return str(result.get("admin_token") or result.get("adminToken") or "").strip()


def login_admin_with_auto_rebind(account: str, admin_key: str, device: dict) -> dict:
    login_payload = build_admin_login_payload(account, admin_key, device)
    result = call_supabase_rpc("admin_login", login_payload)
    if admin_result_token(result):
        return result

    code = str(result.get("code") or "").strip()
    if code != "admin_device_mismatch":
        return result

    try:
        rebind_result = call_supabase_rpc("admin_rebind_device", login_payload)
    except IngestError as exc:
        raise IngestError(f"主管理密钥正确，但自动换绑失败：{exc}", "ADMIN_REBIND_FAILED") from exc

    if admin_result_token(rebind_result):
        rebind_result["rebound"] = True
        return rebind_result

    result_after_rebind = call_supabase_rpc("admin_login", login_payload)
    if admin_result_token(result_after_rebind):
        result_after_rebind["rebound"] = True
    return result_after_rebind


def normalize_license_payload(payload: dict, current: dict | None = None) -> dict:
    current = current or {}
    if isinstance(payload.get("data"), dict):
        payload = {**payload, **payload["data"]}
    license_data = payload.get("license") if isinstance(payload.get("license"), dict) else {}
    session_data = payload.get("session") if isinstance(payload.get("session"), dict) else {}
    token_data = payload.get("token") if isinstance(payload.get("token"), dict) else {}
    access_token = str(payload.get("access_token") or payload.get("accessToken") or session_data.get("access_token") or current.get("accessToken") or "").strip()
    access_token = access_token or str(token_data.get("access_token") or token_data.get("accessToken") or token_data.get("token") or "").strip()
    account = str(payload.get("account") or license_data.get("account") or payload.get("license_account") or current.get("account") or "").strip()
    status = str(payload.get("status") or license_data.get("status") or payload.get("license_status") or current.get("status") or "").strip()
    expires_at = str(payload.get("expires_at") or payload.get("expiresAt") or license_data.get("expires_at") or payload.get("license_expires_at") or current.get("expiresAt") or "").strip()
    offline_grace_hours = payload.get("offline_grace_hours")
    if offline_grace_hours is None:
        offline_grace_hours = payload.get("offlineGraceHours", license_data.get("offline_grace_hours", current.get("offlineGraceHours", 72)))
    try:
        offline_grace_hours = max(0, int(offline_grace_hours))
    except Exception:
        offline_grace_hours = 72
    device = get_license_device()
    now = utc_now_iso()
    return {
        "active": bool(payload.get("active") is True or status == "active"),
        "account": account,
        "status": status or ("active" if payload.get("active") else "inactive"),
        "accessToken": access_token,
        "expiresAt": expires_at,
        "offlineGraceHours": offline_grace_hours,
        "deviceId": device.get("deviceId", ""),
        "deviceName": device.get("deviceName", ""),
        "lastVerifiedAt": now,
        "updatedAt": now,
    }


def build_license_status_response(device: dict, state: dict) -> dict:
    last_verified = parse_iso_time(state.get("lastVerifiedAt"))
    expires_at = parse_iso_time(state.get("expiresAt"))
    now_dt = datetime.utcnow()
    offline_grace_hours = int(state.get("offlineGraceHours") or 72)
    offline_until = None
    offline_ok = False
    if last_verified:
        offline_until_dt = last_verified.timestamp() + offline_grace_hours * 3600
        offline_ok = time.time() <= offline_until_dt
        offline_until = datetime.utcfromtimestamp(offline_until_dt).replace(microsecond=0).isoformat() + "Z"
    not_expired = True if not expires_at else now_dt <= expires_at
    active = bool(state.get("active") and state.get("accessToken") and not_expired and offline_ok)
    return {
        "active": active,
        "account": state.get("account", ""),
        "status": "active" if active else (state.get("status") or "inactive"),
        "expiresAt": state.get("expiresAt", ""),
        "offlineGraceHours": offline_grace_hours,
        "offlineUntil": offline_until,
        "lastVerifiedAt": state.get("lastVerifiedAt", ""),
        "lastVerifyError": state.get("lastVerifyError", ""),
        "deviceId": device.get("deviceId", ""),
        "deviceName": device.get("deviceName", ""),
        "hasToken": bool(state.get("accessToken")),
        **{
            "rebindUsedThisMonth": get_rebind_usage(str(state.get("account", ""))).get("used", 0),
            "rebindLimitPerMonth": LICENSE_REBIND_LIMIT_PER_MONTH,
            "rebindRemainingThisMonth": get_rebind_usage(str(state.get("account", ""))).get("remaining", LICENSE_REBIND_LIMIT_PER_MONTH),
        },
    }


def refresh_license_state(token: str, device: dict, state: dict) -> None:
    try:
        verified = call_supabase_rpc("license_verify", {"p_access_token": token, "p_device_id": device.get("deviceId", "")}, timeout=5.0)
        next_state = normalize_license_payload(verified, state)
        next_state["lastVerifyAttemptTs"] = time.time()
        write_license_state(next_state)
    except Exception as exc:
        state["lastVerifyAttemptTs"] = time.time()
        state["lastVerifyError"] = str(exc)
        try:
            write_license_state(state)
        except Exception:
            pass


def refresh_license_state_with_deadline(token: str, device: dict, state: dict) -> None:
    done = threading.Event()

    def worker() -> None:
        try:
            refresh_license_state(token, device, state)
        finally:
            done.set()

    thread = threading.Thread(target=worker, daemon=True)
    thread.start()
    if done.wait(LICENSE_ONLINE_VERIFY_TIMEOUT_SECONDS):
        return
    state["lastVerifyAttemptTs"] = time.time()
    state["lastVerifyError"] = "授权在线校验超时，请稍后重试。"
    try:
        write_license_state(state)
    except Exception:
        pass


def online_verify_within_throttle(state: dict) -> bool:
    """最近一次在线校验成功且仍在节流窗口内 → 当天无需再次联网校验。

    依据 lastVerifiedAt（仅在成功校验/激活时更新；失败只更新 lastVerifyAttemptTs），
    因此“近期有过成功校验”即可在窗口内复用本地缓存，避免反复授权等待。
    """
    last_verified = parse_iso_time(state.get("lastVerifiedAt"))
    if not last_verified:
        return False
    age_seconds = (datetime.utcnow() - last_verified).total_seconds()
    return 0 <= age_seconds < LICENSE_VERIFY_THROTTLE_SECONDS


def get_license_status(force_online: bool = False, allow_throttle: bool = True) -> dict:
    device = get_license_device()
    state = read_license_state()
    token = str(state.get("accessToken") or "").strip()
    # 当天已成功校验则跳过联网：消除“反复授权、每次都要等”的体感。
    # allow_throttle=False 用于用户手动「立即在线校验」，此时必须真正联网、不复用缓存。
    if token and force_online and allow_throttle and online_verify_within_throttle(state):
        force_online = False
        # 节流命中说明近期校验成功，清掉可能残留的瞬时错误，避免界面误报。
        if state.get("lastVerifyError"):
            state = {**state, "lastVerifyError": ""}
    if token and force_online:
        refresh_license_state_with_deadline(token, device, state)
        state = read_license_state()
    return build_license_status_response(device, state)


def activate_license(account: str, license_key: str) -> dict:
    device = get_license_device()
    result = call_supabase_rpc(
        "license_activate",
        {
            "p_account": account,
            "p_license_key": license_key,
            "p_device_id": device.get("deviceId", ""),
            "p_device_name": device.get("deviceName", ""),
        },
        timeout=12.0,
    )
    state = normalize_license_payload(result)
    if not state.get("accessToken"):
        append_debug_log("license.activate.unexpected_payload", {"payload": result})
        raise IngestError("授权未生效，请检查账号、授权码和设备绑定。", "LICENSE_ACTIVATION_FAILED")
    state["lastVerifyAttemptTs"] = time.time()
    write_license_state(state)
    return get_license_status(force_online=False)


def license_required_for(path: str) -> bool:
    if not path.startswith("/api/"):
        return False
    if path in {"/api/health", "/api/system/environment"} or path.startswith("/api/license/"):
        return False
    return True


SCRIPT_TEMPLATE_MIME = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
SCRIPT_TEMPLATE_FILENAME = "脚本拆镜模板.xlsx"
SCRIPT_TEMPLATE_SOURCE_FILE = BASE_DIR / "templates" / SCRIPT_TEMPLATE_FILENAME
SCRIPT_TEMPLATE_MAIN_SHEET = "分镜脚本"
SCRIPT_TEMPLATE_GUIDE_SHEET = "填写说明"
SCRIPT_TEMPLATE_COLUMNS = ["分镜", "时间", "画面描述", "口播（语气）", "音效"]
SCRIPT_TEMPLATE_COLUMN_ALIASES = {
    "scene": ["分镜", "镜头", "镜头序号", "分镜序号", "镜头编号"],
    "time": ["时间", "时长", "时间范围", "时间段", "镜头时间"],
    "visual": ["画面描述", "画面", "画面内容", "场景描述", "画面说明"],
    "keywords": ["检索词", "关键词", "检索关键词", "向量检索词", "素材检索词"],
    "narration_tone": ["口播（语气）", "口播语气", "语气", "情绪和语气", "口播情绪"],
    "narration": ["口播内容", "口播正文", "台词内容", "旁白内容"],
    "narration_combined": ["口播", "台词", "旁白"],
    "sound": ["音效", "背景音", "声音", "音响"],
}


def clean_template_text(value: object | None) -> str:
    if value is None:
        return ""
    if isinstance(value, bool):
        return "TRUE" if value else "FALSE"
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        number = float(value)
        if number.is_integer():
            return str(int(number))
        return str(value)
    text = str(value).replace("\xa0", " ").replace("\r", "\n").strip()
    return re.sub(r"[ \t]+", " ", text)


def split_template_list(value: object | None) -> list[str]:
    text = clean_template_text(value)
    if not text:
        return []
    return [item.strip() for item in re.split(r"[，,、;；/|\n]+", text) if item.strip()]


def is_placeholder_row(values: list[str]) -> bool:
    if not values:
        return True
    joined = " ".join(values)
    if "示例" in joined:
        return True
    meaningful = [value for value in values if value and "x秒" not in value and value not in {"-", "—"}]
    if len(meaningful) <= 2:
        return True
    return False


def looks_like_scene_label(value: str) -> bool:
    text = clean_template_text(value)
    if not text or "示例" in text or "说明" in text or "填写" in text:
        return False
    return bool(re.match(r"^(?:分镜|镜头)[一二三四五六七八九十百千万\dA-Za-z]+$", text))


def strip_wrapping_quotes(value: str) -> str:
    text = clean_template_text(value)
    if len(text) >= 2 and ((text[0], text[-1]) in {("“", "”"), ("\"", "\""), ("‘", "’"), ("'", "'"), ("「", "」"), ("『", "』")}):
        return text[1:-1].strip()
    return text


def parse_template_narration(tone_value: object | None, narration_value: object | None) -> tuple[str, str]:
    tone = clean_template_text(tone_value)
    narration = clean_template_text(narration_value)
    if tone and narration:
        return tone, strip_wrapping_quotes(narration)

    candidate = narration or tone
    if not candidate:
        return "", ""

    match = re.match(
        r"^\s*(?:[（(【\[](?P<tone>[^）)】\]]+)[）)】\]]\s*)?(?:[：:]\s*)?[“\"『「]?(?P<body>.*?)[”\"』」]?\s*$",
        candidate,
    )
    if match:
        parsed_tone = clean_template_text(match.group("tone") or "")
        parsed_body = strip_wrapping_quotes(match.group("body") or "")
        if parsed_tone or parsed_body != candidate:
            return parsed_tone, parsed_body

    return tone, strip_wrapping_quotes(candidate)


def build_script_template_workbook() -> Workbook:
    workbook = Workbook()
    sheet = workbook.active
    sheet.title = SCRIPT_TEMPLATE_MAIN_SHEET
    sheet.freeze_panes = "A4"
    sheet.sheet_view.showGridLines = True

    title_fill = PatternFill("solid", fgColor="F4F7FF")
    header_fill = PatternFill("solid", fgColor="111827")
    helper_fill = PatternFill("solid", fgColor="F8FAFC")
    title_font = Font(name="Microsoft YaHei", size=14, bold=True, color="1F2937")
    header_font = Font(name="Microsoft YaHei", size=11, bold=True, color="FFFFFF")
    body_font = Font(name="Microsoft YaHei", size=10, color="1F2937")
    helper_font = Font(name="Microsoft YaHei", size=10, color="4B5563")

    sheet.append(SCRIPT_TEMPLATE_COLUMNS)
    for cell in sheet[1]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)

    guidance_rows = [
        ["分镜序号按分镜一、分镜二填写", "格式固定为 00:00-00:02（2秒）", "只写看得见的画面内容，包含场景、主体、动作、镜头，不写情绪", "先写语气，再写口播内容；语气放在括号里", "只写需要的音效关键词，多个用中文逗号隔开"],
        ["示例：分镜一", "00:00-00:02（2秒）", "客厅地面，扫地机低机位推进，正面展示吸尘清理。", "（干脆直接）：“一开机，灰尘直接带走。”", "启动音，吸尘音"],
        ["分镜一", "00:00-00:00（x秒）", "", "", ""],
        ["分镜二", "00:00-00:00（x秒）", "", "", ""],
        ["分镜三", "00:00-00:00（x秒）", "", "", ""],
    ]
    for row in guidance_rows:
        sheet.append(row)
    while sheet.max_row < 16:
        sheet.append(["", "", "", "", ""])
    for row in sheet.iter_rows(min_row=2, max_row=sheet.max_row):
        for cell in row:
            cell.font = body_font
            cell.fill = helper_fill
            cell.alignment = Alignment(vertical="top", wrap_text=True)
    for cell in sheet[1]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)

    widths = [18, 20, 46, 28, 24]
    for index, width in enumerate(widths, start=1):
        sheet.column_dimensions[chr(64 + index)].width = width
    return workbook


def find_script_table_rows(workbook: Workbook) -> tuple[str, int, list[dict]]:
    for sheet in workbook.worksheets:
        rows = list(sheet.iter_rows(values_only=True))
        if not rows:
            continue

        for row_index, row in enumerate(rows):
            cells = [clean_template_text(cell) for cell in row]
            if not any(cells):
                continue

            header_map: dict[str, int] = {}
            for column_index, cell in enumerate(cells):
                if not cell:
                    continue
                for field_name, aliases in SCRIPT_TEMPLATE_COLUMN_ALIASES.items():
                    if field_name in header_map:
                        continue
                    if any(cell == alias or alias in cell for alias in aliases):
                        header_map[field_name] = column_index
                        break

            required = {"scene", "time", "visual"}
            if not required.issubset(header_map):
                continue

            results: list[dict] = []
            for data_row in rows[row_index + 1 :]:
                values = [clean_template_text(cell) for cell in data_row]
                if not any(values) or is_placeholder_row(values):
                    continue
                order_index = len(results) + 1

                def read(field: str) -> str:
                    column_index = header_map.get(field)
                    if column_index is None or column_index >= len(values):
                        return ""
                    return values[column_index]

                scene_label = read("scene") or f"分镜{order_index}"
                time_range_text = read("time")
                visual_description = read("visual")
                retrieval_keywords = split_template_list(read("keywords"))
                narration_tone, narration = parse_template_narration(read("narration_tone") or read("narration_combined"), read("narration"))
                if not narration and not read("narration") and read("narration_combined"):
                    narration_tone, narration = parse_template_narration("", read("narration_combined"))
                sound_effects = split_template_list(read("sound"))

                if not looks_like_scene_label(scene_label):
                    continue
                if not any([visual_description, retrieval_keywords, narration_tone, narration, sound_effects]):
                    continue

                results.append(
                    {
                        "sceneLabel": scene_label,
                        "timeRangeText": time_range_text,
                        "visualDescription": visual_description,
                        "retrievalKeywords": retrieval_keywords,
                        "narrationTone": narration_tone,
                        "narration": narration,
                        "soundEffects": sound_effects,
                    }
                )

            if results:
                return sheet.title, row_index + 1, results

    return "", 0, []


