def deep_merge_dict(base: dict, override: dict) -> dict:
    result = copy.deepcopy(base)
    for key, value in (override or {}).items():
        if isinstance(value, dict) and isinstance(result.get(key), dict):
            result[key] = deep_merge_dict(result[key], value)
        else:
            result[key] = value
    return result


def normalize_global_settings(raw: object | None = None) -> dict:
    source = raw if isinstance(raw, dict) else {}
    settings = deep_merge_dict(GLOBAL_SETTINGS_DEFAULTS, source)
    account = settings["account"]
    account["displayName"] = str(account.get("displayName") or "本机用户").strip()
    account["email"] = str(account.get("email") or "").strip()
    account["phone"] = str(account.get("phone") or "").strip()
    account["workspaceName"] = str(account.get("workspaceName") or "MEIAO 本地工作台").strip()
    account["twoFactorEnabled"] = bool(account.get("twoFactorEnabled"))
    try:
        account["autoLockMinutes"] = max(0, int(account.get("autoLockMinutes") or 0))
    except Exception:
        account["autoLockMinutes"] = 30

    team = settings["team"]
    if not isinstance(team.get("roles"), list) or not team["roles"]:
        team["roles"] = copy.deepcopy(GLOBAL_SETTINGS_DEFAULTS["team"]["roles"])
    team["roles"] = [str(item).strip() for item in team["roles"] if str(item).strip()]
    members = team.get("members") if isinstance(team.get("members"), list) else []
    team["members"] = [
        {
            "id": str(item.get("id") or uuid.uuid4().hex[:10]),
            "name": str(item.get("name") or "未命名成员").strip(),
            "email": str(item.get("email") or "").strip(),
            "role": str(item.get("role") or team["roles"][0]).strip(),
            "department": str(item.get("department") or "").strip(),
            "status": str(item.get("status") or "active").strip(),
        }
        for item in members
        if isinstance(item, dict)
    ] or copy.deepcopy(GLOBAL_SETTINGS_DEFAULTS["team"]["members"])

    notifications = settings["notifications"]
    channels = notifications.get("channels") if isinstance(notifications.get("channels"), dict) else {}
    notifications["channels"] = {
        "inApp": bool(channels.get("inApp", True)),
        "desktop": bool(channels.get("desktop", False)),
        "email": False,
        "webhook": False,
    }
    rules = notifications.get("rules") if isinstance(notifications.get("rules"), list) else []
    notifications["rules"] = [
        {
            "id": str(item.get("id") or uuid.uuid4().hex[:8]),
            "name": str(item.get("name") or "通知规则").strip(),
            "enabled": bool(item.get("enabled", True)),
            "channels": ["desktop"],
        }
        for item in rules
        if isinstance(item, dict) and str(item.get("id") or "").strip() != "team_activity"
    ] or copy.deepcopy(GLOBAL_SETTINGS_DEFAULTS["notifications"]["rules"])
    notifications["email"] = str(notifications.get("email") or "").strip()
    notifications["webhookUrl"] = str(notifications.get("webhookUrl") or "").strip()

    backup = settings["backup"]
    backup["enabled"] = bool(backup.get("enabled"))
    backup["includeMedia"] = bool(backup.get("includeMedia"))
    backup["includeLogs"] = bool(backup.get("includeLogs", True))
    try:
        backup["retentionDays"] = max(1, int(backup.get("retentionDays") or 30))
    except Exception:
        backup["retentionDays"] = 30
    backup["records"] = [item for item in backup.get("records", []) if isinstance(item, dict)][-50:]
    integrations = settings["integrations"]
    if isinstance(integrations, dict):
        integrations.pop("cloudBackupEnabled", None)

    return settings


def file_count_and_size(root: Path) -> dict:
    total = 0
    count = 0
    if root.exists():
        for path in root.rglob("*"):
            try:
                if path.is_file():
                    count += 1
                    total += path.stat().st_size
            except Exception:
                continue
    return {"bytes": total, "files": count}


