def get_ark_api_key(config: dict | None = None) -> str:
    root = config if isinstance(config, dict) else read_local_config()
    credentials = root.get("credentials", {}) if isinstance(root.get("credentials"), dict) else {}
    ark = credentials.get(DEFAULT_ARK_CREDENTIAL_ID, {}) if isinstance(credentials.get(DEFAULT_ARK_CREDENTIAL_ID), dict) else {}
    key = str(ark.get("api_key") or "").strip()
    if key:
        return key
    ark_config = root.get("ark", {}) if isinstance(root.get("ark"), dict) else {}
    key = str(ark_config.get("api_key") or "").strip()
    if key:
        return key
    return str(os.environ.get("ARK_API_KEY") or "").strip()


