        ws = WebSocketConnection(target["webSocketDebuggerUrl"])
        events: list[dict] = []
        try:
            message_id = 1
            for method in ("Page.enable", "Runtime.enable", "Log.enable", "Network.enable"):
                message_id, _ = cdp_call(ws, message_id, method, timeout_seconds=2)
            message_id, _ = cdp_call(ws, message_id, "Page.bringToFront", timeout_seconds=2)
            wanted = {
                "Runtime.exceptionThrown",
                "Log.entryAdded",
                "Network.requestWillBeSent",
                "Network.responseReceived",
                "Network.loadingFailed",
            }
            message_id, click_message = cdp_call(
                ws,
                message_id,
                "Runtime.evaluate",
                {
                    "expression": click_expression,
                    "returnByValue": True,
                    "awaitPromise": True,
                    "userGesture": True,
                },
                timeout_seconds=3,
            )
            deadline = time.time() + 2.5
            while time.time() < deadline:
                message = ws.recv_json()
                if message and message.get("method") in wanted:
                    events.append(message)
        finally:
            ws.close()
        click_value = ((((click_message or {}).get("result") or {}).get("result") or {}).get("value"))
        try:
            data = json.loads(click_value) if isinstance(click_value, str) else {}
        except Exception:
            data = {}
        generation_requests: list[str] = []
        generation_request_payloads: list[dict] = []
        generation_responses: list[dict] = []
        loading_failures: list[dict] = []
        for event in events:
            method = str(event.get("method") or "")
            params = event.get("params") if isinstance(event.get("params"), dict) else {}
            if method == "Network.requestWillBeSent":
                request = params.get("request") if isinstance(params.get("request"), dict) else {}
                url = str(request.get("url") or "")
                if re.search(r"flowMedia:batchGenerate|generate(?:Images|Video|Videos)", url, re.I):
                    generation_requests.append(url[:500])
                    post_data = str(request.get("postData") or "")
                    safe_post_data = re.sub(r'("token"\s*:\s*")[^"]+', r'\1[redacted]', post_data)
                    generation_request_payloads.append({
                        "url": url[:500],
                        "method": request.get("method"),
                        "postDataLength": len(post_data),
                        "postDataPreview": safe_post_data[:1200],
                        "hasPromptText": flow_post_data_has_prompt(expected_prompt, post_data),
                        "hasMediaNameToken": bool(re.search(r"mediaName|mediaId|asset|reference|image", post_data, re.I)),
                    })
            elif method == "Network.responseReceived":
                response = params.get("response") if isinstance(params.get("response"), dict) else {}
                url = str(response.get("url") or "")
                if re.search(r"flowMedia:batchGenerate|generate(?:Images|Video|Videos)", url, re.I):
                    generation_responses.append({"url": url[:500], "status": response.get("status")})
            elif method == "Network.loadingFailed":
                loading_failures.append({
                    "requestId": params.get("requestId"),
                    "errorText": params.get("errorText"),
                    "canceled": params.get("canceled"),
                })
        if isinstance(data, dict):
            data["generationRequestSeen"] = bool(generation_requests)
            data["generationRequests"] = generation_requests[:4]
            data["generationRequestPayloads"] = generation_request_payloads[:2]
            data["generationResponses"] = generation_responses[:4]
            data["loadingFailures"] = loading_failures[:6]
            data["eventSummaries"] = cdp_event_summaries(events)[:8]
        return data if isinstance(data, dict) else {"ok": False, "action": "normal-submit-user-gesture:invalid-result"}

