def extract_kie_result_audio_url(task_data: dict) -> str:
    result_json = task_data.get("resultJson")
    result = {}
    if isinstance(result_json, str) and result_json.strip():
        try:
            parsed = json.loads(result_json)
            if isinstance(parsed, dict):
                result = parsed
            elif isinstance(parsed, list):
                result = {"resultUrls": parsed}
        except Exception:
            result = {}
    elif isinstance(result_json, dict):
        result = result_json
    elif isinstance(result_json, list):
        result = {"resultUrls": result_json}
    else:
        result = task_data
    for key in ("audioUrl", "audio_url", "resultUrl", "result_url", "url", "fileUrl", "file_url", "downloadUrl", "download_url"):
        value = str(result.get(key) or "").strip()
        if value:
            return value
    for list_key in ("resultUrls", "result_urls", "audioUrls", "audio_urls", "urls", "files"):
        result_urls = result.get(list_key)
        if isinstance(result_urls, list):
            for item in result_urls:
                if isinstance(item, dict):
                    value = extract_kie_result_audio_url(item)
                else:
                    value = str(item or "").strip()
                if value:
                    return value
    for key in ("response", "data"):
        nested = result.get(key)
        if isinstance(nested, dict):
            value = extract_kie_result_audio_url(nested)
            if value:
                return value
        if isinstance(nested, list):
            for item in nested:
                if isinstance(item, dict):
                    value = extract_kie_result_audio_url(item)
                else:
                    value = str(item or "").strip()
                if value:
                    return value
    return ""


def normalize_kie_task_state(state: str) -> str:
    value = str(state or "").strip().lower()
    if value == "success":
        return "success"
    if value in {"fail", "failed", "error"}:
        return "failed"
    if value in {"waiting", "queuing", "generating", "running", "processing"}:
        return "processing"
    return "submitted"
def get_public_base_url() -> str:
    configured = str(os.environ.get("MEIAO_PUBLIC_BASE_URL") or os.environ.get("MEIAO_RUNTIME_URL") or "").strip().rstrip("/")
    if configured:
        return configured
    return f"http://{HOST}:{PORT}"


def get_public_media_url(media_id: str, filename: str) -> str:
    return f"{get_public_base_url()}/media/{quote(media_id, safe='')}/{quote(filename, safe='')}"


def resolve_ab_source_path(shot: dict) -> Path | None:
    for key in ("url", "sourceUrl", "remoteVideoUrl"):
        value = str(shot.get(key) or "").strip()
        if not value:
            continue
        media_path = media_url_to_file_path(value)
        if media_path:
            return media_path
        parsed = urlparse(value)
        if parsed.scheme in {"", "file"}:
            candidate_text = unquote(parsed.path if parsed.scheme else value).strip()
            if os.name == "nt" and re.match(r"^/[A-Za-z]:/", candidate_text):
                candidate_text = candidate_text[1:]
            candidate = Path(candidate_text)
            if candidate.exists() and candidate.is_file():
                return candidate
    return None


def run_ab_frame_dedup(source_path: Path, output_dir: Path, output_name: str, intensity: float) -> dict:
    if not FFMPEG_EXE.exists():
        raise IngestError("缺少 ffmpeg，无法生成 AB 帧视频。")
    if not source_path.exists() or not source_path.is_file():
        raise IngestError("源视频不存在，无法处理。")

    source_fps = probe_video_fps(source_path) or 30.0
    output_fps = max(24.0, min(120.0, source_fps * 2.0))
    source_resolution = probe_video_resolution(source_path)
    source_duration = probe_video_duration(source_path) or 0
    safe_intensity = max(0.2, min(1.0, float(intensity or 0.55)))
    brightness = 0.006 + safe_intensity * 0.014
    contrast = 1.006 + safe_intensity * 0.026
    saturation = 1.006 + safe_intensity * 0.028
    noise = round(0.8 + safe_intensity * 2.7, 2)
    sharpen = round(0.12 + safe_intensity * 0.32, 3)

    output_dir.mkdir(parents=True, exist_ok=True)
    output_path = output_dir / output_name
    filter_graph = (
        "[0:v]"
        "scale=720:1280:force_original_aspect_ratio=decrease,"
        "pad=720:1280:(ow-iw)/2:(oh-ih)/2,"
        "setsar=1,split=2[a][b];"
        f"[b]eq=brightness={brightness:.4f}:contrast={contrast:.4f}:saturation={saturation:.4f},"
        f"noise=alls={noise}:allf=t+u,"
        f"unsharp=3:3:{sharpen}:3:3:0.0[b2];"
        f"[a][b2]interleave,setpts=N/({output_fps:.6f}*TB),format=yuv420p[v]"
    )
    command = [
        str(FFMPEG_EXE),
        "-y",
        "-hide_banner",
        "-i",
        str(source_path),
        "-filter_complex",
        filter_graph,
        "-map",
        "[v]",
        "-map",
        "0:a?",
        "-c:v",
        "libx264",
        "-preset",
        "veryfast",
        "-crf",
        "20",
        "-r",
        f"{output_fps:.6f}",
        "-c:a",
        "aac",
        "-b:a",
        "128k",
        "-movflags",
        "+faststart",
        "-shortest",
        str(output_path),
    ]
    started = time.time()
    completed = subprocess.run(command, capture_output=True, text=True, encoding="utf-8", errors="ignore", timeout=900)
    elapsed_ms = int((time.time() - started) * 1000)
    if completed.returncode != 0 or not output_path.exists() or output_path.stat().st_size <= 0:
        append_debug_log(
            "ab_dedup.ffmpeg_failed",
            {
                "sourcePath": str(source_path),
                "outputPath": str(output_path),
                "returncode": completed.returncode,
                "stderr": (completed.stderr or "")[-1600:],
            },
        )
        raise IngestError("AB帧去重生成失败，请查看运行日志。")

    output_resolution = probe_video_resolution(output_path) or (720, 1280)
    output_duration = probe_video_duration(output_path) or source_duration
    return {
        "path": output_path,
        "sourceDuration": round(source_duration, 3),
        "outputDuration": round(output_duration, 3),
        "sourceFps": round(source_fps, 3),
        "outputFps": round(output_fps, 3),
        "sourceWidth": source_resolution[0] if source_resolution else None,
        "sourceHeight": source_resolution[1] if source_resolution else None,
        "width": output_resolution[0],
        "height": output_resolution[1],
        "size": output_path.stat().st_size,
        "elapsedMs": elapsed_ms,
        "command": command,
    }


def run_ab_dedup_batch(shots: list[dict], options: dict | None = None) -> dict:
    if not isinstance(shots, list) or not shots:
        raise IngestError("请选择要处理的分镜素材。")
    opts = options or {}
    repeat_count = max(1, min(12, int(opts.get("repeatCount") or 1)))
    intensity = max(0.2, min(1.0, float(opts.get("intensity") or 0.55)))
    task_id = f"AB-{datetime.now().strftime('%Y%m%d%H%M%S')}-{uuid.uuid4().hex[:6]}"
    media_id = sanitize_filename(f"ab-dedup-{task_id}")
    output_dir = MEDIA_ROOT / media_id
    results: list[dict] = []
    failed: list[dict] = []
    created_at = int(time.time() * 1000)

    for shot in shots:
        if not isinstance(shot, dict):
            continue
        shot_id = sanitize_filename(str(shot.get("shotId") or shot.get("id") or "shot"))
        source_path = resolve_ab_source_path(shot)
        if not source_path:
            failed.append({"shotId": shot_id, "error": "没有找到这个分镜对应的本地视频文件。"})
            continue
        for repeat_index in range(repeat_count):
            output_name = sanitize_filename(f"{shot_id}_AB帧去重_{repeat_index + 1}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.mp4")
            try:
                processed = run_ab_frame_dedup(source_path, output_dir, output_name, intensity)
                output_path = processed["path"]
                poster_path = generate_poster(output_path, output_dir)
                result = {
                    "id": f"{task_id}-{shot_id}-{repeat_index + 1}",
                    "sourceShotId": shot_id,
                    "name": output_path.stem,
                    "url": get_public_media_url(media_id, output_path.name),
                    "posterUrl": get_public_media_url(media_id, poster_path.name) if poster_path else "",
                    "localMediaId": media_id,
                    "fileName": output_path.name,
                    "sourceDuration": processed["sourceDuration"],
                    "outputDuration": processed["outputDuration"],
                    "sourceFps": processed["sourceFps"],
                    "outputFps": processed["outputFps"],
                    "width": processed["width"],
                    "height": processed["height"],
                    "size": processed["size"],
                    "createdAt": created_at,
                }
                results.append(result)
                append_debug_log(
                    "ab_dedup.output",
                    {
                        "taskId": task_id,
                        "shotId": shot_id,
                        "sourcePath": str(source_path),
                        "outputPath": str(output_path),
                        "outputFps": processed["outputFps"],
                        "elapsedMs": processed["elapsedMs"],
                    },
                )
            except Exception as exc:
                failed.append({"shotId": shot_id, "error": str(exc)})

    requested = len(shots) * repeat_count
    return {
        "ok": len(results) > 0 and not failed,
        "taskId": task_id,
        "requested": requested,
        "completed": len(results),
        "failed": failed,
        "results": results,
        "message": f"AB帧去重完成 {len(results)}/{requested} 条。",
    }


def resolve_local_video_path(value: str | None) -> Path | None:
    text = str(value or "").strip().strip('"')
    if not text:
        return None
    media_path = media_url_to_file_path(text)
    if media_path:
        return media_path
    parsed = urlparse(text)
    candidate_text = text
    if parsed.scheme == "file":
        candidate_text = unquote(parsed.path)
    elif parsed.scheme in {"http", "https"}:
        return None
    if os.name == "nt" and re.match(r"^/[A-Za-z]:/", candidate_text):
        candidate_text = candidate_text[1:]
    candidate = Path(candidate_text).expanduser()
    if candidate.exists() and candidate.is_file():
        return candidate
    return None


def probe_has_audio(video_path: Path) -> bool:
    ffprobe = FFMPEG_DIR / "ffprobe.exe"
    if not ffprobe.exists():
        return True
    command = [
        str(ffprobe),
        "-v",
        "error",
        "-select_streams",
        "a:0",
        "-show_entries",
        "stream=index",
        "-of",
        "csv=p=0",
        str(video_path),
    ]
    completed = subprocess.run(command, capture_output=True, text=True, timeout=15)
    return completed.returncode == 0 and bool((completed.stdout or "").strip())



def build_download_options(output_dir: Path, browser: str | None = None, profile: Path | None = None) -> dict:
    options = {
        "quiet": True,
        "no_warnings": True,
        "noplaylist": False,
        "ignoreerrors": False,
        "windowsfilenames": True,
        "restrictfilenames": False,
        "outtmpl": {
            "default": str(output_dir / "%(title).120B [%(id)s].%(ext)s"),
            "thumbnail": str(output_dir / "%(title).120B [%(id)s].%(ext)s"),
        },
        "paths": {"home": str(output_dir)},
        "merge_output_format": "mp4",
        "format": "bv*+ba/b/best",
        "ffmpeg_location": str(FFMPEG_DIR),
        "writethumbnail": False,
    }
    if browser and profile:
        options["cookiesfrombrowser"] = (browser, str(profile))
    elif browser:
        options["cookiesfrombrowser"] = (browser,)
    return options


def is_login_required_error(error: Exception) -> bool:
    text = str(error).lower()
    markers = [
        "fresh cookies",
        "cookies are needed",
        "cookie",
        "login",
        "sign in",
        "not necessarily logged in",
        "failed to decrypt with dpapi",
        "dpapi",
        "需要登录",
        "请登录",
    ]
    return any(marker in text for marker in markers)


def make_login_message(platform_key: str | None) -> str:
    platform_name = {
        "douyin": "抖音",
        "xiaohongshu": "小红书",
        "kuaishou": "快手",
        "tiktok": "TikTok",
        "youtube": "YouTube",
        "bilibili": "Bilibili",
    }.get(platform_key or "", "当前平台")
    return f"{platform_name}需要登录态才能下载。请在登录窗口完成登录或验证后，回到这里重试。"


def extract_info_with_login_retry(target_url: str, output_dir: Path, download: bool) -> dict:
    platform_key = detect_platform_key(target_url)
    attempts: list[tuple[str | None, Path | None]] = [(None, None)]
    if platform_key in {"douyin", "xiaohongshu", "kuaishou", "tiktok", "youtube", "bilibili"}:
        auth_profile_dir = get_auth_cookie_profile_dir(platform_key)
        attempts.extend([("edge", auth_profile_dir), ("chrome", auth_profile_dir), ("edge", None), ("chrome", None)])

    append_debug_log(
        "download.extract.start",
        {
            "url": target_url,
            "platform": platform_key,
            "download": download,
            "attempts": [{"browser": browser, "profile": str(profile) if profile else None} for browser, profile in attempts],
        },
    )
    last_error: Exception | None = None
    for browser, profile in attempts:
        try:
            append_debug_log(
                "download.extract.attempt",
                {"url": target_url, "platform": platform_key, "download": download, "browser": browser, "profile": str(profile) if profile else None},
            )
            options = build_download_options(output_dir, browser, profile)
            with YoutubeDL(options) as ydl:
                info = ydl.extract_info(target_url, download=download)
                append_debug_log(
                    "download.extract.success",
                    {
                        "url": target_url,
                        "platform": platform_key,
                        "download": download,
                        "browser": browser,
                        "profile": str(profile) if profile else None,
                        "extractor": info.get("extractor") if isinstance(info, dict) else None,
                        "title": info.get("title") if isinstance(info, dict) else None,
                    },
                )
                return info
        except Exception as exc:
            last_error = exc
            append_debug_log(
                "download.extract.error",
                {
                    "url": target_url,
                    "platform": platform_key,
                    "download": download,
                    "browser": browser,
                    "profile": str(profile) if profile else None,
                    "errorType": type(exc).__name__,
                    "error": str(exc),
                    "loginRequired": is_login_required_error(exc),
                },
            )
            if not is_login_required_error(exc):
                break

    if last_error and is_login_required_error(last_error):
        if platform_key == "douyin":
            browser_result = resolve_douyin_with_browser(target_url)
            browser_info = browser_result_to_info(target_url, output_dir, download, browser_result) if browser_result else None
            if browser_info:
                return browser_info
            if browser_result and browser_result.get("verificationRequired"):
                raise IngestError("抖音要求完成验证码或短信验证。请在打开的抖音窗口完成验证后再重试。", "LOGIN_REQUIRED", "LOGIN_AND_RETRY") from last_error
        append_debug_log("download.extract.login_required", {"url": target_url, "platform": platform_key, "error": str(last_error)})
        raise IngestError(make_login_message(platform_key), "LOGIN_REQUIRED", "LOGIN_AND_RETRY") from last_error
    if last_error:
        append_debug_log("download.extract.failed", {"url": target_url, "platform": platform_key, "error": str(last_error)})
        raise last_error
    raise IngestError("下载失败，未返回有效信息。")


def resolve_downloaded_file(info: dict) -> Path | None:
    requested = info.get("requested_downloads")
    if isinstance(requested, list):
        for item in requested:
            if isinstance(item, dict):
                filepath = item.get("filepath")
                if filepath:
                    path = Path(filepath)
                    if path.exists():
                        return path
    for key in ("filepath", "_filename"):
        value = info.get(key)
        if value:
            path = Path(value)
            if path.exists():
                return path
    return None


def generate_poster(video_path: Path, output_dir: Path) -> Path | None:
    if not FFMPEG_EXE.exists():
        return None

    poster_path = output_dir / f"{video_path.stem}.jpg"
    duration = probe_video_duration(video_path) or 0
    target_offset = min(1.0, max(0.0, duration * 0.15))
    attempts = [
        [
            str(FFMPEG_EXE),
            "-y",
            "-ss",
            f"{target_offset:.3f}",
            "-i",
            str(video_path),
            "-frames:v",
            "1",
            str(poster_path),
        ],
        [
            str(FFMPEG_EXE),
            "-y",
            "-i",
            str(video_path),
            "-vf",
            "thumbnail,scale='min(1280,iw)':-1",
            "-frames:v",
            "1",
            str(poster_path),
        ],
    ]
    for command in attempts:
        completed = subprocess.run(command, capture_output=True, text=True, encoding="utf-8", errors="ignore")
        if completed.returncode == 0 and poster_path.exists() and poster_path.stat().st_size > 0:
            return poster_path
        append_debug_log(
            "poster.generate_failed",
            {
                "videoPath": str(video_path),
                "posterPath": str(poster_path),
                "command": command,
                "returncode": completed.returncode,
                "stderr": completed.stderr[-800:] if completed.stderr else "",
            },
        )
    return None


def detect_scene_boundaries(video_path: Path, threshold: float) -> list[float]:
    if not FFMPEG_EXE.exists():
        raise IngestError("缺少 ffmpeg，无法执行场景检测。")

    thresholds = [threshold, min(0.6, threshold * 0.8), 0.18, 0.12, 0.08]
    for scene_threshold in dict.fromkeys(round(value, 3) for value in thresholds if value >= 0.08):
        command = [
            str(FFMPEG_EXE),
            "-hide_banner",
            "-i",
            str(video_path),
            "-vf",
            f"select=gt(scene\\,{scene_threshold:.3f}),metadata=print",
            "-vsync",
            "vfr",
            "-f",
            "null",
            "NUL",
        ]
        completed = subprocess.run(command, capture_output=True, text=True, encoding="utf-8", errors="ignore")
        if completed.returncode != 0:
            append_debug_log(
                "scene.detect_failed",
                {
                    "videoPath": str(video_path),
                    "threshold": scene_threshold,
                    "returncode": completed.returncode,
                    "stderr": completed.stderr[-1200:] if completed.stderr else "",
                },
            )
            raise IngestError("场景检测失败，暂时无法自动分割。")

        output_text = "\n".join([completed.stderr or "", completed.stdout or ""])
        timestamps: list[float] = []
        matches = re.findall(r"pts_time:([0-9]+(?:\.[0-9]+)?)", output_text)
        for value in matches:
            try:
                point = float(value)
            except ValueError:
                continue
            if point > 0:
                timestamps.append(point)

        deduped = sorted(set(timestamps))
        append_debug_log(
            "scene.detect_attempt",
            {
                "videoPath": str(video_path),
                "threshold": scene_threshold,
                "detected": deduped,
                "count": len(deduped),
                "outputTail": output_text[-800:],
            },
        )
        if deduped:
            return deduped

    return []


def detect_visual_change_boundaries(video_path: Path, threshold: float) -> list[float]:
    if not FFMPEG_EXE.exists():
        return []

    sample_fps = 2
    width = 64
    height = 36
    frame_size = width * height
    command = [
        str(FFMPEG_EXE),
        "-hide_banner",
        "-i",
        str(video_path),
        "-vf",
        f"fps={sample_fps},scale={width}:{height},format=gray",
        "-f",
        "rawvideo",
        "-pix_fmt",
        "gray",
        "pipe:1",
    ]
    completed = subprocess.run(command, capture_output=True)
    if completed.returncode != 0:
        append_debug_log(
            "scene.visual_detect_failed",
            {
                "videoPath": str(video_path),
                "returncode": completed.returncode,
                "stderr": completed.stderr.decode("utf-8", errors="ignore")[-1200:],
            },
        )
        return []

    raw = completed.stdout or b""
    if len(raw) < frame_size * 2:
        return []

    frames: list[memoryview] = []
    for offset in range(0, len(raw) - frame_size + 1, frame_size):
        chunk = memoryview(raw)[offset : offset + frame_size]
        if len(chunk) != frame_size:
            break
        frames.append(chunk)

    if len(frames) < 2:
        return []

    diffs: list[tuple[float, float]] = []
    previous = frames[0]
    for index in range(1, len(frames)):
        current = frames[index]
        delta = sum(abs(current[pixel] - previous[pixel]) for pixel in range(frame_size)) / (frame_size * 255.0)
        diffs.append((index / sample_fps, delta))
        previous = current

    if not diffs:
        return []

    diff_values = [value for _, value in diffs]
    median_diff = statistics.median(diff_values)
    mad = statistics.median([abs(value - median_diff) for value in diff_values]) if len(diff_values) > 1 else 0.0
    normalized = max(0.0, min(1.0, (threshold - 0.08) / (0.6 - 0.08)))
    factor = 2.6 - normalized * 1.9
    cutoff = max(0.012, median_diff + max(mad, 0.0035) * factor)

    boundaries: list[float] = []
    for index, (timestamp, value) in enumerate(diffs):
        prev_value = diffs[index - 1][1] if index > 0 else value
        next_value = diffs[index + 1][1] if index + 1 < len(diffs) else value
        if value < cutoff:
            continue
        if value < prev_value or value < next_value:
            continue
        boundaries.append(round(timestamp, 3))

    append_debug_log(
        "scene.visual_detect_attempt",
        {
            "videoPath": str(video_path),
            "threshold": threshold,
            "cutoff": round(cutoff, 6),
            "medianDiff": round(median_diff, 6),
            "mad": round(mad, 6),
            "detected": boundaries,
            "count": len(boundaries),
        },
    )
    return boundaries


FFMPEG_ENCODERS_CACHE: set[str] | None = None


def ffmpeg_encoder_available(encoder_name: str) -> bool:
    global FFMPEG_ENCODERS_CACHE
    if not FFMPEG_EXE.exists():
        return False
    if FFMPEG_ENCODERS_CACHE is None:
        try:
            completed = subprocess.run(
                [str(FFMPEG_EXE), "-hide_banner", "-encoders"],
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="ignore",
                timeout=8,
            )
            FFMPEG_ENCODERS_CACHE = set(re.findall(r"\b([a-z0-9_]+)\s+", completed.stdout or ""))
        except Exception:
            FFMPEG_ENCODERS_CACHE = set()
    return encoder_name in FFMPEG_ENCODERS_CACHE


def scene_video_encoder_attempts() -> list[tuple[str, list[str]]]:
    attempts: list[tuple[str, list[str]]] = []
    if ffmpeg_encoder_available("h264_nvenc"):
        attempts.append((
            "h264_nvenc",
            ["-c:v", "h264_nvenc", "-preset", "p4", "-tune", "hq", "-cq", "23", "-b:v", "0", "-pix_fmt", "yuv420p"],
        ))
    attempts.append(("libx264", ["-c:v", "libx264", "-preset", "veryfast", "-crf", "22", "-pix_fmt", "yuv420p"]))
    return attempts


def ingest_local_file(filename: str, file_bytes: bytes) -> MediaItem:
    if not filename:
        raise IngestError("缺少本地视频文件名。")
    if not file_bytes:
        raise IngestError("本地视频文件内容为空。")

    suffix = Path(filename).suffix.lower()
    if suffix not in {".mp4", ".mov", ".avi", ".m4v", ".webm", ".mkv"}:
        raise IngestError("仅支持 MP4、MOV、AVI、M4V、WEBM、MKV 视频文件。")

    media_id = uuid.uuid4().hex[:12]
    media_dir = MEDIA_ROOT / media_id
    media_dir.mkdir(parents=True, exist_ok=True)

    safe_stem = sanitize_filename(Path(filename).stem) or "local-video"
    video_name = f"{safe_stem}{suffix or '.mp4'}"
    video_path = media_dir / video_name
    video_path.write_bytes(file_bytes)

    duration_seconds = probe_video_duration(video_path)
    poster_path = generate_poster(video_path, media_dir)
    return MediaItem(
        media_id=media_id,
        title=Path(filename).stem or safe_stem,
        duration=format_duration(duration_seconds),
        source="本地视频",
        platform_key=None,
        source_url=f"local://{quote(filename, safe='')}",
        source_video_url=None,
        remote_video_url=get_public_media_url(media_id, video_path.name),
        remote_poster_url=get_public_media_url(media_id, poster_path.name) if poster_path else None,
        notes="已复制到程序媒体库，可直接用于场景分割与向量化。",
    )


def build_scene_segments_for_media(media_id: str, threshold: float, min_scene_seconds: float) -> dict:
    media_dir = MEDIA_ROOT / media_id
    if not media_dir.exists():
        raise IngestError("未找到对应媒体目录。")

    source_path = find_primary_media_video(media_dir)
    if not source_path:
        raise IngestError("该媒体下未找到可分割的视频文件。")

    total_duration = probe_video_duration(source_path)
    if not total_duration or total_duration <= 0:
        raise IngestError("无法读取视频时长，暂时不能执行场景分割。")

    min_scene_seconds = max(0.5, float(min_scene_seconds))
    threshold = max(0.08, min(0.6, float(threshold)))
    detected_boundaries = detect_scene_boundaries(source_path, threshold)
    detection_mode = "ffmpeg-scene"
    if not detected_boundaries:
        detected_boundaries = detect_visual_change_boundaries(source_path, threshold)
        detection_mode = "visual-change" if detected_boundaries else "single-segment"
    append_debug_log(
        "scene.detect_result",
        {
            "mediaId": media_id,
            "threshold": threshold,
            "minSceneSeconds": min_scene_seconds,
            "detected": detected_boundaries,
            "mode": detection_mode,
            "duration": total_duration,
        },
    )

    boundaries = [0.0]
    for point in detected_boundaries:
        if point - boundaries[-1] >= min_scene_seconds:
            boundaries.append(point)
    if total_duration - boundaries[-1] < min_scene_seconds and len(boundaries) > 1:
        boundaries.pop()
    boundaries.append(total_duration)

    scenes_dir = media_dir / "scenes"
    scenes_dir.mkdir(parents=True, exist_ok=True)
    split_run_id = unique_file_token("split", media_id)

    segments = []
    for index in range(len(boundaries) - 1):
        start = round(boundaries[index], 3)
        end = round(boundaries[index + 1], 3)
        if end <= start:
            continue
        clip_end = round(max(start + 0.08, end - 0.08), 3) if index < len(boundaries) - 2 else end
        if clip_end <= start:
            clip_end = round(min(end, start + 0.12), 3)
        segment_id = f"{split_run_id}-{index + 1:03d}"
        segment_filename = f"scene-{segment_id}.mp4"
        segment_path = scenes_dir / segment_filename
        if not FFMPEG_EXE.exists():
            raise IngestError("缺少 ffmpeg，无法执行场景分割。")

        segment_duration = round(max(0.08, clip_end - start), 3)
        completed = None
        used_encoder = ""
        for encoder_name, video_args in scene_video_encoder_attempts():
            if segment_path.exists():
                try:
                    segment_path.unlink()
                except Exception:
                    pass
            command = [
                str(FFMPEG_EXE),
                "-y",
                "-ss",
                str(start),
                "-i",
                str(source_path),
                "-t",
                str(segment_duration),
                "-map",
                "0:v:0",
                "-map",
                "0:a?",
                "-sn",
                "-reset_timestamps",
                "1",
                "-avoid_negative_ts",
                "make_zero",
                *video_args,
                "-c:a",
                "aac",
                "-movflags",
                "+faststart",
                str(segment_path),
            ]
            encode_started_at = time.perf_counter()
            completed = subprocess.run(command, capture_output=True, text=True, encoding="utf-8", errors="ignore")
            if completed.returncode == 0 and segment_path.exists() and segment_path.stat().st_size > 0:
                used_encoder = encoder_name
                append_debug_log(
                    "scene.segment_encode",
                    {
                        "mediaId": media_id,
                        "segment": segment_filename,
                        "encoder": encoder_name,
                        "start": start,
                        "duration": segment_duration,
                        "elapsedMs": round((time.perf_counter() - encode_started_at) * 1000),
                    },
                )
                break
            append_debug_log(
                "scene.segment_encode_failed",
                {
                    "mediaId": media_id,
                    "segment": segment_filename,
                    "encoder": encoder_name,
                    "returncode": completed.returncode if completed else None,
                    "stderr": completed.stderr[-1200:] if completed and completed.stderr else "",
                },
            )
        if not used_encoder:
            raise IngestError(f"切分片段失败：{segment_filename}")

        poster_path = generate_poster(segment_path, scenes_dir)
        segment_resolution = probe_video_resolution(segment_path)
        segment_width, segment_height = segment_resolution if segment_resolution else (None, None)
        segments.append(
            {
                "index": index + 1,
                "segmentId": segment_id,
                "splitRunId": split_run_id,
                "start": start,
                "end": clip_end,
                "duration": round(max(0.0, clip_end - start), 3),
                "filename": segment_filename,
                "url": get_public_media_url(media_id, f"scenes/{segment_filename}"),
                "width": segment_width,
                "height": segment_height,
                "posterUrl": get_public_media_url(media_id, f"scenes/{poster_path.name}") if poster_path else None,
            }
        )

    return {
        "mediaId": media_id,
        "source": source_path.name,
        "splitRunId": split_run_id,
        "threshold": threshold,
        "minSceneSeconds": min_scene_seconds,
        "segments": segments,
    }


def normalize_targets(info: dict, source_url: str) -> list[str]:
    entries = info.get("entries")
    if not isinstance(entries, list):
        return [source_url]

    targets: list[str] = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        target = entry.get("webpage_url") or entry.get("url")
        if isinstance(target, str) and target:
            targets.append(target)
    return targets or [source_url]


def download_single_url(target_url: str) -> list[MediaItem]:
    platform_key = detect_platform_key(target_url)
    target_urls = [target_url]
    if platform_key != "douyin":
        preview_info = extract_info_with_login_retry(target_url, MEDIA_ROOT, download=False)
        target_urls = normalize_targets(preview_info, target_url)
    items: list[MediaItem] = []

    for url in target_urls:
        media_id = uuid.uuid4().hex[:12]
        media_dir = MEDIA_ROOT / media_id
        media_dir.mkdir(parents=True, exist_ok=True)
        info = extract_info_with_login_retry(url, media_dir, download=True)

        video_path = resolve_downloaded_file(info)
        if not video_path:
            raise RuntimeError(f"未找到下载后的视频文件: {url}")

        poster_path = generate_poster(video_path, media_dir)
        platform_key = (
            detect_platform_key(info.get("extractor_key"))
            or detect_platform_key(info.get("extractor"))
            or detect_platform_key(info.get("webpage_url_domain"))
            or detect_platform_key(url)
        )

        title = str(info.get("title") or video_path.stem)
        duration = format_duration(probe_video_duration(video_path) or info.get("duration"))
        source = f"{platform_key and platform_key != 'youtube' and platform_key.title() or '作品'} 链接" if platform_key else "作品链接"
        if platform_key == "douyin":
            source = "抖音链接"
        elif platform_key == "xiaohongshu":
            source = "小红书链接"
        elif platform_key == "bilibili":
            source = "Bilibili 链接"
        elif platform_key == "kuaishou":
            source = "快手链接"
        elif platform_key == "tiktok":
            source = "TikTok 链接"
        elif platform_key == "youtube":
            source = "YouTube 链接"

        platform_metadata = build_platform_metadata(info, url)
        items.append(
            MediaItem(
                media_id=media_id,
                title=title,
                duration=duration,
                source=source,
                platform_key=platform_key,
                source_url=str(info.get("webpage_url") or url),
                source_video_url=str(info.get("url") or "").strip() or None,
                remote_video_url=get_public_media_url(media_id, video_path.name),
                remote_poster_url=get_public_media_url(media_id, poster_path.name) if poster_path else None,
                notes="已通过统一下载服务完成提取并入库。",
                basic_info=platform_metadata.get("basicInfo"),
                author=platform_metadata.get("author"),
                metrics=platform_metadata.get("metrics"),
                content_tags=platform_metadata.get("contentTags") or None,
                commerce=platform_metadata.get("commerce"),
                platform_raw=platform_metadata.get("platformRaw"),
            )
        )

    return items


class Handler(BaseHTTPRequestHandler):
    def log_message(self, format: str, *args: object) -> None:
        return

    def request_base_url(self) -> str:
        forwarded_proto = str(self.headers.get("X-Forwarded-Proto") or "").split(",")[0].strip().lower()
        scheme = forwarded_proto if forwarded_proto in {"http", "https"} else "http"
        raw_host = str(self.headers.get("Host") or f"{HOST}:{PORT}").strip()
        host = raw_host if re.fullmatch(r"[A-Za-z0-9.\-:\[\]]+", raw_host) else f"{HOST}:{PORT}"
        return f"{scheme}://{host}"

    def request_cors_origin(self) -> str:
        origin = str(self.headers.get("Origin") or "").strip()
        parsed = urlparse(origin)
        hostname = (parsed.hostname or "").lower()
        if parsed.scheme in {"http", "https"} and hostname in {"127.0.0.1", "localhost", "::1"}:
            return origin
        return "http://127.0.0.1:5174"

    def handle_one_request(self) -> None:
        try:
            super().handle_one_request()
        except Exception as exc:
            append_debug_log(
                "server.request_unhandled_error",
                {
                    "client": str(getattr(self, "client_address", "")),
                    "path": getattr(self, "path", ""),
                    "errorType": type(exc).__name__,
                    "error": str(exc),
                    "traceback": traceback.format_exc(),
                },
            )
            raise

    def end_headers(self) -> None:
        self.send_header("Access-Control-Allow-Origin", self.request_cors_origin())
        self.send_header("Vary", "Origin")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type")
        super().end_headers()

    def do_OPTIONS(self) -> None:
        self.send_response(204)
        self.end_headers()

    def do_HEAD(self) -> None:
        parsed = urlparse(self.path)
        if parsed.path == "/api/health":
            self.send_response(200)
            self.send_header("Content-Type", "application/json; charset=utf-8")
            self.send_header("Content-Length", "0")
            self.end_headers()
            return
        self.send_response(200 if FRONTEND_DIR.exists() else 404)
        self.send_header("Content-Length", "0")
        self.end_headers()

    def do_GET(self) -> None:
        parsed = urlparse(self.path)
        if parsed.path == "/api/health":
            self.write_json(200, {"status": "ok"})
            return
        if parsed.path == "/api/license/status":
            self.handle_license_status()
            return
        if license_required_for(parsed.path) and not get_license_status(force_online=False).get("active"):
            self.write_json(403, {"error": "软件未授权或授权已过期，请先完成账号授权。", "code": "LICENSE_REQUIRED"})
            return
        if parsed.path == "/api/global-settings":
            self.write_json(200, get_global_settings_bundle())
            return
        if parsed.path == "/api/script-template/xlsx":
            self.handle_script_template_download()
            return
        if parsed.path == "/api/system/capcut/locate":
            self.write_json(200, locate_capcut_installation())
            return
        if parsed.path == "/api/system/environment":
            self.write_json(200, build_environment_health())
            return
        if parsed.path == "/api/system/select-video-folder":
            self.handle_select_video_folder()
            return
        if parsed.path == "/api/system/select-export-folder":
            self.handle_select_export_folder()
