    def do_DELETE(self) -> None:
        parsed = urlparse(self.path)
        if license_required_for(parsed.path) and not get_license_status(force_online=False).get("active"):
            self.write_json(403, {"error": "软件未授权或授权已过期，请先完成账号授权。", "code": "LICENSE_REQUIRED"})
            return
        if parsed.path.startswith("/api/media/"):
            media_id = parsed.path.split("/")[-1]
            target = MEDIA_ROOT / media_id
            if target.exists():
                shutil.rmtree(target, ignore_errors=True)
            pruned = prune_vector_items(media_id=media_id)
            append_debug_log("api.media.delete", {"mediaId": media_id, "vectorRemoved": pruned["removed"]})
            self.write_json(200, {"deleted": True, "vectorRemoved": pruned["removed"]})
            return
        if parsed.path.startswith("/api/bgm-library/"):
            self.handle_bgm_library_delete(parsed.path.split("/")[-1])
            return
        self.write_json(404, {"error": "Not found"})

    def read_json_body(self) -> dict:
        content_length = int(self.headers.get("Content-Length", "0"))
        if content_length <= 0:
            return {}
        payload = json.loads(self.rfile.read(content_length).decode("utf-8"))
        return payload if isinstance(payload, dict) else {}

    def handle_media_library_list(self) -> None:
        try:
            saved_items = read_media_library_items()
            disk_items = recover_media_library_items_from_disk()
            items = merge_media_library_items(saved_items, disk_items)
            if items != saved_items:
                write_media_library_items(items)
                sync_client_state_value("meiao-ingest-items", items)
            self.write_json(200, {"items": items, "saved": len(saved_items), "recovered": len(items) - len(saved_items)})
        except Exception as exc:
            append_debug_log("api.media_library.list.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": "读取素材库备份失败。"})

    def handle_media_library_save(self) -> None:
        try:
            payload = self.read_json_body()
            raw_items = payload.get("items")
            if not isinstance(raw_items, list):
                self.write_json(400, {"error": "items 必须是数组。"})
                return
            items = [item for item in raw_items if isinstance(item, dict) and str(item.get("id") or "").strip()]
            current = read_media_library_items()
            if not items and current and payload.get("allowEmptyProtected") is not True:
                self.write_json(200, {"ok": True, "count": len(current), "skipped": True})
                return
            if payload.get("replace") is not True:
                items = merge_media_library_items(items, current)
            write_media_library_items(items)
            sync_client_state_value("meiao-ingest-items", items, replace=payload.get("replace") is True)
            self.write_json(200, {"ok": True, "count": len(items)})
        except Exception as exc:
            append_debug_log("api.media_library.save.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": "保存素材库备份失败。"})

    def handle_product_project_delete(self) -> None:
        try:
            payload = self.read_json_body()
            project_id = str(payload.get("projectId") or "").strip()
            confirm_text = str(payload.get("confirmText") or "").strip()
            if not project_id:
                self.write_json(400, {"error": "缺少 projectId。"})
                return
            state = build_recovered_client_state()
            projects = state.get("meiao-product-projects") if isinstance(state.get("meiao-product-projects"), list) else []
            project = next((item for item in projects if isinstance(item, dict) and str(item.get("id") or "").strip() == project_id), None)
            project_name = str(project.get("name") or project_id).strip() if isinstance(project, dict) else project_id
            expected_texts = {project_id, project_name, f"删除{project_name}"}
            if confirm_text not in expected_texts:
                self.write_json(409, {"error": f"二次确认失败：请输入项目名称“{project_name}”或项目 ID“{project_id}”。", "projectName": project_name})
                return
            result = delete_product_project_cascade(project_id)
            self.write_json(200, {**result, "projectName": project_name})
        except Exception as exc:
            append_debug_log("api.product_projects.delete.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": f"删除项目失败：{str(exc)}"})

    def handle_media_extract_frame(self) -> None:
        try:
            payload = self.read_json_body()
            result = extract_frame_from_media_url(
                str(payload.get("url") or payload.get("mediaUrl") or ""),
                float(payload.get("offsetSeconds") or 0.05),
            )
            append_debug_log("api.media.extract_frame", {"sourceUrl": result.get("sourceUrl"), "mediaId": result.get("mediaId")})
            self.write_json(200, result)
        except IngestError as exc:
            append_debug_log("api.media.extract_frame.error", {"error": str(exc), "code": exc.code})
            self.write_json(409, {"error": str(exc), "code": exc.code, "action": exc.action})
        except Exception as exc:
            append_debug_log("api.media.extract_frame.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": str(exc)})

