    def handle_client_state_save(self) -> None:
        try:
            payload = self.read_json_body()
            incoming = payload.get("state")
            if not isinstance(incoming, dict):
                self.write_json(400, {"error": "state 必须是对象。"})
                return
            current = read_client_state()
            skipped: list[str] = []
            allow_empty = payload.get("allowEmptyProtected") is True
            for key, value in incoming.items():
                if not isinstance(key, str) or not key.startswith("meiao-"):
                    continue
                if should_skip_empty_client_state_update(key, value, current.get(key), allow_empty=allow_empty):
                    skipped.append(key)
                    continue
                current[key] = merge_client_state_value(key, value, current.get(key), client_state_replace_requested(payload, key))
            write_client_state(current)
            if isinstance(current.get("meiao-ingest-items"), list):
                write_media_library_items(merge_media_library_items(current["meiao-ingest-items"], []))
            if isinstance(current.get("meiao-draft-templates"), list):
                write_draft_templates(merge_draft_templates(current["meiao-draft-templates"], []))
            if isinstance(current.get("meiao-batch-draft-projects"), list):
                write_batch_draft_projects(current["meiao-batch-draft-projects"])
            self.write_json(200, {"ok": True, "keys": sorted(current.keys()), "skippedEmpty": skipped})
        except Exception as exc:
            append_debug_log("api.client_state.save.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": "保存工作台数据失败。"})

    def handle_client_state_clean(self) -> None:
        try:
            payload = self.read_json_body()
            result = clean_client_state(apply=bool(payload.get("apply")))
            append_debug_log("api.client_state.clean", {"applied": result.get("applied"), "changes": result.get("changes")})
            self.write_json(200, result)
        except Exception as exc:
            append_debug_log("api.client_state.clean.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
