    def handle_capcut_mate_generate_draft(self) -> None:
        try:
            content_length = int(self.headers.get("Content-Length", "0"))
            payload = json.loads(self.rfile.read(content_length).decode("utf-8")) if content_length else {}
            if not isinstance(payload, dict):
                self.write_json(400, {"error": "请求体格式错误"})
                return
            plan = payload.get("plan")
            if not isinstance(plan, dict):
                self.write_json(400, {"error": "缺少草稿计划"})
                return
            width = int(payload.get("width") or 1080)
            height = int(payload.get("height") or 1920)
            if width <= 0 or height <= 0:
                self.write_json(400, {"error": "画布尺寸无效"})
                return
            try:
                from integrations.capcut_mate.adapter import CapCutMateAdapter, CapCutMateError
            except Exception as exc:
                append_debug_log("api.capcut_mate.import.error", {"errorType": type(exc).__name__, "error": str(exc)})
                self.write_json(500, {"error": "剪映小助手适配器缺失，请检查 integrations/capcut_mate。"})
                return

            adapter = CapCutMateAdapter()
            with CAPCUT_DRAFT_WRITE_SEMAPHORE:
                result = adapter.generate_draft_from_plan(plan, width=width, height=height)
            draft_url = str(result.get("draft_url") or "").strip()
            if not draft_url:
                self.write_json(500, {"error": "剪映小助手未返回草稿地址。"})
                return
            append_debug_log(
                "api.capcut_mate.generate_draft.success",
                {
                    "planId": plan.get("id"),
                    "clipCount": result.get("clip_count"),
                    "draftUrl": draft_url,
                    "voiceDurationResult": result.get("voice_duration_result"),
                    "timingResult": result.get("timing_result"),
                    "addVideosResult": {
                        "total_duration": (result.get("add_videos_result") or {}).get("total_duration"),
                        "source_duration_total": (result.get("add_videos_result") or {}).get("source_duration_total"),
                        "segment_count": len((result.get("add_videos_result") or {}).get("segment_ids") or []),
                    },
                },
            )
            self.write_json(
                200,
                {
                    "draftUrl": draft_url,
                    "clipCount": int(result.get("clip_count") or 0),
                    "timingResult": result.get("timing_result"),
                    "voiceDurationResult": result.get("voice_duration_result"),
                    "createResult": result.get("create_result"),
                    "addVideosResult": result.get("add_videos_result"),
                    "addAudiosResult": result.get("add_audios_result"),
                    "addCaptionsResult": result.get("add_captions_result"),
                    "addFiltersResult": result.get("add_filters_result"),
                    "addEffectsResult": result.get("add_effects_result"),
                    "addStickersResult": result.get("add_stickers_result"),
                    "addDedupeVideoResult": result.get("add_dedupe_video_result"),
                    "addMasksResult": result.get("add_masks_result"),
                    "addKeyframesResult": result.get("add_keyframes_result"),
                    "saveResult": result.get("save_result"),
                    "importResult": result.get("import_result"),
                    "recognizeSubtitlesResult": result.get("recognize_subtitles_result"),
                },
            )
        except Exception as exc:
            error_text = str(exc)
            append_debug_log(
                "api.capcut_mate.generate_draft.error",
                {"errorType": type(exc).__name__, "error": error_text, "traceback": traceback.format_exc()},
            )
            status = 409 if "capcut-mate service unavailable" in error_text or "Connection refused" in error_text else 500
            hint = ""
            if status == 409:
                hint = "请先启动剪映小助手服务 http://127.0.0.1:30000。"
            self.write_json(status, {"error": f"剪映草稿写入失败：{error_text}{('。' + hint) if hint else ''}"})

    def handle_capcut_mate_template_preview(self) -> None:
        try:
            content_length = int(self.headers.get("Content-Length", "0"))
            payload = json.loads(self.rfile.read(content_length).decode("utf-8")) if content_length else {}
            if not isinstance(payload, dict):
                self.write_json(400, {"error": "请求体格式错误"})
                return
            template = payload.get("template")
            if not isinstance(template, dict):
                self.write_json(400, {"error": "缺少草稿模板配置"})
                return
            template = sanitize_draft_template(template)

            aspect_ratio = str(template.get("aspectRatio") or "9:16")
            canvas_by_ratio = {
                "21:9": (2520, 1080),
                "16:9": (1920, 1080),
                "3:2": (1620, 1080),
                "4:3": (1440, 1080),
                "5:4": (1350, 1080),
                "1:1": (1080, 1080),
                "4:5": (1080, 1350),
                "3:4": (1080, 1440),
                "9:16": (1080, 1920),
            }
            width, height = canvas_by_ratio.get(aspect_ratio, (1080, 1920))
            rejected_preview_videos: list[dict] = []
            def safe_preview_video_from_payload(raw_item: object) -> Path | None:
                raw_path = ""
                raw_url = ""
                if isinstance(raw_item, dict):
                    raw_path = str(raw_item.get("path") or "").strip()
                    raw_url = str(raw_item.get("url") or "").strip()
                elif isinstance(raw_item, str):
                    raw_path = raw_item.strip()

                def validate_candidate(candidate: Path) -> Path | None:
                    media_root_resolved = MEDIA_ROOT.resolve()
                    resolved = candidate.resolve()
                    resolved.relative_to(media_root_resolved)
                    if resolved.is_file() and resolved.suffix.lower() in VIDEO_FILE_SUFFIXES:
                        return resolved
                    return None

                if raw_path:
                    try:
                        candidate = validate_candidate(Path(raw_path))
                        if candidate:
                            return candidate
                    except Exception:
                        pass

                if raw_url:
                    try:
                        parsed_media_url = urlparse(raw_url)
                        media_path = unquote(parsed_media_url.path or raw_url)
                        if media_path.startswith("/media/"):
                            relative_media_path = media_path[len("/media/") :]
                            candidate = validate_candidate(MEDIA_ROOT / relative_media_path)
                            if candidate:
                                return candidate
                    except Exception:
                        pass

                if not raw_path and not raw_url:
                    rejected_preview_videos.append({"path": "", "reason": "empty"})
                    return None
                rejected_preview_videos.append({"path": raw_path, "url": raw_url, "reason": "unusable_preview_video"})
                return None

            preview_clip_limit = 3
            requested_preview_videos = payload.get("previewVideos") if isinstance(payload.get("previewVideos"), list) else []
            requested_sample_videos: list[Path] = []
            for raw_item in requested_preview_videos:
                candidate = safe_preview_video_from_payload(raw_item)
                if candidate and candidate not in requested_sample_videos:
                    requested_sample_videos.append(candidate)
                if len(requested_sample_videos) >= preview_clip_limit:
                    break

            discovered_sample_videos = sorted(
                [
                    item
                    for item in MEDIA_ROOT.rglob("*")
                    if item.is_file() and item.suffix.lower() in VIDEO_FILE_SUFFIXES
                ],
                key=lambda item: (0 if "scene" in str(item).lower() else 1, item.stat().st_size if item.exists() else 0),
            )
            sample_videos = list(requested_sample_videos)
            if len(sample_videos) < preview_clip_limit:
                for item in discovered_sample_videos:
                    if item not in sample_videos:
                        sample_videos.append(item)
                    if len(sample_videos) >= preview_clip_limit:
                        break
            if not sample_videos:
                self.write_json(409, {"error": "没有找到可用于真实预览的本地视频素材，请先导入或拆分一个素材。"})
                return

            def media_url(path: Path) -> str:
                relative_parts = [quote(part, safe="") for part in path.relative_to(MEDIA_ROOT).parts]
                return f"{self.request_base_url()}/media/" + "/".join(relative_parts)

            clip_paths = list(sample_videos[:preview_clip_limit])
            if len(clip_paths) == 1:
                clip_paths = [clip_paths[0], clip_paths[0]]
            preview_draft_parts = [
                re.sub(r"[^0-9A-Za-z_.-]+", "-", str(template.get("projectId") or "").strip()).strip(".-"),
                re.sub(r"[^0-9A-Za-z_.-]+", "-", str(template.get("id") or "").strip()).strip(".-"),
            ]
            preview_draft_seed = "-".join(part for part in preview_draft_parts if part)
            if not preview_draft_seed:
                preview_draft_seed = uuid.uuid5(uuid.NAMESPACE_URL, json.dumps(template, ensure_ascii=False, sort_keys=True)).hex[:16]
            preview_draft_id = f"MEIAO-TEMPLATE-PREVIEW-{preview_draft_seed}"[:120].rstrip(".-")
            sample_video_source = "payload" if requested_sample_videos and len(requested_sample_videos) >= len(clip_paths) else ("payload+auto" if requested_sample_videos else "auto")
            clip_duration_ms = 5000
            preview_total_duration_ms = len(clip_paths) * clip_duration_ms
            def preview_write_plan_summary(template_data: dict) -> dict:
                raw_filters = template_data.get("filterLayers") if isinstance(template_data.get("filterLayers"), list) else []
                filter_layers = [
                    item for item in raw_filters
                    if isinstance(item, dict) and str(item.get("filterChoice") or "").strip()
                ]
                if not filter_layers and str(template_data.get("filterChoice") or "").strip():
                    filter_layers = [
                        {
                            "filterChoice": str(template_data.get("filterChoice") or ""),
                            "intensity": template_data.get("filterIntensity") if template_data.get("filterIntensity") is not None else 100,
                            "opacity": 100,
                        }
                    ]

                raw_stickers = template_data.get("stickerLayers") if isinstance(template_data.get("stickerLayers"), list) else []
                sticker_layers = [
                    item for item in raw_stickers
                    if isinstance(item, dict) and (str(item.get("stickerId") or "").strip() or str(item.get("keyword") or "").strip())
                ]
                if not sticker_layers and bool(template_data.get("stickersEnabled")) and str(template_data.get("stickerId") or "").strip():
                    sticker_layers = [
                        {
                            "stickerId": str(template_data.get("stickerId") or ""),
                            "scale": template_data.get("stickerScale") if template_data.get("stickerScale") is not None else 0.35,
                            "alpha": 100,
                            "transformX": template_data.get("stickerTransformX") if template_data.get("stickerTransformX") is not None else 0.28,
                            "transformY": template_data.get("stickerTransformY") if template_data.get("stickerTransformY") is not None else -0.3,
                        }
                    ]

                def write_intensity(layer: dict) -> int:
                    intensity = float(layer.get("intensity") if layer.get("intensity") is not None else 100)
                    opacity = float(layer.get("opacity") if layer.get("opacity") is not None else 100)
                    return round(max(0, min(100, intensity)) * max(0, min(100, opacity)) / 100)

                def sticker_alpha(layer: dict) -> int:
                    return round(max(0, min(100, float(layer.get("alpha") if layer.get("alpha") is not None else 100))))

                bgm_ids = template_data.get("bgmTrackIds") if isinstance(template_data.get("bgmTrackIds"), list) else []
                audio_track_count = 1 if str(template_data.get("bgmMode") or "none") != "none" and any(str(item or "").strip() for item in bgm_ids) else 0
                dedupe_count = int(max(0, min(4, float(template_data.get("dedupeAuxVideoCount") if template_data.get("dedupeAuxVideoCount") is not None else 0)))) if bool(template_data.get("dedupeEnabled")) else 0
                caption_count = len(clip_paths) if bool(template_data.get("subtitleEnabled", True)) else 0
                caption_font_size = int(max(6, min(40, round(float(template_data.get("captionFontSize") or 46) / 3))))
                caption_transform_x = int(max(-width, min(width, float(template_data.get("captionTransformX") or 0))))
                caption_raw_y = float(template_data.get("captionTransformY") if template_data.get("captionTransformY") is not None else 690)
                caption_transform_y = int(-max(-height, min(height, caption_raw_y)))
                caption_alpha = int(max(0, min(100, float(template_data.get("captionAlpha") if template_data.get("captionAlpha") is not None else 100))))
                keyword_sound_count = 1 if bool(template_data.get("captionKeywordEnabled")) and bool(template_data.get("keywordSoundEnabled")) and str(template_data.get("keywordSoundUrl") or "").strip() else 0
                basic_dedupe_filter_count = 5 if dedupe_count and not filter_layers else 0
                user_filter_count = len(filter_layers)
                expected_filter_count = user_filter_count + basic_dedupe_filter_count

                summary = [
                    f"写入预检：画布 {aspect_ratio} · {width}×{height}",
                    f"写入预检：字幕 {caption_count} 条 · 字号 {caption_font_size} · X {caption_transform_x} · Y {caption_transform_y} · 透明 {caption_alpha}%" if caption_count else "写入预检：字幕关闭",
                ]
                if filter_layers:
                    summary.append(f"写入预检：滤镜 {len(filter_layers)} 轨 · 强度 {'/'.join(str(write_intensity(layer)) for layer in filter_layers[:4])}%")
                if basic_dedupe_filter_count:
                    summary.append(f"写入预检：基础去重滤镜 {basic_dedupe_filter_count} 轨 · 强度 2%")
                if sticker_layers:
                    summary.append(f"写入预检：贴纸 {len(sticker_layers)} 轨 · 透明 {'/'.join(str(sticker_alpha(layer)) for layer in sticker_layers[:4])}%")
                if dedupe_count:
                    summary.append(f"写入预检：辅助视频 {dedupe_count} 条 · {template_data.get('dedupeAuxAlpha')}%")
                if audio_track_count:
                    summary.append(f"写入预检：音乐 {audio_track_count} 轨")
                if keyword_sound_count:
                    summary.append("写入预检：关键词提示音 1 条")
                return {
                    "filterLayerCount": expected_filter_count,
                    "userFilterLayerCount": user_filter_count,
                    "basicDedupeFilterLayerCount": basic_dedupe_filter_count,
                    "filterWriteIntensities": [write_intensity(layer) for layer in filter_layers],
                    "stickerLayerCount": len(sticker_layers),
                    "stickerAlphas": [sticker_alpha(layer) for layer in sticker_layers],
                    "dedupeAuxVideoCount": dedupe_count,
                    "captionCount": caption_count,
                    "captionFontSize": caption_font_size,
                    "captionTransformX": caption_transform_x,
                    "captionTransformY": caption_transform_y,
                    "captionAlpha": caption_alpha,
                    "audioTrackCount": audio_track_count,
                    "keywordSoundCount": keyword_sound_count,
                    "appliedSummary": summary,
                }
            write_plan_summary = preview_write_plan_summary(template)
            def preview_acceptance_summary(actual_counts: dict | None = None) -> list[str]:
                actual_counts = actual_counts or {}
                expected_caption_count = int(write_plan_summary.get("captionCount") or 0)
                expected_filter_count = int(write_plan_summary.get("filterLayerCount") or 0)
                expected_sticker_count = int(write_plan_summary.get("stickerLayerCount") or 0)
                expected_dedupe_count = int(write_plan_summary.get("dedupeAuxVideoCount") or 0)
                expected_audio_count = int(write_plan_summary.get("audioTrackCount") or 0)
                actual_clip_count = int(actual_counts.get("clipCount") or 0)
                actual_caption_count = int(actual_counts.get("captionCount") or 0)
                actual_filter_count = int(actual_counts.get("filterCount") or 0)
                actual_sticker_count = int(actual_counts.get("stickerCount") or 0)
                actual_dedupe_count = int(actual_counts.get("dedupeCount") or 0)
                actual_audio_count = int(actual_counts.get("audioCount") or 0)
                actual_draft_ready = bool(actual_counts.get("draftReady"))
                if actual_counts:
                    layer_summary = (
                        f"写入验收：视频 {actual_clip_count}/{len(clip_paths)} · "
                        f"字幕 {actual_caption_count}/{expected_caption_count} · "
                        f"滤镜 {actual_filter_count}/{expected_filter_count} · "
                        f"贴纸 {actual_sticker_count}/{expected_sticker_count} · "
                        f"辅助 {actual_dedupe_count}/{expected_dedupe_count}"
                    )
                    audio_summary = f"写入验收：音乐 {actual_audio_count}/{expected_audio_count}" if expected_audio_count else "写入验收：音乐 未选择或未缓存，不阻断模板"
                    draft_summary = "写入验收：固定预览草稿已更新到剪映草稿目录" if actual_draft_ready else "写入验收：真实草稿已生成，导入目录待确认"
                else:
                    layer_summary = (
                        f"预检验收：视频 {len(clip_paths)} 段 · "
                        f"字幕 {expected_caption_count} · 滤镜 {expected_filter_count} · "
                        f"贴纸 {expected_sticker_count} · 辅助 {expected_dedupe_count}"
                    )
                    audio_summary = f"预检验收：音乐 {expected_audio_count} 轨" if expected_audio_count else "预检验收：音乐 未选择或未缓存，不阻断模板"
                    draft_summary = "预检验收：待生成真实剪映草稿"
                return [
                    f"验收：数据 本机服务端 · 样片 {len(clip_paths)}/{len(requested_preview_videos) or len(clip_paths)}",
                    f"验收：画布 {aspect_ratio} · {width}×{height}",
                    layer_summary,
                    f"验收：字幕字号 {write_plan_summary.get('captionFontSize')} · X {write_plan_summary.get('captionTransformX')} · Y {write_plan_summary.get('captionTransformY')}",
                    audio_summary,
                    draft_summary,
                ]
            if payload.get("validateOnly") is True:
                self.write_json(
                    200,
                    {
                        "previewId": "",
                        "draftUrl": "",
                        "exportSubmitted": False,
                        "previewDraftId": preview_draft_id,
                        "sampleVideos": [str(item) for item in clip_paths],
                        "sampleVideoSource": sample_video_source,
                        "canvas": {"width": width, "height": height, "aspectRatio": aspect_ratio},
                        "writePlanSummary": write_plan_summary,
                        "appliedSummary": write_plan_summary.get("appliedSummary", []),
                        "acceptanceSummary": preview_acceptance_summary(),
                        "debug": {
                            "mediaRoot": str(MEDIA_ROOT.resolve()),
                            "requestedPreviewVideoCount": len(requested_preview_videos),
                            "acceptedPreviewVideoCount": len(requested_sample_videos),
                            "rejectedPreviewVideos": rejected_preview_videos[:4],
                        },
                    },
                )
                return
            clips: list[dict] = []
            captions: list[dict] = []
            for index, video_path in enumerate(clip_paths):
                source_duration_ms = max(1000, round((probe_video_duration(video_path) or 5.0) * 1000))
                start_ms = index * clip_duration_ms
                end_ms = start_ms + clip_duration_ms
                clips.append(
                    {
                        "id": f"TEMPLATE-PREVIEW-CLIP-{index + 1}",
                        "order": index + 1,
                        "sourceUrl": media_url(video_path),
                        "sourceStartMs": 0,
                        "sourceEndMs": min(source_duration_ms, clip_duration_ms),
                        "sourceDurationMs": source_duration_ms,
                        "requiredDurationMs": clip_duration_ms,
                        "timelineStartMs": start_ms,
                        "timelineEndMs": end_ms,
                        "durationMs": clip_duration_ms,
                        "playbackSpeed": max(0.05, source_duration_ms / clip_duration_ms),
                        "volume": 0 if bool(template.get("removeOriginalAudio", True)) else 1,
                        "fitMode": str(template.get("fitMode") or "cover"),
                    }
                )
                captions.append(
                    {
                        "id": f"TEMPLATE-PREVIEW-CAPTION-{index + 1}",
                        "text": "我一定要把这个模板效果做出来" if index == 0 else "这里会按剪映真实草稿预览",
                        "startMs": start_ms,
                        "endMs": end_ms,
                    }
                )

            raw_bgm_id = ""
            bgm_ids = template.get("bgmTrackIds")
            if isinstance(bgm_ids, list) and bgm_ids:
                raw_bgm_id = str(bgm_ids[0] or "").strip()
            audio_tracks: list[dict] = []
            if str(template.get("bgmMode") or "none") != "none" and raw_bgm_id:
                bgm_url = raw_bgm_id
                if not (bgm_url.startswith("/") or bgm_url.startswith("http://") or bgm_url.startswith("https://")):
                    bgm_match = next(
                        (
                            normalize_bgm_item(item)
                            for item in read_bgm_library()
                            if isinstance(item, dict) and str(item.get("id") or "").strip() == raw_bgm_id
                        ),
                        None,
                    )
                    if bgm_match:
                        bgm_url = str(bgm_match.get("url") or bgm_url)
                if bgm_url.startswith("/"):
                    bgm_url = f"{self.request_base_url()}{bgm_url}"
                if bgm_url.startswith("http://") or bgm_url.startswith("https://"):
                    audio_tracks.append(
                        {
                            "id": "TEMPLATE-PREVIEW-BGM",
                            "title": "模板预览 BGM",
                            "sourceType": "bgm_library",
                            "sourceUrl": bgm_url,
                            "startMs": 0,
                            "endMs": preview_total_duration_ms,
                            "durationMs": preview_total_duration_ms,
                            "volume": float(template.get("bgmVolume") or 0.16),
                            "audioEffect": str(template.get("toneEffect") or template.get("audioSceneEffect") or ""),
                        }
                    )

            raw_filter_layers = template.get("filterLayers") if isinstance(template.get("filterLayers"), list) else []
            filter_layers = raw_filter_layers
            if not filter_layers and str(template.get("filterChoice") or "").strip():
                filter_layers = [
                    {
                        "filterChoice": str(template.get("filterChoice") or ""),
                        "intensity": int(template.get("filterIntensity") or 100),
                        "opacity": 100,
                        "startSec": 0,
                        "endSec": 0,
                    }
                ]

            plan = {
                "id": f"TEMPLATE-PREVIEW-{uuid.uuid4().hex[:10]}",
                "taskId": str(template.get("id") or "template-preview"),
                "targetDraftId": preview_draft_id,
                "removeOriginalAudio": bool(template.get("removeOriginalAudio", True)),
                "subtitlePreset": "recommended" if bool(template.get("subtitleEnabled", True)) else "none",
                "filterChoice": str(template.get("filterChoice") or ""),
                "filterLayers": filter_layers,
                "filterIntensity": int(template.get("filterIntensity") or 100),
                "filterStartSec": float(template.get("filterStartSec") or 0),
                "filterEndSec": float(template.get("filterEndSec") or 0),
                "effectChoice": "",
                "effectLayers": [],
                "effectStartSec": float(template.get("effectStartSec") or 0),
                "effectEndSec": float(template.get("effectEndSec") or 0),
                "motionPreset": str(template.get("motionPreset") or ""),
                "randomZoomEnabled": bool(template.get("randomZoomEnabled", True)),
                "randomZoomMin": max(1.0, float(template.get("randomZoomMin") or 110) / 100),
                "randomZoomMax": max(1.0, float(template.get("randomZoomMax") or 130) / 100),
                "randomFlipEnabled": bool(template.get("randomFlipEnabled", False)),
                "clipScale": float(template.get("clipScale") or 1),
                "clipTransformX": int(template.get("clipTransformX") or 0),
                "clipTransformY": int(template.get("clipTransformY") or 0),
                "transitionStyle": str(template.get("transitionStyle") or ""),
                "transitionDurationMs": int(template.get("transitionDurationMs") or 500),
                "videoMask": str(template.get("videoMask") or ""),
                "maskFeather": float(template.get("maskFeather") or 0),
                "captionFont": str(template.get("captionFont") or ""),
                "captionFontSize": int(template.get("captionFontSize") or 46),
                "captionColor": str(template.get("captionColor") or "#ffffff"),
                "captionKeywordEnabled": bool(template.get("captionKeywordEnabled", False)),
                "captionKeywords": str(template.get("captionKeywords") or ""),
                "captionKeywordColor": str(template.get("captionKeywordColor") or "#ff7100"),
                "captionKeywordFontSize": int(template.get("captionKeywordFontSize") or 58),
                "keywordSoundEnabled": bool(template.get("keywordSoundEnabled", False)),
                "keywordSoundUrl": str(template.get("keywordSoundUrl") or ""),
                "captionBorderColor": str(template.get("captionBorderColor") or "#000000"),
                "captionAlignment": int(template.get("captionAlignment") if template.get("captionAlignment") is not None else 1),
                "captionAlpha": float(template.get("captionAlpha") if template.get("captionAlpha") is not None else 100),
                "captionLetterSpacing": float(template.get("captionLetterSpacing") if template.get("captionLetterSpacing") is not None else 0),
                "captionLineSpacing": float(template.get("captionLineSpacing") if template.get("captionLineSpacing") is not None else 0),
                "captionScaleX": float(template.get("captionScaleX") if template.get("captionScaleX") is not None else 100),
                "captionScaleY": float(template.get("captionScaleY") if template.get("captionScaleY") is not None else 100),
                "captionBold": bool(template.get("captionBold", True)),
                "captionItalic": bool(template.get("captionItalic", False)),
                "captionUnderline": bool(template.get("captionUnderline", False)),
                "captionShadowEnabled": bool(template.get("captionShadowEnabled", True)),
                "captionTransformX": int(template.get("captionTransformX") or 0),
                "captionTransformY": int(template.get("captionTransformY") or 690),
                "captionTextEffect": "",
                "stickersEnabled": bool(template.get("stickersEnabled", False)),
                "stickerId": str(template.get("stickerId") or ""),
                "stickerKeyword": str(template.get("stickerKeyword") or ""),
                "stickerScale": float(template.get("stickerScale") if template.get("stickerScale") is not None else 0.35),
                "stickerAlpha": float(template.get("stickerAlpha") if template.get("stickerAlpha") is not None else 100),
                "stickerTransformX": float(template.get("stickerTransformX") if template.get("stickerTransformX") is not None else 0.28),
                "stickerTransformY": float(template.get("stickerTransformY") if template.get("stickerTransformY") is not None else -0.3),
                "stickerLayers": template.get("stickerLayers") if isinstance(template.get("stickerLayers"), list) else [],
                "dedupeDisabled": not bool(template.get("dedupeEnabled", False)),
                "dedupeAuxVideoFolderPath": str(template.get("dedupeAuxVideoFolderPath") or ""),
                "dedupeAuxVideoCount": int(template.get("dedupeAuxVideoCount") if template.get("dedupeAuxVideoCount") is not None else 2),
                "dedupeAuxAlpha": float(template.get("dedupeAuxAlpha") if template.get("dedupeAuxAlpha") is not None else 2),
                "clips": clips,
                "audioTracks": audio_tracks,
                "captions": captions if bool(template.get("subtitleEnabled", True)) else [],
            }

            try:
                from integrations.capcut_mate.adapter import CapCutMateAdapter
            except Exception:
                self.write_json(500, {"error": "剪映小助手适配器缺失，请检查 integrations/capcut_mate。"})
                return

            adapter = CapCutMateAdapter()
            with CAPCUT_DRAFT_WRITE_SEMAPHORE:
                result = adapter.generate_draft_from_plan(plan, width=width, height=height)
            draft_url = str(result.get("draft_url") or "").strip()
            if not draft_url:
                self.write_json(500, {"error": "剪映小助手未返回预览草稿地址。"})
                return
            preview_open_result = {"opened": False, "skipped": True, "reason": "true preview exports in background without opening Jianying"}
            import_result = result.get("import_result") if isinstance(result.get("import_result"), dict) else {}
            imported_target_dir = Path(str(import_result.get("target_dir") or "").strip())
            if imported_target_dir.exists():
                preview_open_result = {
                    "opened": False,
                    "skipped": True,
                    "draftPath": str(imported_target_dir),
                    "draftName": read_jianying_draft_name(imported_target_dir),
                    "reason": "true preview exports in background without opening Jianying",
                }
            export_result = adapter.generate_video(draft_url, str(payload.get("apiKey") or "").strip() or None)
            preview_summary: list[str] = []
            if int(result.get("clip_count") or 0) > 0:
                preview_summary.append(f"真实视频 {int(result.get('clip_count') or 0)} 段")
            timing_result = result.get("timing_result") if isinstance(result.get("timing_result"), dict) else {}
            if timing_result.get("normalized"):
                preview_summary.append(
                    f"变速 {timing_result.get('video_speed_min')}x-{timing_result.get('video_speed_max')}x · 配音 {timing_result.get('voice_speed')}x"
                )
            captions_result = result.get("add_captions_result") if isinstance(result.get("add_captions_result"), dict) else {}
            caption_count = len(captions_result.get("segment_ids") or captions_result.get("text_ids") or [])
            if caption_count:
                preview_summary.append(f"字幕 {caption_count} 条")
            filters_result = result.get("add_filters_result") if isinstance(result.get("add_filters_result"), dict) else {}
            filter_count = len(filters_result.get("segment_ids") or filters_result.get("filter_ids") or [])
            if filter_count:
                preview_summary.append(f"滤镜轨道 {filter_count} 条")
            stickers_result = result.get("add_stickers_result") if isinstance(result.get("add_stickers_result"), dict) else {}
            sticker_count = len(stickers_result.get("segment_ids") or stickers_result.get("sticker_ids") or [])
            if sticker_count:
                preview_summary.append(f"贴纸轨道 {sticker_count} 条")
            dedupe_result = result.get("add_dedupe_video_result") if isinstance(result.get("add_dedupe_video_result"), dict) else {}
            dedupe_count = len(dedupe_result.get("items") or dedupe_result.get("track_ids") or [])
            if dedupe_count:
                preview_summary.append(f"辅助视频 {dedupe_count} 条")
            audio_result = result.get("add_audios_result") if isinstance(result.get("add_audios_result"), dict) else {}
            actual_audio_count = len(audio_result.get("audio_ids") or [])
            import_target_dir = ""
            if isinstance(import_result, dict):
                import_target_dir = str(import_result.get("target_dir") or "").strip()
            actual_counts = {
                "clipCount": int(result.get("clip_count") or 0),
                "captionCount": caption_count,
                "filterCount": filter_count,
                "stickerCount": sticker_count,
                "dedupeCount": dedupe_count,
                "audioCount": actual_audio_count,
                "draftReady": bool(import_target_dir and Path(import_target_dir).exists()),
            }
            acceptance_summary = preview_acceptance_summary(actual_counts)
            append_debug_log(
                "api.capcut_mate.template_preview.success",
                {
                    "templateId": template.get("id"),
                    "previewDraftId": preview_draft_id,
                    "draftUrl": draft_url,
                    "sampleVideos": [str(item) for item in clip_paths],
                    "sampleVideoSource": sample_video_source,
                    "audioTrackCount": len(audio_tracks),
                    "previewSummary": preview_summary,
                    "acceptanceSummary": acceptance_summary,
                    "previewOpenResult": preview_open_result,
                    "exportResult": export_result,
                },
            )
            self.write_json(
                200,
                {
                    "previewId": plan["id"],
                    "previewDraftId": preview_draft_id,
                    "draftUrl": draft_url,
                    "exportSubmitted": True,
                    "exportResult": export_result,
                    "previewOpenResult": preview_open_result,
                    "sampleVideos": [str(item) for item in clip_paths],
                    "sampleVideoSource": sample_video_source,
                    "audioTrackCount": len(audio_tracks),
                    "appliedSummary": preview_summary,
                    "acceptanceSummary": acceptance_summary,
                    "writeValidation": {
                        "expected": {
                            "clipCount": len(clip_paths),
                            "captionCount": int(write_plan_summary.get("captionCount") or 0),
                            "filterCount": int(write_plan_summary.get("filterLayerCount") or 0),
                            "stickerCount": int(write_plan_summary.get("stickerLayerCount") or 0),
                            "dedupeCount": int(write_plan_summary.get("dedupeAuxVideoCount") or 0),
                            "audioCount": int(write_plan_summary.get("audioTrackCount") or 0),
                        },
                        "actual": actual_counts,
                    },
                    "addAudiosResult": result.get("add_audios_result"),
                    "addFiltersResult": result.get("add_filters_result"),
                    "addEffectsResult": result.get("add_effects_result"),
                    "addStickersResult": result.get("add_stickers_result"),
                    "addDedupeVideoResult": result.get("add_dedupe_video_result"),
                    "addMasksResult": result.get("add_masks_result"),
                    "addKeyframesResult": result.get("add_keyframes_result"),
                    "addCaptionsResult": result.get("add_captions_result"),
                    "importResult": result.get("import_result"),
                },
            )
        except Exception as exc:
            error_text = str(exc)
            append_debug_log(
                "api.capcut_mate.template_preview.error",
                {"errorType": type(exc).__name__, "error": error_text, "traceback": traceback.format_exc()},
            )
            status = 409 if "capcut-mate service unavailable" in error_text or "Connection refused" in error_text else 500
            hint = "请先启动剪映小助手服务 http://127.0.0.1:30000。" if status == 409 else ""
            self.write_json(status, {"error": f"真实预览生成失败：{error_text}{('。' + hint) if hint else ''}"})

    def handle_select_video_folder(self) -> None:
        try:
            folder = select_folder_with_native_dialog("选择辅助视频文件夹")
            if not folder:
                self.write_json(200, {"selected": False, "path": "", "name": "", "videoCount": 0})
                return
            folder_path = Path(folder)
            if not folder_path.exists() or not folder_path.is_dir():
                self.write_json(400, {"error": "选择的路径不是有效文件夹"})
                return
            video_count = count_video_files_quick(folder_path)
            self.write_json(
                200,
                {
                    "selected": True,
                    "path": str(folder_path),
                    "name": folder_path.name,
                    "videoCount": video_count,
                },
            )
        except Exception as exc:
            append_debug_log("api.system.select_video_folder.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": f"选择文件夹失败：{exc}"})

    def handle_select_export_folder(self) -> None:
        folder = ""
        try:
            folder = select_folder_with_native_dialog("选择导出视频保存文件夹")
            if not folder:
                self.write_json(200, {"selected": False, "path": "", "name": ""})
                return
            folder_path = Path(folder)
            if not folder_path.exists() or not folder_path.is_dir():
                self.write_json(400, {"error": "选择的路径不是有效文件夹"})
                return
            try:
                assert_writable_directory(folder_path, "导出文件夹")
            except Exception as exc:
                self.write_json(400, {"error": describe_file_operation_error("检查导出文件夹", folder_path, exc), "path": str(folder_path)})
                return
            self.write_json(
                200,
                {
                    "selected": True,
                    "path": str(folder_path),
                    "name": folder_path.name,
                    "writable": True,
                    "networkPath": path_is_network_location(folder_path),
                },
            )
        except Exception as exc:
            append_debug_log("api.system.select_export_folder.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": describe_file_operation_error("选择导出文件夹", Path(folder or "."), exc)})

    def handle_check_export_folder(self) -> None:
        folder_path: Path | None = None
        try:
            payload = self.read_json_body()
            raw_path = str(payload.get("path") or "").strip()
            project_id = str(payload.get("projectId") or "").strip()
            if not raw_path:
                self.write_json(400, {"error": "缺少导出文件夹路径。"})
                return

            state = read_client_state()
            export_folders = state.get("meiao-export-folders") if isinstance(state.get("meiao-export-folders"), dict) else {}
            saved_paths = [str(value or "").strip() for value in export_folders.values() if str(value or "").strip()]
            if project_id:
                expected_path = str(export_folders.get(project_id) or "").strip()
                if not expected_path:
                    self.write_json(403, {"error": "当前项目没有已登记的导出文件夹，请重新选择导出目录。"})
                    return
                saved_paths = [expected_path]

            def same_folder(left: str, right: str) -> bool:
                try:
                    return os.path.normcase(os.path.abspath(left)) == os.path.normcase(os.path.abspath(right))
                except Exception:
                    return left.strip().rstrip("\\/") == right.strip().rstrip("\\/")

            if not any(same_folder(raw_path, saved_path) for saved_path in saved_paths):
                self.write_json(403, {"error": "导出文件夹未在当前工作台配置中登记，请重新选择导出目录。"})
                return

            folder_path = Path(raw_path)
            assert_writable_directory(folder_path, "导出文件夹")
            self.write_json(
                200,
                {
                    "ok": True,
                    "path": str(folder_path),
                    "name": folder_path.name,
                    "writable": True,
                    "networkPath": path_is_network_location(folder_path),
                },
            )
        except Exception as exc:
            append_debug_log("api.system.check_export_folder.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(400, {"error": describe_file_operation_error("检查导出文件夹", folder_path or Path("."), exc), "path": str(folder_path or "")})

    def handle_open_local_path(self) -> None:
        target: Path | None = None
        raw_path = ""
        try:
            payload = self.read_json_body()
            raw_path = str(payload.get("path") or "")
            target = normalize_local_open_path(raw_path)
            assert_local_open_allowed(target)
            reveal_local_path(target)
            self.write_json(
                200,
                {
                    "opened": True,
                    "path": str(target),
                    "kind": "file" if target.is_file() else "folder",
                    "networkPath": path_is_network_location(target),
                },
            )
        except Exception as exc:
            append_debug_log("api.system.open_local_path.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            if isinstance(exc, ValueError):
                status = 400
                error = str(exc)
            elif isinstance(exc, PermissionError):
                status = 403
                error = str(exc)
            elif isinstance(exc, FileNotFoundError):
                status = 404
                error = describe_file_operation_error("打开本地产物", target or Path(raw_path or "."), exc)
            else:
                status = 500
                error = describe_file_operation_error("打开本地产物", target or BASE_DIR, exc)
            self.write_json(status, {"error": error, "path": str(target or raw_path or "")})

    def handle_capcut_mate_assets(self) -> None:
        try:
            root = BASE_DIR / "integrations" / "capcut_mate" / "upstream" / "capcut-mate-main"
            if not root.exists():
                self.write_json(404, {"error": "剪映小助手资源目录不存在", "root": str(root)})
                return
            inserted = False
            if str(root) not in sys.path:
                sys.path.insert(0, str(root))
                inserted = True
            try:
                from src.pyJianYingDraft.metadata.audio_scene_effect import AudioSceneEffectType
                from src.pyJianYingDraft.metadata.filter_meta import FilterType
                from src.pyJianYingDraft.metadata.font_meta import FontType
                from src.pyJianYingDraft.metadata.text_intro import TextIntro
                from src.pyJianYingDraft.metadata.text_loop import TextLoopAnim
                from src.pyJianYingDraft.metadata.text_outro import TextOutro
                from src.pyJianYingDraft.metadata.video_group_animation import GroupAnimationType
                from src.pyJianYingDraft.metadata.video_intro import IntroType
                from src.pyJianYingDraft.metadata.video_outro import OutroType
                from src.pyJianYingDraft.metadata.video_scene_effect import VideoSceneEffectType
                from src.pyJianYingDraft.metadata.video_character_effect import VideoCharacterEffectType
                from src.pyJianYingDraft.metadata.tone_effect import ToneEffectType

                def effect_meta_item(item):
                    return {
                        "name": item.value.name,
                        "isVip": bool(item.value.is_vip),
                        "resourceId": item.value.resource_id,
                        "effectId": item.value.effect_id,
                    }

                def media_relative_url(path: Path) -> str:
                    return "/media/" + "/".join(quote(part, safe="") for part in path.relative_to(MEDIA_ROOT).parts)

                font_cache_root = Path.home() / "AppData" / "Local" / "JianyingPro" / "User Data" / "Cache" / "effect"
                font_media_root = MEDIA_ROOT / "capcut-fonts"

                def cached_font_url(item) -> str:
                    effect_id = str(item.value.effect_id or "").strip()
                    if not effect_id:
                        return ""
                    source_root = font_cache_root / effect_id
                    if not source_root.exists():
                        return ""
                    candidates = [path for path in source_root.rglob("*") if path.is_file() and path.suffix.lower() in {".ttf", ".otf", ".woff", ".woff2"}]
                    if not candidates:
                        return ""
                    source = candidates[0]
                    target_dir = font_media_root / effect_id
                    target_dir.mkdir(parents=True, exist_ok=True)
                    target = target_dir / source.name
                    try:
                        if not target.exists() or target.stat().st_size != source.stat().st_size:
                            shutil.copy2(source, target)
                        return media_relative_url(target)
                    except OSError:
                        return ""

                def font_meta_item(item):
                    data = effect_meta_item(item)
                    url = cached_font_url(item)
                    if url:
                        data["fontUrl"] = url
                    return data

                filters = [
                    effect_meta_item(item)
                    for item in FilterType
                ]
                fonts = [
                    font_meta_item(item)
                    for item in FontType
                ]
                effects = [
                    effect_meta_item(item)
                    for item in [*list(VideoSceneEffectType), *list(VideoCharacterEffectType)]
                ]
                audio_scene_effects = [effect_meta_item(item) for item in AudioSceneEffectType]
                tone_effects = [effect_meta_item(item) for item in ToneEffectType]
                huazi_path = root / "config" / "huazi.json"
                raw_text_effects = json.loads(huazi_path.read_text(encoding="utf-8")) if huazi_path.exists() else []
                text_effects = [
                    {
                        "id": str(item.get("id") or ""),
                        "title": str(item.get("title") or ""),
                        "isVip": bool(item.get("is_vip")),
                    }
                    for item in raw_text_effects
                    if isinstance(item, dict)
                ]
                text_animations = {
                    "in": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in TextIntro],
                    "out": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in TextOutro],
                    "loop": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in TextLoopAnim],
                }
                image_animations = {
                    "in": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in IntroType],
                    "out": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in OutroType],
                    "loop": [{"name": item.value.title, "isVip": bool(item.value.is_vip), "resourceId": item.value.resource_id, "effectId": item.value.effect_id} for item in GroupAnimationType],
                }
            finally:
                if inserted:
                    try:
                        sys.path.remove(str(root))
                    except ValueError:
                        pass

            sticker_path = root / "config" / "sticker.json"
            stickers: list[dict] = []
            sticker_title_status = "missing"
            raw_stickers: list[dict] = []
            free_sticker_title_blocklist = re.compile("(vip|svip|\u4f1a\u5458|\u4ed8\u8d39|\u4e13\u4eab|\u5145\u503c|\u8d35\u5bbe|\u4f1a\u5458\u5361|premium|paid|pay)", re.IGNORECASE)
            if sticker_path.exists():
                raw_stickers = json.loads(sticker_path.read_text(encoding="utf-8"))
                if isinstance(raw_stickers, list):
                    for item in raw_stickers:
                        if not isinstance(item, dict):
                            continue
                        sticker = item.get("sticker") if isinstance(item.get("sticker"), dict) else {}
                        image = sticker.get("large_image") if isinstance(sticker.get("large_image"), dict) else {}
                        sticker_id = str(item.get("sticker_id") or "").strip()
                        title = str(item.get("title") or "").strip()
                        sticker_type = int(sticker.get("sticker_type") or 0)
                        stickers.append(
                            {
                                "id": sticker_id,
                                "title": title,
                                "imageUrl": str(image.get("image_url") or ""),
                                "stickerType": sticker_type,
                                "isCommercialCandidate": bool(sticker_id and sticker_type == 1 and not free_sticker_title_blocklist.search(title)),
                            }
                        )
                    titles = [item.get("title", "") for item in stickers[:20]]
                    sticker_title_status = "ok" if any(title and "�" not in title for title in titles) else "garbled"
                else:
                    raw_stickers = []
            free_sticker_candidate_count = 0
            for item in raw_stickers:
                if not isinstance(item, dict):
                    continue
                sticker = item.get("sticker") if isinstance(item.get("sticker"), dict) else {}
                sticker_id = str(item.get("sticker_id") or "").strip()
                title = str(item.get("title") or "").strip()
                sticker_type = int(sticker.get("sticker_type") or 0)
                if sticker_id and sticker_type == 1 and not free_sticker_title_blocklist.search(title):
                    free_sticker_candidate_count += 1

            def collect_music_tracks() -> list[dict]:
                candidates: list[Path] = []
                roots = [
                    Path.home() / "AppData" / "Local" / "JianyingPro" / "User Data" / "Cache" / "music",
                    Path.home() / "AppData" / "Local" / "JianyingPro" / "User Data" / "EMaterial",
                    Path.home() / "AppData" / "Local" / "JianyingPro" / "User Data" / "Resources",
                    Path.home() / "AppData" / "Local" / "CapCut" / "User Data" / "Cache" / "music",
                    Path.home() / "AppData" / "Local" / "CapCut" / "User Data" / "EMaterial",
                    Path.home() / "AppData" / "Local" / "CapCut" / "User Data" / "Resources",
                ]
                skip_pattern = re.compile(r"(voice|tts|eleven|dub|配音|口播|旁白|draft|com\.lveditor|storage[\\/]+media|output[\\/]+draft)", re.IGNORECASE)
                for scan_root in roots:
                    if not scan_root.exists():
                        continue
                    try:
                        for item in scan_root.rglob("*"):
                            item_path = str(item)
                            if item.is_file() and item.suffix.lower() in AUDIO_FILE_SUFFIXES and not skip_pattern.search(item_path):
                                candidates.append(item)
                                if len(candidates) >= 300:
                                    break
                    except Exception:
                        continue
                    if len(candidates) >= 300:
                        break
                tracks: list[dict] = []
                seen: set[str] = set()
                category_counts: dict[str, int] = {}
                file_metadata_index = build_jianying_audio_file_metadata_index()
                for item in candidates:
                    key = str(item.resolve()).lower()
                    if key in seen:
                        continue
                    seen.add(key)
                    try:
                        stat = item.stat()
                    except OSError:
                        continue
                    source = "jianying_music_cache" if "jianyingpro" in str(item).lower() else "capcut_music_cache"
                    index_item = read_audio_cache_index_item(item)
                    cfg_item = file_metadata_index.get(item.name.lower(), {})
                    indexed_category = str(index_item.get("category") or "").strip()
                    cfg_category = str(cfg_item.get("category") or "").strip()
                    category = indexed_category if indexed_category and indexed_category != "未归类缓存" else cfg_category
                    category = category or ("节拍缓存" if item.suffix.lower() == ".beat" else "其他")
                    indexed_title = str(index_item.get("title") or cfg_item.get("title") or "").strip()
                    indexed_author = str(index_item.get("author") or cfg_item.get("author") or "").strip()
                    music_id = str(index_item.get("musicId") or cfg_item.get("musicId") or cfg_item.get("id") or cfg_item.get("web_id") or "").strip()
                    category_counts[category] = category_counts.get(category, 0) + 1
                    title = indexed_title or (item.stem if not re.fullmatch(r"[0-9a-f]{16,64}", item.stem, re.IGNORECASE) else f"剪映音乐 {len(tracks) + 1}")
                    tracks.append({
                        "id": f"capcut-audio-{len(tracks) + 1}",
                        "name": title,
                        "title": title,
                        "author": indexed_author,
                        "musicId": music_id,
                        "fileName": item.name,
                        "source": source,
                        "category": category,
                        "mediaKind": "beat" if item.suffix.lower() == ".beat" else "music",
                        "size": stat.st_size,
                        "url": f"/api/capcut-mate/audio-file?path={quote(str(item), safe='')}",
                        "isCommercialCandidate": bool(index_item.get("isCommercialCandidate", cfg_item.get("isCommercialCandidate", True))),
                    })
                return tracks

            missing_music_index_entries = prune_missing_audio_cache_index()
            music_tracks = collect_music_tracks()
            music_cache_status = inspect_jianying_music_cache_state()
            cached_music_categories = load_jianying_music_collections()
            music_categories = cached_music_categories or [
                {"id": "recommended", "name": "推荐音乐", "cacheable": True},
                {"id": "latest", "name": "最新", "cacheable": True},
                {"id": "pure", "name": "纯音乐", "cacheable": True},
                {"id": "light", "name": "轻快", "cacheable": True},
                {"id": "vlog", "name": "Vlog", "cacheable": True},
                {"id": "travel", "name": "旅行", "cacheable": True},
                {"id": "birthday", "name": "生日", "cacheable": True},
                {"id": "marketing", "name": "营销", "cacheable": True},
                {"id": "beat", "name": "卡点", "cacheable": True},
                {"id": "warm", "name": "温暖", "cacheable": True},
                {"id": "food", "name": "美食", "cacheable": True},
                {"id": "fashion", "name": "时尚", "cacheable": True},
                {"id": "unbox", "name": "开箱", "cacheable": True},
            ]
            sound_effect_categories = [
                {"id": "scene", "name": "场景音效", "cacheable": False},
                {"id": "tone", "name": "变声音色", "cacheable": False},
                {"id": "hot", "name": "热门音效", "cacheable": True},
                {"id": "life", "name": "生活", "cacheable": True},
                {"id": "transition", "name": "转场", "cacheable": True},
                {"id": "nature", "name": "自然", "cacheable": True},
                {"id": "ui", "name": "提示音", "cacheable": True},
            ]

            self.write_json(
                200,
                {
                    "root": str(root),
                    "filters": {"readable": True, "count": len(filters), "items": filters, "samples": filters[:20]},
                    "effects": {"readable": True, "count": len(effects), "items": effects, "samples": effects[:20]},
                    "audioSceneEffects": {"readable": True, "count": len(audio_scene_effects), "items": [{**item, "category": "场景音效", "mediaKind": "sound_effect", "isCommercialCandidate": True} for item in audio_scene_effects], "samples": audio_scene_effects[:20]},
                    "toneEffects": {"readable": True, "count": len(tone_effects), "items": tone_effects, "samples": tone_effects[:20]},
                    "musicTracks": {"readable": True, "count": len(music_tracks), "items": music_tracks, "samples": music_tracks[:20], "categories": music_categories, "cacheFolder": str(Path.home() / "AppData" / "Local" / "JianyingPro" / "User Data" / "Cache" / "music"), "missingIndexEntries": missing_music_index_entries, "cacheStatus": music_cache_status},
                    "audioCategories": {"music": music_categories, "soundEffects": sound_effect_categories},
                    "fonts": {"readable": True, "count": len(fonts), "items": fonts, "samples": fonts[:20]},
                    "textEffects": {"readable": True, "count": len(text_effects), "items": text_effects, "samples": text_effects[:20]},
                    "textAnimations": {
                        "readable": True,
                        "in": {"count": len(text_animations["in"]), "items": text_animations["in"]},
                        "out": {"count": len(text_animations["out"]), "items": text_animations["out"]},
                        "loop": {"count": len(text_animations["loop"]), "items": text_animations["loop"]},
                    },
                    "imageAnimations": {
                        "readable": True,
                        "in": {"count": len(image_animations["in"]), "items": image_animations["in"]},
                        "out": {"count": len(image_animations["out"]), "items": image_animations["out"]},
                        "loop": {"count": len(image_animations["loop"]), "items": image_animations["loop"]},
                    },
                    "stickers": {
                        "readable": bool(stickers),
                        "count": len(raw_stickers),
                        "freeCandidateCount": free_sticker_candidate_count,
                        "items": stickers,
                        "samples": stickers[:20],
                        "titleStatus": sticker_title_status,
                        "source": str(sticker_path),
                    },
                },
            )
        except Exception as exc:
            append_debug_log("api.capcut_mate.assets.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": f"读取剪映资源失败：{exc}"})

