    def handle_capcut_mate_archive_exported_video(self) -> None:
        try:
            content_length = int(self.headers.get("Content-Length", "0"))
            payload = json.loads(self.rfile.read(content_length).decode("utf-8")) if content_length else {}
            video_url = str(payload.get("videoUrl") or "").strip()
            output_dir_text = str(payload.get("outputDir") or "").strip()
            project_name = str(payload.get("projectName") or "").strip()
            if not output_dir_text:
                self.write_json(400, {"error": "缺少导出文件夹"})
                return
            output_dir = Path(output_dir_text).expanduser().resolve()
            try:
                assert_writable_directory(output_dir, "导出文件夹")
            except Exception as exc:
                self.write_json(400, {"error": describe_file_operation_error("检查导出文件夹", output_dir, exc), "path": str(output_dir)})
                return
            try:
                source = resolve_capcut_export_source(video_url)
            except Exception as exc:
                self.write_json(400, {"error": describe_file_operation_error("检查导出视频", Path(video_url or "."), exc), "videoUrl": video_url})
                return
            target, index = next_export_target_path(output_dir, project_name)
            try:
                shutil.move(str(source), str(target))
            except Exception as exc:
                self.write_json(
                    500,
                    {
                        "error": describe_file_operation_error("移动导出视频", target, exc),
                        "sourcePath": str(source),
                        "targetPath": str(target),
                    },
                )
                return
            append_debug_log(
                "api.capcut_mate.archive_exported_video",
                {"source": str(source), "target": str(target), "index": index, "projectName": project_name},
            )
            self.write_json(
                200,
                {
                    "moved": True,
                    "sourcePath": str(source),
                    "localPath": str(target),
                    "fileName": target.name,
                    "index": index,
                },
            )
        except Exception as exc:
            append_debug_log("api.capcut_mate.archive_exported_video.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": f"移动导出视频失败：{exc}"})

