    def handle_analysis_chat(self) -> None:
        try:
            content_length = int(self.headers.get("Content-Length", "0"))
            payload = json.loads(self.rfile.read(content_length).decode("utf-8")) if content_length else {}
            if not isinstance(payload, dict):
                self.write_json(400, {"error": "请求体格式错误"})
                return
            messages = normalize_chat_messages(payload.get("messages"))
            if not messages:
                self.write_json(400, {"error": "缺少 messages 或消息内容为空"})
                return

            config = get_analysis_model_config()
            raw_timeout = payload.get("timeoutSeconds") or payload.get("timeout_seconds")
            try:
                timeout_seconds = float(raw_timeout)
            except Exception:
                timeout_seconds = 120.0
            timeout_seconds = max(15.0, min(240.0, timeout_seconds))
            requested_model_id = str(payload.get("modelId") or payload.get("model_id") or "").strip()
            profiles = select_analysis_profiles_for_request(config, requested_model_id, messages)
            if not profiles:
                self.write_json(409, {"error": "未配置可用分析模型。请在设置里补充。", "code": "ANALYSIS_CONFIG_MISSING", "action": "CONFIGURE_ANALYSIS_MODEL"})
                return
            response_data = None
            profile = profiles[0]
            last_error: IngestError | None = None
            for index, candidate in enumerate(profiles):
                profile = candidate
                try:
                    response_data = openai_compatible_chat_completion(
                        profile,
                        messages,
                        stream=bool(payload.get("stream")) if isinstance(payload.get("stream"), bool) else False,
                        tools=payload.get("tools"),
                        include_thoughts=payload.get("include_thoughts"),
                        reasoning_effort=str(payload.get("reasoning_effort") or "").strip() or None,
                        response_format=payload.get("response_format"),
                        timeout_seconds=timeout_seconds,
                    )
                    break
                except IngestError as exc:
                    last_error = exc
                    if index + 1 >= len(profiles):
                        raise
                    append_debug_log(
                        "api.analysis.chat.retry",
                        {
                            "failedModelId": profile.get("id"),
                            "nextModelId": profiles[index + 1].get("id"),
                            "error": str(exc),
                            "code": exc.code,
                        },
                    )
            if response_data is None:
                if last_error:
                    raise last_error
                raise IngestError("分析模型调用失败。", "ANALYSIS_REQUEST_FAILED", "RETRY")
            assistant_content = extract_chat_message_content(response_data)
            append_debug_log(
                "api.analysis.chat.success",
                {
                    "modelId": profile["id"],
                    "model": profile.get("model"),
                    "messageCount": len(messages),
                    "contentLength": len(assistant_content),
                },
            )
            self.write_json(
                200,
                {
                    "model": profile.get("model"),
                    "modelId": profile["id"],
                    "provider": profile.get("provider"),
                    "content": assistant_content,
                    "response": response_data,
                },
            )
        except IngestError as exc:
            append_debug_log("api.analysis.chat.error", {"error": str(exc), "code": exc.code, "action": exc.action})
            self.write_json(409, {"error": str(exc), "code": exc.code, "action": exc.action})
        except Exception as exc:
            traceback.print_exc()
            append_debug_log("api.analysis.chat.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": str(exc)})

    def handle_elevenlabs_voice_create(self) -> None:
        try:
            content_length = int(self.headers.get("Content-Length", "0"))
            payload = json.loads(self.rfile.read(content_length).decode("utf-8")) if content_length else {}
            if not isinstance(payload, dict):
                self.write_json(400, {"error": "请求体格式错误"})
                return
            text = str(payload.get("text") or "").strip()
            voice = str(payload.get("voice") or "EkK5I93UQWFDigLMpZcX").strip()
            language_code = str(payload.get("language_code") or "zh").strip()
            stability_raw = payload.get("stability", 0.5)
            try:
                stability = float(stability_raw)
            except Exception:
                stability = 0.5
            if stability not in {0.0, 0.5, 1.0}:
                stability = 0.5
            if not text:
                self.write_json(400, {"error": "缺少口播文案"})
                return
            if len(text) > 5000:
                self.write_json(400, {"error": "口播文案超过 5000 字符，请拆分后生成"})
                return

            config = get_audio_model_config()
            profile = config.get("active_model") or {}
            model_name = str(profile.get("model") or DEFAULT_AUDIO_MODEL).strip() or DEFAULT_AUDIO_MODEL
            request_body = {
                "model": model_name,
                "input": {
                    "dialogue": [{"text": text, "voice": voice}],
                    "stability": stability,
                    "language_code": language_code,
                },
            }
            callback_url = str(payload.get("callBackUrl") or "").strip()
            if callback_url:
                request_body["callBackUrl"] = callback_url
            api_result = call_kie_market_create_task(request_body, profile)
            data = api_result.get("data") if isinstance(api_result.get("data"), dict) else {}
            task_id = str(data.get("taskId") or "").strip()
            record_id = str(data.get("recordId") or "").strip()
            if not task_id:
                raise IngestError("Kie 配音接口未返回 taskId")
            append_debug_log(
                "api.voice.elevenlabs.create",
                {"taskId": task_id, "recordId": record_id, "model": model_name, "textLength": len(text), "voice": voice},
            )
            self.write_json(
                200,
                {
                    "taskId": task_id,
                    "recordId": record_id,
                    "status": "submitted",
                    "model": model_name,
                    "voice": voice,
                    "stability": stability,
                    "language_code": language_code,
                    "raw": api_result,
                },
            )
        except IngestError as exc:
            append_debug_log("api.voice.elevenlabs.create.error", {"error": str(exc), "code": exc.code, "action": exc.action})
            self.write_json(409, {"error": str(exc), "code": exc.code, "action": exc.action})
        except Exception as exc:
            traceback.print_exc()
            append_debug_log("api.voice.elevenlabs.create.error", {"errorType": type(exc).__name__, "error": str(exc), "traceback": traceback.format_exc()})
            self.write_json(500, {"error": str(exc)})

