        """音色试听：本地缓存命中即发送，未命中则从官方 CDN 下载后再发送（支持 Range/206）。"""
        params = parse_qs(parsed.query)
        voice_id = str((params.get("voiceId") or params.get("voice") or [""])[0] or "").strip()
        target = ensure_voice_preview_cached(voice_id)
